insert into _recap_sessions (session_number, patch) values
  (1, '{"session_number": 1, "loop_number": 1, "played_at": "2025-07-18", "time_range": "20:00 — 00:00", "game_date": "0 петля, 31 странствий\n- 1 петля, 1 странствий", "recap": "Летний фестиваль в Сиории на территории королевской академии во время полного парада планет. В главном зале собираются представители правительства, важные персоны и высокопоставленные лица, преподаватели и ученики разных курсов, среди которых наши герои. Каждый приходит со своей парой, Британия в компании Зака. Маркус начинает ревновать и посреди танца нападает на Зака, вырубает его. \n\nНа фоне раздаются залпы салюта, плавно переходящие в громкие взрывы. Каэл замечает, что на город с его окраин в сторону центра летят артиллерийские заклинания, уничтожая часть города. Начинается паника, важных гостей ведут на высокий этаж к телепортационным комнатам, преподаватели бегут на помощь в город, а учеников сопровождают в убежища старосты потока. Роза пропадает в толпе (невидимость), Альд защищает сестру (невидимость), Британия пытается руководить потоком студентов, чтобы успокоить их. Организовывается группа из 5 наших героев, когда они выбегают из подземного перехода на пути к убежищу, до которого 500 футов на открытом пространстве. \n\nУченики сталкиваются с группой Снежных Волков, нападающих на всех студентов. Кто-то даёт отпор, группа героев пытается бежать напрямик без прямых столкновений (Рывок, Отход, Невидимость, Туманный шаг). Выбегают тролли, с неба нападают Железнокрылы, трясёт землю, начинается кратковременная метель. В этом хаосе наши герои трагически погибают, Маркус жертвует собой и Британии удаётся добежать до убежища. Там она замечает молодого чецловека, не студента, который выпускает ядовитый дым из колбы, и все окончательно умирают. \n\nНаши герои просыпаются 1 августа, как было ровно месяц назад. Британия и Маркус после ночи секса (их первый раз), отрицание, гнев, депрессия... Альд и Каэл всё как обычно. Роза просыпается дома в своём родном городе, бежит рассказать своей няне страшный сон, и обнаруживает её мёртвой (не как в прошлой раз). Остальные так или иначе встречаются в таверне Золотой Петух, случайно делятся своим странным сном, или нет, и понимают, что они вместе пережили странный опыт. Альд и Каэл уходят из таверны спать, Британия и Маркус остаются и делают ставки на победу Железнодорожников в магболле, помня исход в прошлый раз. К ним подходят новые ребята - Дрипли, Янка, Фрэд и Рион  (смотри 3 игру)", "new_npcs_raw": "Зак Новеда, одноклассник Зак Новеда\n\nИльза Зилети, преподаватель Ильза Зилети\n\nКайрон, преподаватель Кайрон", "materials": "- Портрет *предателя*, который убил всех в убежище. Портрет *предателя* Саймона\n\n♣️ Колода карт\nВопрос *Что произойдёт на балу*\nОтвет *Увядающая Старейшина Тверди, Чёрный Бродяга Тверди, Синий Скиталец Глубин, Красный Путник Крови* \nИнтерпретация *Пиздец всё плохо и непронятно*\nГадание 31 Странствий", "materials_url": "https://drive.google.com/file/d/1F0tMgB2vke0WhFUtaHyjzjM0fH1c0Msb/view?usp=drive_link", "achievements": "🎲Первый бросок кубика в компании - Британия\n\n👊Первый бой - Маркус\n\n🔞Первая постельная сцена - Британия и Маркус \n\n🤬Счётчик *Да пошёл ты* от Британии - 8"}'::jsonb),
  (2, '{"session_number": 2, "loop_number": 1, "played_at": "2025-07-20", "time_range": "19:00 — 23:00", "game_date": "0 петля, 31 странствий\n- 1 петля, 1 странствий", "recap": "Летний фестиваль в Сиории на территории королевской академии во время полного парада планет. В главном зале собираются представители правительства, важные персоны и высокопоставленные лица, преподаватели и ученики разных курсов, среди которых наши герои. Каждый приходит со своей парой: Дрюс с Еленой, Энтони со своим доспехом, Дрипли с Янкой (при этом Дрипли загримирован под человека). Ребята наблюдают драку Зака и Маркуса в центре зала, на фоне раздаются всполохи салюта, плавно переходящие в громкие взрывы. Они замечают, что на город с его окраин в сторону центра летят артиллерийские заклинания, уничтожая часть города. \n\nНачинается паника, важных гостей ведут на высокий этаж к телепортационным комнатам, преподаватели бегут на помощь в город, а учеников сопровождают в убежища старосты потока. Организовывается группа из наших героев, когда они выбегают из подземного перехода на пути к убежищу, до которого 500 футов на открытом пространстве.\n\nУченики сталкиваются с группой Снежных Волков, которые нападают на всех. Янка пытается уговорить Дрипли сбежать с ней в сторону ее дома, чтобы постараться спасти близких, но Дрипли отказывает (герои не сбегают перед опасностью). Часть его тела формируется в маленький парящий сгусток и идет вместе с Янкой в качестве фамильяра, Капли. Остальные дерутся: Дрюс защищает свою девушку, Энтони и Дрипли идут на рожон и даже убивают одного волка. Тем временем Янка пытается сбежать, один волк отделяется от стаи и перекрывает ей путь, но она бьет его током и телепортируется. Дрипли, замечая опасность для Янки, через фамильра кастует защитный купол. За счет дополнительной защиты Янке удается избежать удара железных птиц, она сначала ползет по крыше, потом протискивается в дымоход пустого дома, чтобы не упереться в троллей. Когда прерывается метель и тролли вместе с железнокрылами нападают, все, кроме Янки, трагически погибают на поле боя. Янке удается успешно избегать монстров какое-то время, но когда она выбегает на открытую площадь, ее горячо встречают неизвестные военные (убивают на месте).\n\nГерои просыпаются 1 августа в своих домах как ни в чем не бывало. Дрипли рассказывает профессору про свой сон, который был похож на реальность, но профессор только предполагает, что это могут быть воспоминания из прошлой жизни. После этого Дрипли как и в прошлый раз делает листовки, но теперь он изображает на них события прошедшего нападения. Энтони после пробуждения сразу же делает записи в двух своих дневниках для конспирации, в одном из них как можно подробнее описывает все события, которые запомнил, и нелестно отзывается о разных одноклассниках. Дрюс и Энтони независимо друг от друга решают промочить горло в Золотом петухе и замечают там подозрительную группу одноклассников, которая перешептывается за столиком. Энтони делает вид, что не узнает друида, и просто заказывает выпивку на весь зал с многозначительной фразой о времени (наблюдает за реакцией); после этого он так же делает ставку за столиком с Маркусом и Британией. Янка после пробуждения решает проветрить голову и позже в парке сталкивается с Дрипли и Фредом (смотри 3 игру)", "achievements": "🐾Первый призыв фамильяра - Дрипли"}'::jsonb),
  (3, '{"session_number": 3, "loop_number": 1, "played_at": "2025-07-27", "time_range": "20:00 — 23:30", "game_date": "1 петля, 1 странствий", "recap": "Фред не пошел на бал и погиб в комнате общежития от первого артиллерийского залпа, Рион погиб от лап снежного волка, пока пытался его лучше изучить. Фред просыпается в своей комнате в Академии и спустя время встречает там Дрипли, раздающего листовки. Они собираются развесить приглашения в таверне \"Золотой петух\", по пути встречают Янку в парке, а уже в таверне замечают Риона. Клуб начинающих приключенцев оказывается в сборе.\n\nВ кабаке уже сидят Британия, Маркус и Энтони и делают ставки на спорт. Дрипли приглашает ребят в клуб, но Энтони отмахивается (?), а Маркус ставит условие, что вступит в клуб, если Дрипли его перепьет. Пара неудачных бросков и слизь перепивает пьяного мастера, тот оказывается в отключке. Британия неохотно вступает в клуб, ребята решают покинуть таверну и обсудить происходящее в менее людном месте. Рион предлагает свое поместье. \n\nПо пути в дом Риона герои встречают стаю мозговых крыс, которых успешно распугивают атаками (ногами, огнем, психикой и некротикой), пока Дрипли растекается от оглушения. Они продолжают обсуждение у Риона дома, Британия посвящает 10 минут вдохновляющей объединяющей речи. Когда уже ребята думали разойтись, на пороге дома они обнаружили овцу со свитком в зубах. Британия зачитывает свиток массового разговора с животными, и в следующие несколько минут ребята понимают, что к ним пришла не просто овца, а заколдованный маг Фенитир Шайнбрайт, который пропал несколько лет назад.  Волшебник просит о помощи, чтобы наши герои нашли палочку в его поместье и расколдовали его. Он не обратился к опытным магам, так как боится выставить себя дураком, ведь его обхитрил какой-то ученик. Шайнбрайт сообщает дорогу до своего поместья, Фред ее тщательно запоминает. \n\nЧерез некоторое время на порог так же заявляется молодая неприметно одетая женщина Аериси Калинос (с собой 36 зм, Жезл обжигающих лучей, Жезл с маг. стрелой) в компании двух гигантских человекоподобных обезьян. Это телохранительница того самого ученика, которая занимается поиском овцы с помощью специального заклинания. Герои прячут овцу в погреб, Рион пытается добазариться с магичкой, но она быстро находит обращенного мага под полом. Аериси чувствует, что владеет ситуацией, ровно до момента, пока Маркус не запуливает ее вниз к овце одним точным ударом ногой. На нее нападают толпой, магичка пытается защищаться звуковыми заклинаниями, создавая грохот в доме. Тем временем из-за угла кухни выходит Янка, которая выглядит и разговаривает точь в точь как Аериси. Пока компания разбирается с настоящей магичкой, Янка успешно уводит обезьян от поместья и некоторое время ходит с ними по городу, а потом растворяется (телепортируется туманным шагом). \n\nВ погребе Аериси пытается скинуть с себя агрессивных подростков, но оседлавший её Маркус ещё раз хорошенько прикладывает ее после того, как оказывается подкинутым в воздух. Добивают магичку несколько точных магических стрел Риона, она оказывается без сознания.  Овца (Фенитир) на самом деле весьма кровожадна и хочет добить оглушённую женщину, но Маркус решает вопрос кардинально и лишает сознания обоих. Герои решают, что так дело оставлять нельзя. Они прячут тело волшебницы в бочку, а овцу в мешок, чтобы пронести через город к доверенному магу - Лайонелу Вириону, профессору алхимии и создателю Дрипли. До дома Дрипли малолетние преступники добираются без проишествий. Профессор совсем не ожидал, что его творение вляпается в приключения еще до начала занятий в академии. Лайонел вызывает Ильзу Зилети, та забирает оба оглушенных тела с собой и распускает студентов по домам, ожидая завтра на выборе факультативов. На этом проблемы для путешественников во времени, казалось бы, заканчиваются.", "new_npcs_raw": "Джалин - барменша в Золотом Петухе Джалин 2\n\nФенитир Шайнбрайт - волшебник, овца, трансмутатор\n\nНеназванный ученик Шайнбрайта, укравший палочку с истинным полиморфом (упоминается)\n\nАериси Калинос - волшебница, телохранительница ученика Шайнбрайта \n\nЛайонел Вирион - профессор алхимии, \"отец\" Дрипли Лайонел Вирион", "perks": "🔮Волшебная палочка снарядов - Британия (минус) \n\n🔮Волшебная палочка секретов - Дрипли (минус)"}'::jsonb),
  (4, '{"session_number": 4, "loop_number": 1, "played_at": "2025-08-09", "time_range": "15:00 — 18:30", "game_date": "1 петля, 2 странствий", "recap": "Студенты встречаются в коридоре академии перед выбором факультативов возле кабинета Ильзы, ученики по очереди выбирают занятия, назначаются кураторы для каждого. Британия пробует узнать у Ильзы про *сон*, та намекает что другие ученики видимо сговорились и тоже спрашивали про события фестиваля, какие именно, она не стала говорить. Дрипли всех активно агитирует вступить в свой Клуб Начинающих Приключенцев, в котором уже состоит несколько членов. Ребята по разным мотивам хотят отправиться в подземелье, для этого требуется подтверждение и аккредитация у преподавателя (на выходном), и чтобы не ждать идут к подруге Дрипли - Тайвен, которая знает нелегальные входы в подземелье(на самом деле нет, у её боевой группы есть допуск). \n\nТайвен предлаегает смотаться на одно простое задание из доски объявлений, группа доходит до мрачного особняка, знакомится с дворецкий Адамом с просьбой *зачистить дом от вредителей*. Дом оказывается заполнен призраками, которые не нападают, обыскав весь дом, группа находит в подвале огромную груду трупных личинок, которые перекрыли путь дальше в подвал. Ребята начинают активно их давить, Дрюс жарить, Дрипли заливать кислотой, Британия ментально разбрасывать. Несколько минут очищения помещения от ядовитого дыма, и они пробираются дальше. Дрипли показал массу особенностей - лелал, надувался, плавал по трубам, прекращал дыхание (все приколы плазмоида).\n\nОказалось,что подвал - крипта, полная саркофагов со скелетами хозяев особняка, и их духами. Альд начинает складывать кости и приводить саркофаги в порядок с помощью ребят., духи остаются благодарны. Дворецкий Адам помогает студентам убираться в подвале, Британия подозревает что дворецкий нежить, его нужно сдать властям. Начинается какое-то неловкое выяснение обстоятельств, и всё, что удаётся узнать - хозяева умерли от Плача. Группа получает плату и покидает особняк, отправляются заниматься своими делами.", "new_npcs_raw": "Адам - дворецкий странного дома  Адам Lurch поместье Аддамс смотритель Холмовой великан.webp\n\nТайвен - подруга Дрипли, выпускница Тайвен\n\n🥊 Трупные личинки https://dnd.su/bestiary/625-swarm-of-rot-grubs/", "materials": "- Рисунок на приглашении в клуб приключенццев Дрипли *Маг стреляет струи кислоты в сторону снежного волка* \nСписок Дрипли", "materials_url": "https://drive.google.com/file/d/1cX6UP7gT-n10NgdclzmHFYoNkfw2foKB/view?usp=drive_link", "perks": "💲Выполнение задания - 60 золотых", "achievements": "⚗️Первое выпитое зелье - Дрипли"}'::jsonb),
  (5, '{"session_number": 5, "loop_number": 1, "played_at": "2025-08-15", "time_range": "20:00 — 00:00", "game_date": "1 петля, 11 странствий", "recap": "*до начала игры*: Альд отправляется в особняк Адама 3 августа, чтобы проверить состояние склепа на наличие призраков и провести полноценный обряд упокоения. Оказалось, что дом пуст и следы духов отсутствуют. Альд пытается сподвигнуть Адама к защите дома с помощью призраков, рассказывая ему о вторжении в Сиории в конце месяца. Адам не очень сговорчив (после доноса Британии), и Альд с подозрением покидает это место. Утром 11 августа Альд посещает место работы в морге, чтобы подготовиться к пропаже трупа девушки и спасти своего сменщика Петра, который будет работать 13 августа. \n\nРоза заканчивает домашние хлопоты, связанные с похоронами её няни, и возвращается в Сиорию, а прошлые события расценивает как дурной сон, уходя в полное отрицание и депрессию. Локи потихоньку к 11 дню знакомится с ребятами, где бы он ни был, происходят какие-то странные еле заметные вещи (шалит барабашка). \nВсе собираются на новую неделю обучения, делая вид, что всё идёт своим чередом (заодно пробуем понять, как проходят занятия). Основы Инвокаций (скипнуто). Основы Алхимии, варили зелье понимания, Каэл испортил расходники для трёх зелий, Локи тоже облажался, но скрыл свою неудачу какими-то махинациями (у обоих единицы на кубах). Обращение с магическими предметами, проверка концентрации с помощью браслета, соревнование на скорость лазания по башне (заклинания Прыжок и Левитация). Каэл победил, Локи сначала помог Альду, потом помешал (Альд не понял). Роза и Янка без энтузиазма наблюдали за этим (все вспомнили какие-то основные механики). История и Магическое право скип.\n\nПосле занятий ребята захотели развеяться и собрать информацию, но на выходе в город их встретила группа из 5-6 парней из политехнического, разводя на деньги, помятую победу *друзей* на ставках. Пока Локи заговаривает им зубы, Альд в крысу убегает, за ним ретируется Роза (оба уходят в Невидимость, мастер даёт инфу про нелегальность этого заклинания, для него нужна лицензия). Янка превращается в Локи, Локи создаёт копию, и три иллюзии издеваются над братками. Каэл бежит на помощь в поисках стражи, привлекая внимание, и с помощью иллюзии стражи студентам удаётся обмануть хулиганов, которые отступили (бой без боя). Альд возвращается и врезается (криты на кубе) в Розу в невидимости, у той истерика, Янка её успокаивают и все решают пойти в таверну Золотой Петух выпить и поговорить. \n\nРоза быстро пьянеет (отыгрыш пьяной 16-ти летки, браво), Локи ловит флешбеки и все готовы поговорить о *сне*. Ребята обсуждают несколько противоричивых теорий, от второго шанса богом, до попадания в *ад*. Главные акценты - повторяющиеся события, необъяснимый рост магических сил, и самое интересное - смерть няни Розы (ведьма), которая отличается, в прошлый раз не умирала (возможно). Каэл начинает фиксировать события в хронологическом порядке, кто где был на фестивале, карта событий, каждый делится подробностями побега: Локи запрыгнул в телепортационный круг для знати и там тоже было всё плохо, а Янка с Альдом приходят к тому, что её убили Изгнанники (некроманты). Локи зовёт всех в библиотеку, каждый берёт свою область интересов: Локи - мифические артефакты, легенды и сказки, Альд - магические твари (тролли, волки, железнокрылы), Янка (без энтузиазма) - войны некромантов, Каэл - внешняя и внутренняя политика, история, Роза попыталась узнать у библиотекарши об учебнике, найденном у няни\n\nМастер выдаёт большое количество ЛОРа, механики мира, другие планы, войны раскола, войны некромантов, плач, географические ориентиры.", "new_npcs_raw": "Пётр - жрец, сменщик в морге \n\nОльга - санитар в морге\n\nДжалин - барменша в Золотом Петухе Джалин 2\n\nКиритишли Корисова - библиотекарь Киритишли Корисова", "materials": "- Начать бы собирать условную карту академии с прилегающими территориями (не начата)\n\n- Альд начал схематичный рисунок в виде человеческого тела, с *врагами* Сиории, как анамнез болезни - симптомы, больные места, возможное лечение.  \n\n♣️ Колода карт\nВопрос *Кто напал и убил Янку* \nОтвет *Три тёмные карты*\nИнтерпретация *Маги изгнанники некроманты*", "achievements": "‼️Первые две единицы на столе - Каэл и Локи\n\n✅Первая критическая 20 по запросу мастера - Альд"}'::jsonb),
  (6, '{"session_number": 6, "loop_number": 1, "played_at": "2025-08-21", "time_range": "20:00 — 00:00", "game_date": "1 петля, 13-14 странствий", "recap": "Занятия немагического боя, Маркус против Альда и Янки, размотал всухую, даже с помощью магии поддержки и Британии, пока Локки скучает. Янка для добивающего удара превращается в Маркуса, чтобы тот сам себе зарядил по роже (через 6 сек она уже в накауте). В этой петле класс узнает, что Янка умеет очень убедительно принимать личину другого человека, возможно Бенесек растрепает всей академии. После уроков, ребята решают пойти на работу к Альду в морг, чтобы узнать как дела у Петра, предупредить его или предотвраить его смерть. Группа добирается до храма *всех религий*, неожиданно ребята обнаруживают интересные фрески и мозаики, Локи акцентирует внимание на истории *О сотворении мира*, боги сражаются с семью драконами, остаётся один последний, из его тела рождается этот мир. Британия вдохновенно рассказывает всем смежные с этим истории на 10 минут, после этого группа продвигается дальше, к уличному входу в морг. \n\nМаркус и Альд неожиданно замечают Саймона - того самого парня с рисунка Британии, и догоняют его. Маркус начинает заходить с кулаков, Британия орёт *Зачем ты убил меня, зачем ты взорвал нас, предатель, ты зачем это сделал!!!1!!!???*. Парень искренне не понимает что происходит, Локи пытается выкрутить ситуацию, чтобы ребят не скрутила стража, и все делают вид, что они разыграли пранк, готовятся к театральному выступлению, и это была актёрская игра. Саймон сворачивается и уходит, пока группа пытается разобраться между собой, как они поступают с такими ситуациями, что нужно поступать обдуманно и не нападать на всех подряд с обвинениями (не знаем, кто в курсе петли, а кто нет). Затем студенты всё-таки входят в морг и видят, как Петр лежит на полу, и из него пьёт кровь девушка (порождение вампира) в белом платье. (опоздали то ли из-за 10-ти минутного вдохновения Британии, то ли из-за разговора с Саймоном)\n\nАльд пытается спасти Петра, но тщетно, студенты набрасываются на нежить, та в суматохе боя хватает Британию, после чего получает от бардки разряд *Магической стрелы* из той самой палочки прямо в голову. Нежить успевает напоследок укусить Британию, кое как задев зубами. Угадайте что?! Правильно, очередная истерика от девушки, но всё кончается *хорошо* - пока ребята собирают остатки порождения без части головы, и тело Петра, Британия снова решила мусорнуться, добежав до участка. Оказалось, что полиция не верит ей, но идёт на место нападения и опрашивает всех про ситуацию. Становится очевидно, что полиция не хочет и вряд ли будет расследовать это дело, потому что вамипиры просто не могут быть в Сиории и это какой-то бред. В участке ребят навещает Ильза со словами *Скажите, почему, когда что-нибудь происходит, вы трое всегда оказываетесь рядом?*. Преподавательница тоже как-то скептически относится к этой ситуации, как будто все взрослые в принципе не замечают опасностей вокруг или просто устали или что-то скрывают. \n\nАльд возвращается в морг, закончить дела за Петра и опрашивает тех, кто нашёл тело девушки, чтобы позже пойти по следу. На 14 день на одной из перемен Локи разыгрывает в коридоре Академии Британию, создавая копию Саймона. Расходятся мирно. Саймон, кстати, не является учеником Академии Сиории. После занятий Британия выбегает глубже в город и пытается в одиночку найти *тот самый дом*, но блуждает и теряет кучу времени. Остальные после уроков занимаются своими делами.", "new_npcs_raw": "Ниртак - преподаватель немагического боя Ниртак\n\nБенисек - болтливый студент Бенисек\n\nСаймон - тот самый *предатель* Портрет *предателя* Саймона\n\n🥊 Анна - девушка порождение вампира в белом платье Девушка нежить из морга https://dnd.su/bestiary/308-vampire-spawn/", "materials": "- Карта морга и Храма 8 Путей \n\nХрам 8 путей.png", "materials_url": "https://drive.google.com/file/d/1RO5PE0ydj5uXjpx72pyoOitXJF64JTR-/view?usp=drive_link", "achievements": "🔪Первая сники атака и сразу в крите - Локи\n\n🤬Счётчик *Да пошёл ты* от Британии - 11"}'::jsonb),
  (7, '{"session_number": 7, "loop_number": 1, "played_at": "2025-08-27", "time_range": "20:30 — 00:30", "game_date": "1 петля, 15 странствий", "recap": "Студенты собираются в аудитории Клуба Начинающих Приключенцев (где-то за кадром процесс получения лицензии, наличие Каэла 22-летнего волшебника поспособствовало этому).\nРебята настроены на поход в подземелье, и предстоящие дни собирали деньги и готовили снаряжение (оружие, заклинания), Дрипли сварил зелье лечения каждому.\nПолучают задание от гильдии - разведка дороги до входа в подземелье и обеспечение безопасного прохода к нему. \nГруппа направляется в сторону Temple of Fortuna (см. карту окрестностей), в двух часах ходьбы от города.\n\nНа лесной дороге Маркус замечает движение в деревьях и немного паутины, но ничего опасного и студенты двигаются дальше, замечая недалеко от дороги руины. Маркус (почему-то), отправляет на разведку фамильяра пса, и находит в глубине развалин спящего совомедведя. Группа решает что с ним делать, голосует и большинством решают двигаться дальше, Каэл помечает на карте опасность.\nДальше паутины становится больше, приключенцы видят площадку с фонтаном, а Маркус замечает в листве глаза паука. Янка ветром раздувает листья, Дрипли опознаёт ледяных пауков и начинается бой.\n\nДевять пауков нападает из укрытия, заплёвывая всех паутиной, Маркуса особенно, но он отбивается (очко ци) и топчит нескольких. Дрипли в окружении заливает их кислотой и ядом, Анарион атакует и магией и оружием, Янка отбивается и предусмотрительно прячется в кустах, когда Кайл решает кинуть в пауков Дребезги. Раздаётся громкий звон, падает дерево, и на шум драки из руин выбегает совомедведь. Пока он бежит, приключенцы раскидывают остатки тварей, и неожиданно (нет) встречают новую опасность.\n\nСовомедведь сразу получает несколько удачных атак (луч слабости, луч болезни, бум палкой по макушке, пылающий шар) ото всех, и готовится убегать, как ему в спину прилетает подарок от Янки (снова очко, но не ци) и он погибает.\nАлхимики начинают собирать ингредиенты (60 з с медведя, 140 з с пауков), Янка отходит подальше не смотреть на живодерство, Анарион пробует изучать фонтан, а Маркус всем готовит вкуснейший кебаб из полудичи и все уходят на средний отдых. \n\nПосле отдыха у всех будет время заметить, как Янка стала выше на 25 см и поравнялась с Маркусом ростом (эффект Дикой Магии). В конце отдыха мастер выкидывает крит 20 на случайную встречу.", "new_npcs_raw": "🥊 Ледяной паук https://dnd.su/bestiary/7734-ice-spider/", "materials": "- Карта дороги до подземелья (руины и фонтан у мастера)", "perks": "💡Новый способ заработка - продажа ценных ингридиентов с монстров\n\n🧪Ингридиенты для зелий - 200 золотых (минус)", "achievements": "‼️Две единицы подряд - Маркус\n\n🎰Первая Дикая Магия (увеличение роста на 10 дюймов) - Янка"}'::jsonb),
  (8, '{"session_number": 8, "loop_number": 1, "played_at": "2025-09-04", "time_range": "20:30 — 23:30", "game_date": "1 петля, 15 странствий", "recap": "Группа собралась в Клубе Начинающих Приключенцев, и видит, как их товарищи уходят в подземелье без них. Студенты решают найти зацепки по телу девушки (Нежить) и идут на место, где её нашли. Это городское трёхэтажное общежитие (в 50 минутах от академии), там Альд знакомится с консьержкой, и расспрашивает о теле. Старушка указывет на компанту №3. В это время Дрюс и Энтони по одной им понятной причине, превращаются (Маскировка) в консьержку и в ходе неловкого социального инкаунтера проходят мимо старушки (она приняла это за рофл), а Британия и Фрэд просто с фэйспалмом проходят следом просто так (было очень смешно) \n\nЗа дверями в комнату грубая бабка рассказывает Британии (которая играла роль сестры убитого Петра), что нашла тело у входа в подвал этого общежития (пнула, пдумала что пьяница), и пожаловалась на соседа сверху из-за запахов. Пока ребята разговаривают с монахом, Энтони находит вход в подвал и приглашает всех спуститься. Студенты не находят никаких следов насилия в подвале среди кладовок, и решают идти дальше в канализацию, по верхнему уровню поземки, спускаясь вниз. Пройдя совсем немного, они выходят на какое-то гладкое плато в коллекторе и попадают во внезапную ловушку, хотя верхние уровни подземки считаются безопасными.\n\nМутная слизь вздымается вверх, все оказываются внутри её тела, которое заполняет всё пространство до потолка (35х35 футов). Альд телепортируется назад, освещая куб, Британия выпускает мощнейший заряд палочки (Магическая стрела 9-го круга), но слизь не отступает, Энтони усилием освобождается и атакует электричеством, Дрюс с помощью Духа Огня тоже телепортируется и вызывает Пылающий шар, Фрэд колдует Увеличение на себя, но не может освободиться. Куб продолжает надвигаться, глотая уже высвободившихся ребят, те с попеременным успехом вытаскивают друг друга, время от времени отбегая подальше, Фрэд в итоге теряет сознание внутри куба, туда влетает Альд и лечит его, и ребят успешно вытаскивают и уже на расстоянии они уничтожают слизь. \n\nПотеряв от 40 до 60% целостности немагического снаряжения, группа решает не идти дальше, а вернуться в город и восстановиться, Британия покупает всем дешёвые плащи, пишет письмо отцу с просьбой денег, и все идут в магическую лавку, где знакомятся с Савочкой. Ребята узнают цены на товары, продают слизь, которую собрал Фред, и узнают как можно заработать - продавать свою магическую силу как возобновляемый ресурс. Ничего не купив, студенты расходятся по своим делам. \n\nКомната Британии, *происходят какие-то события* в ходе которых 16-ти летняя бардка трагически погибает (за кадром, никто из группы не был свидетелем), и наверняка пропустит выступление 16-го странствий, к которому так готовилась. (ПРОДОЛЖЕНИЕ СЛЕДУЕТ)", "new_npcs_raw": "Шолоха - милая старушка, консьержка общежития, где нашли труп девушки Шолоха\n\nАгафья - мерзкая старушка, из квартиры №3, которая нашла труп девушки Агафья из 3 комнаты\n\nМонах из квартиры №17, просто чел Монах из комнаты 17\n\nСавва *Савочка* Шрэк - мужчина в рассвете сил, владелец лавки *Магические предметы Савочки Шрэка* Савочка.jpg\n\n🥊 Серая слизь http://dm-stuff.ru/creature-catalog/gray_ooze", "materials": "- Одна из песен Британии, с которой она вытупает в постановке:\n\nВо тьме нами созданной ночи\nПроносятся серые совы…\nИ блещут их мрачные очи\nИ злы, и угрюмо суровы!..\n\nИ гулко их крики несутся,\nСмеются они и рыдают,\nПроклятья в них дню раздаются,\nА ночь они смехом встречают…\n\nО, если бы мрака оковы\nС моей юной рощи упали,\nИсчезли бы дикие совы,\nИ соколы только б летали!..\n\nНо соколы, — слабы и хилы, —\nЗабилися робко в ущелья\nИ злятся без чести и силы\nПод звуки чужого веселья.\n\nИх крылья уныло повисли,\nПостыдно сердца у них дремлют,\nИ голосу чести и мысли\nСвободные птицы не внемлют…", "perks": "💡Новый способ заработка - продажа своих очков\\ячеек заклинаний у Савочки (банк спермы)\n\n🧪Ингридиенты для зелий - 100 золотых (Фред оставил свою часть на 25 золотых)\n\n🔮Бутылка с бесконечным кофе - Энтони (минус)\n\n💲200 золотых на карманные - Британия (минус)", "achievements": "🤬Счётчик *Да пошёл ты* от Британии - 14\n\n💀Первая смерть персонажа в петле - Британия"}'::jsonb),
  (9, '{"session_number": 9, "loop_number": 1, "played_at": "2025-09-07", "time_range": "18:30 — 22:00", "game_date": "1 петля, 15 странствий\n- 2 петля, 1 странствий", "recap": "Заканчивается средний отдых (в конце которого мастер в прошлой игре выкинул крит 20 на случайную встречу). Янке стыдно за то, что она не помогла сразу своей группе, но ничего не говорит, а громко молчит выше на 25 см. Дрипли сортирует ингридиенты по мешкам, Анарион помогает ему их нести. В начале отдыха ребята не выставляют дозор, никто не следит за периметром, все доедают обед от Маркуса, и собираются в путь, выбирая между тем, чтобы идти обратно или дальше к мосту через пропасть. \n\n\"Вокруг тихо и спокойно, даже птицы не поют\". НЕОЖИДАННО на студентов нападают какие-то твари из невидимости, Маркус первый с ними сталкивается и начинает душить змею. Змеи быстро окружают ребят, начинается форменный хаос, какая-то заварушка. У мастера рак кубов, поэтому всё заканчивается без потери сознания, но студенты тратят все свои силы. Группа не успев отойти от старого лагеря снова уходит на средний отдых, Маркус готовит азу из змей, чтобы все восстановили силы после отравления, а Каэл выходит в дозор. В конце отдыха мастер ОПЯТЬ выкинул крит 20 на случайную встречу. \n\nРебята снова собираются, и опять выдвигаются в сторону моста (мастер установил маленькую петлю в петле, чтобы они были в петле, когда проходят петлю). Впереди открывается большой провал, и подвесной верёвочный деревянный мост, длиной 125 футов. Маркус одним броском пробегает мост, и пока ребята выдвигаются следом за ним пешком, НЕОЖИДАННО на обоих концах моста поднимается густой туман, обвалакивающий выходы с моста. \nВсе, кроме Маркуса, останавливаются прямо над глубоким провалом. Маркус пытается ударить странную тварь с щупальцами, появившуюся из тумана, но щупальца оказываются ловчее змей и уворачиваются. Анарион кастует пылающий шар прямо над вторым монстром и в воздухе откатывает его назад, чтобы ненароком не поджечь деревянный мост. Твари не нравится новая игрушка, и одним точным критическим ударом она разрубает Анариона пополам. То же самое она пытается сделать с только что промахнувшейся Янкой (оставляет ей 1 хп). В следующую секунду второй монстр атакует всех выживших мощным конусом психической энергии. Ментальных сил большинства героев оказывается недостаточно, чтобы противостоять атаке: Янка окончательно отключается, Маркуса и Дрипли ошеломляет психический поток. Капля (фамильяр Дрипли), который ранее страховал заднюю часть моста, устремляется к Янке, чтобы оказать помощь в следующем раунде. Единственный, кто остаётся в разуме, это Каэл, и самым логичным способом спастись от этих жутких тварей он видит массовую атаку звуком по деревянному мосту. Мост раскалывается, ошеломленные герои не могут ухватиться, Капля безрезультатно пытается удерживать Янку в воздухе. Все падают в темноту\n\nИ всё повторяется заново. В пятницу, 1 день месяца, Маркус просыпается с Британией, Анарион просыпается в общежитии, Дрипли, Янка и Каэл у себя дома. Первое, что делает Анарион, это пакует вещички и прикидывает, когда ближайший поезд из Сиории. На выходе из комнаты его встречает Маркус и хорошенько прописывает леща, чтобы тот очухался. Они собираются в Золотого петуха", "new_npcs_raw": "🥊 Совомед https://dnd.su/bestiary/25-owlbear/ \n\n🥊 Аберрации https://dnd.su/bestiary/600-ulitharid/", "materials": "- Карта дороги до подземелья (руины \\ фонтан \\ мост через провал у мастера)", "perks": "🧪Ингридиенты для зелий - 160 золотых (минус)", "achievements": "💀💀💀💀💀 Первая *Тотал килл пати*"}'::jsonb),
  (10, '{"session_number": 10, "loop_number": 1, "played_at": "2025-09-09", "time_range": "19:30 — 23:30", "game_date": "1 петля, 14 странствий", "recap": "Студенты встречаются в аудитории клуба, застают Янку, Локи подписывается в списке Дрипли, и пока никто не обращает внимания, Локи изучает помещение обнаружением магии, и находит (список у мастера). В ходе беседы студенты решают, что в клуб должны вступать только те, кто помнит прошлые события. В клуб хочет вступить Бенисек, со словами *А Британия тут с вами?*, но его прерывает Янка длинной тирадой какой он хуйло, выгоняя его за дверь. Студенты фиксируют правило клуба: *Никому не говорить о тайном клубе.* Бенисек подслушивает под дверью и 15 числа пошёл слух о клубе по свержению короля. Группа решает снова пойти в морг, искать путь по которому могла убежать нежить в прошлой петле.\n\nПо пути ребята встречают мальчишек, которые продают уродские пельмени.Альд даёт им подаяние, Дрипли скупает все пельмени, Энтони спрашивает о слухах, и ему рассказывают о волшебнике Горнокрабле, который поднял таверну, повертел на пальце и даже не пролил ни капли пива. Добравшись до храма и  зайдя в морг ребята начинают искать тайные ходы из морга, которые ведут в подземку. Янка и Альд ничего не находят в холодильнике, а Энтони и Дрюс замечают полость под полом лифта. Ребята пытаются вскрыть каменную кладку, чтобы Дрипли мог в неё протиснуться, Локи пробует магией подобрать ключ к лифту, чтобы он спускался вниз, а Энтони вспоминает что есть бусина для нужного заклинания опознания, и бежит в академию. В это время в морг спускается настоятель храма, и спрашивает что здесь происходит, Альд объясняет ему о расследовании гибели Петра и теле девушки, настоятель уходит. (хорошо, что в этот момент Локи не сбросил невидимость со своего фамильяра, потому что он выглядит буквально как бес) \n\nПока Энтони бегает туда-обратно, Альд поднимается к настоятелю и просит его дать ключ от прохода, чтобы проверить теорию о том, что нежить как-то может им пользоваться. Настоятель неуверенно даёт ключ, и пока Альд возвращается, как раз прибегает Энтони. Ключом ребята открывают проход, и чтобы не рисковать Локи отправляет Йотуна в невидимости на разведку вниз, в образе паука незаметно пробирается по коридору подземного склепа, и выходит на комнату в которой шатается 20 умертвий, дальше такой же коридор и комната с 20 умертвиями, ещё дальше в проходе виднеется свет, и Локи возвращает фамильяра назад. Альд оставляет проход открытым и бежит рассказывать настоятелю что увидел, и уже вдвоём быстро возвращаются обратно, закрывая проход. Дрипли предлагает услуги приключенцев, но Марцелл сказав что их сил не хватит, отправляется за помощью к верховной жрице и запрещает студентам лезть вниз. Через час в морг входят: настоятель храма Марцелл, младший жрец старого храма Батак, верховная жрица старого храма Килая и вялый детектив Хаслуш. Спустившись в подвал со спутниками, Жрица двумя мощнейшими молитвами стирает умертвия в петел и никого не находят в комнате со светом. После этого проход закрывают и остаётся Хаслуш на допрос.\n\nХаслуш опрашивает всех студентов, показывая глубокие познания в биографии и некоторых событиях в жизни приключенцев. Альда в связях с нежитью (из-за прошлого Суламнона), Янку спросил про нелегальное использование иллюзий, и переходит к Локи. Используя область истины Хаслуш узнаёт у Локи про то, что он не из этого мира, но не несёт какой-то прямой угрозы. Ребята в шоке. Хаслуш просит Локи зарегистрировать своё нахождение в городе и уходит. Студенты начинают активно расспрашивать Локи о его природе, о силах и о добре со злом, он неохотно но отвечает и они вместе собирались выходить из морга, как оказалось их на выходе подслушивал и ждал Хаслуш. Локи забирают в участок, в сопровождении 4-ёх человек (эшники). Там на Локи оказывают давление и просят принести присягу короне, используя заклинание Обет, при помощи Юлиана Альфреда Панкраца (куратор Британии). Он не может нарушать законы Сиории (используя магию иллюзий без регистрации будет получать по голове магией)", "new_npcs_raw": "Марцелл Червини - настоятель Храма 8 Путей Марцелл Червини  \n\nБатак из дома Рэйд - младший жрец старого храма, куратор Альда Батак Рейд \n\nКилая Купоси - верховная Жрица старого храма, провидица\n\nХаслуш Энзетери - детектив, который много знает о студентах\nХаслуш Экзетери \n\n🥊Умертвие https://next.dnd.su/bestiary/21627-wight/", "materials": "- Карта части подземки под моргом в Храме 8 путей \n\nХрам 8 путей.png", "materials_url": "https://drive.google.com/file/d/1RO5PE0ydj5uXjpx72pyoOitXJF64JTR-/view?usp=drive_link", "perks": "🔮Локи (несколько необычных предметов) \n\n🕳️Найден секретный вход в подземелье в морге Храма 8 путей"}'::jsonb),
  (11, '{"session_number": 11, "loop_number": 1, "played_at": "2025-09-12", "time_range": "20:00 — 00:00", "game_date": "1 петля, 16 странствий\n- 2 петля, 1 странствий", "recap": "Альд утром идёт в морг, думает о смертях вокруг. Локи с помощью Йотуна проверяет, кто следит за ним у дома, замечает двух в штатском. Отправляет Йотуна в город, находит КПП перед подземельем, не видит путей в обход, и Локи идёт на фестиваль, а за ним хвост. Энтони в библиотеке находит карты академии, ничего секретного, и уходит в таверну. Дрюс просыпается с влажными фантазиями о Британии, прихорашивается, и направляется к комнате бардки. У дверей он встречает Эстина Гриера, оба стучатся в дверь, тишина. С помощью коменданта открывают дверь и видят тело девушки, погром из-за взрыва, коменда закрывает дверь и вызывает полицию. \nДрюс пауком попадает в комнату, видит палочку с инструментами, осколки стекла, выбитые наружу, и возвращается в коридор, пока полиция попадает в комнату и фиксирует несчастный случай. Роза выходит из комнаты и видит, как выносят тело Британии, в испуге пишет письмо тёте, выходит в коридор, и начинает причитать Дрюсу *мы прокляты*. Оба идут за санитарами в морг. До Энтони доходят слухи о пропавших студентах и теле девушки, он всё понимает и бежит в морг, по пути встречает Локи, который тоже слышал о пропавшей Британии, и встречают Лайонела, который ищет Дрипли. \n\nЗаносят тело Британии, Альд принимает его, Дрюс рассказывает подробности, Роза причитает *Мы точно прокляты и ребята пропали*. Альд просит найти Хаслуша, ребята выходят из морга, встречают Локи, Энтони и алхимика, и оказывается, что Хаслуш лично следит за Локи. Возвращаются в морг под тихое пение, Хаслуш использует разговор с мёртвыми, Бардка выдаёт всё, что знала. Начинается сумбурные разговоры: Альд и Роза думают линять из города, Дрюс найти обидчиков Британии, Локи и Энтони идти с поисковым отрядом спасать ребят. Хаслуш не отстаёт от Локи, и в этот момент в морг залетает Зак Новеда, наперебой твердит *Вы тоже там были, всё знаете, я пережил миллион жизней, ничего не имеет смысла*, прямо при всех. Студенты невнятно пытаются его успокоить. Таким составом собираются с поисковой группой, Роза и Альд нехотя следуют, Зак на своей волне, остальные воодушевлены, Лайонел встревожен. Перед академией встречают разъярённую мать Янки, которая разносит всех трёхэтажным матом, и группа выходит по следу. Лайонел использует свиток поиска, приводит всех к фонтану, видно кострище и тела пауков, а дальше обрыв. Группа доходит до упавшего моста, на той стороне видно тело Маркуса без мозгов (аахахах), из тумана появляются две аберрации. \nАльд и Роза начинают отступать назад, Зак и Энтони целят в одну тварь, Локи и Дрюс подхватывают, Лайонел и Хаслуш добавляют, и первой твари достаётся. Сзади два паука преграждают отступление Розе и Альду. Одна тварь использует взрыв разума, группе сильно достаётся, а вторая берёт Локи под контроль, заставляя напасть на союзников. Монстры по очереди атакуют и прячутся, группа использует весь арсенал, пока Хаслуша не роняют, высасывая мозг. Лайонел начинает спасать студентов, используя переносящую дверь, Альд попутно лечит тех, кто уже упал. Бежать, лечить, дождаться Лайонела, спрятаться. Почти все спасаются, но Зака утаскивают в обрыв, а Энтони, жертвуя собой, погибает на руках товарищей. Группа возвращается в город.\n\nСобирается сильная группа для возврата тел, с армией, без студентов. Фестиваль проходит без огласки, чтобы не пугать людей. Альд в морге ждет новые тела, думает уезжать из города, а ночью просыпается от боли, видит зелёную вспышку и мгновенно умирает. В это же время с Локи происходит тоже самое - 60 оживших игл в один миг впивается в тело Локи, и даже Йотун не успел предупредить. Дрюс остаток петли бухал в таверне (помянем погибших), его прибило огненным шаром прямо за баром. Роза уехала из Сиории после новостей о смерти Локи и Альда, 31 странствий засыпает и просыпается в начале петли. Локи же открывает глаза с телом любимой на руках, опечаленный, но полный надежды.", "new_npcs_raw": "Эстин Гриер - одноклассник, искал Британию, которая не пришла на финальную репетицию Эстин Гриер", "materials": "- Песня, которую пел Альд в морге:\n\n\"Я вижу, как закат стекла оконные плавит.\nДень прожит, а ночь оставит тени снов в углах.\nМне не вернуть назад серую птицу печали.\nВсе в прошлом... Так быстро тают замки в облаках.\n\nТам все живы, кто любил меня.\nГде восход, как праздник бесконечной жизни.\nТам нет счета рекам и морям,\nНо по ним нельзя доплыть домой.\n\nВозьми меня с собой, пурпурная река.\nПрочь унеси меня с собой, закат.\nТоска о том, что было, рвется через край\nПод крики серых птичьих стай.\"  \n\n♣️ Колода карт: \nВопрос *Что с ребятами, кто жив*\nОтвет *Дьявол. Королева мечей. Четвёрка жезлов*\nИнтерпретация *Группа встретилась с потусторонней демонической сущностью, все погибли, возможно выжил один*", "achievements": "🏁Дожить до конца петли - Дрюс, Роза, Фрэд, Рион\n\n🔝4 игры за 9 дней - Мастер"}'::jsonb),
  (12, '{"session_number": 12, "loop_number": 2, "played_at": "2025-09-24", "time_range": "20:00 — 00:00", "game_date": "2 петля, 1 странствий\n2 петля, 2 странствий", "recap": "Британия и Маркус как всегда просыпаются вместе. Британия планирует свалить и собирает вещи в своей комнате, пока под дверь не прилетает письмо \"От тайного поклонника\". В коридоре оказывается пусто, а в голове Британии звучит голос Альда: \"Умоляю, не выделяйтесь, за нами могут следить и избавиться, возможно враги тоже помнят. Избегайте собраний, следуйте распорядку. В твоей комнате письмо. Ключ - фамильяр Локи\". Не читая письмо, Британия возвращается к Маркусу и нарочито открывает конверт прямо ему в лицо. Только вместо романтического признания в письме оказывается несколько неразборчивых пунктов, вероятно зашифрованных. Не справившись с шифром самостоятельно, Маркус и Британия подхватывают Анариона (см. рекап 9) и идут домой к Дрипли \n\nДрипли просыпается в истерике от произошедшего, профессор Лайонел приходит на крики и даёт ему зелье для успокоения. После того, как ребята заваливаются к нему в дом, происходит пара неловких диалогов с профессором, совместный завтрак и попутная расшифровка письма (после этого письмо сжигают). Там же к ним присоединяется Локи, который проснулся в библиотеке (см. рекап 11) и слонялся по городу\n\nЧтобы переварить *полученную информацию*, все ребята проводят некоторое время наедине: Маркус тренируется, Дрипли снова делает листовки, Британия чиллит в парке, а Локи вскрывает клубную комнату и возвращается в библиотеку (там же работает Анарион). Ближе к 14:30 они договариваются встретится в Золотом петухе\n\nПока все присаживаются в таверне и заказывают пиво, в неё врывается всклокоченная Янка, с криками \"Дрипли, ты живой!\" бросается на парня и начинает рыдать. Ребята выясняют, что по сути умерли из-за Каэла, и в их головы закрадываются подозрения. Спустя несколько сальных взглядов Маркуса на барменшу, в таверну заходит Зак. Проницательные герои замечают, что Зак рассказывает лишь половину правды, а так же ничерта не помнит, не пускает в свой мозг и горит идеей предотвратить вторжение. Британия без оглядки вешается на него и наслаждается дуэлью между Маркусом и Заком: они уходят на площадку Академии, Зак преимуществом дистанции и магии (туманные шаги, вихрь пространства, элдрич бласты и облако кинжалов) побеждает Маркуса. Но монах так просто не сдаётся и под видом мирного рукопожатия погружает Зака в сон вспеском ци. Довольный собой, Маркус уходит, падает от головной боли (диссонирующий шёпот от Британии), встаёт и, не оборачиваясь на сосущуюся парочку, идёт дальше как победитель\n\nПока самцы махаются за бардку, в таверне Локи *от скуки* телепатически объсняет Дрипли, что такое отношения между мужчиной и женщиной, чем очень сильно смущает Янку. Когда все вновь возвращаются за стол, герои решают, что нужно становиться сильнее и выяснять больше информации\n\nНа следующий день, в субботу, после выбора факультативов ребята резервируют зал для тренировок. Первый бой: девочки+Дрипли против Локи, Анариона и Маркуса. Британия мощно даёт своей команде +20 хп, Дрипли поит экспериментальными зельями смелости. Мартиалы быстро отлетают от молнии (сопровождающейся лепестками цветов и бабочками), кислотных всплесков и нестройных мелодий. В реванше Британия и Маркус меняются командами. Дрипли делает Маркуса и его кулаки большими, так что противников отпинывают по одному. Янку очень сильно пытаются уронить, подключая фамильяров, но Дрипли дважды её поднимает (ещё немного ищет червяков). Янка добивает Анариона, который опрометчиво спрятался за прекрасным проводником электричества (задом Маркуса) и не имел ни шанса убежать от цветного шарика. Кажется, герои и в правду придумывают какую-то тактику", "materials": "- Письмо Альда: \n*Советы.\n1. Мы снова здесь, это повторилось, возможно это ловушка. Всё, что у нас есть - это сила духа и память. Берегите их.\n2. Лучше скрывать мысли и намерения, те кто отличаются очень заметны, ищите отличия от прошлого цикла. Вас могут найти так же.\n3. А если хотите выбраться, то нужно стать сильнее, для этого лучше знать что происходит, а значит доживать до конца. Знание - сила.\n4. Постарайтесь избегать открытых собраний по принципу *Те кто помнит*, так вы раскрываете свои карты. Никаких списков.\n5. Найдите укромное место, где сможете хранить и копить ресурсы, создайте легенду на случай раскрытия, например *Клуб исследований всего*.\n6. Есть свидетельства, что Зак Новеда помнит или понимает, что он тоже в петле, но у него длинный язык и необдуманные действия. Лучше завербовать.\n7. Каждый цикл важен. Судя по ощущениям и силам, цикл был не один, доказательств нет и неизвестно сколько их ещё будет и будут ли ещё. Нельзя тратить время понапрасну.\n8. Кто друг, а кто враг сложно разобрать, доверяйте только своим суждениям и подвергайте всё сомнениям. Даже это письмо.\n9. Обратите внимание на мозговых крыс, они не случайно появились в первый день и если умеют читать мысли - не попадайтесь, защитите разум или скройте мысли. Возможно шпионы.\n10. Некоторые не дожили до конца месяца, умерев в постели дома. Подумайте как себя обезопасить, скрывая своё местонахождение.\n11. Думайте основательно, поступайте осторожно. Желательно сжечь письмо, и придумать свой шифр. Ваш друг и скромный советник.*", "achievements": "🤬Счётчик *Да пошёл ты* от Британии - 16\n\n💞Пестики и тычинки. Ликбез об отношении полов - Локи для Дрипли\n\n⚔️Первая PvP - боевая тренировка три на три"}'::jsonb),
  (13, '{"session_number": 13, "loop_number": 2, "played_at": "2025-10-01", "time_range": "19:30 — 00:30", "game_date": "2 петля, 2-9 странствий", "recap": "В пятницу первый день Рион встречает в своём поместье овцу-мага, забирает у него свиток и отдаёт животное Аериси. Обращается в банк, на полученные деньги экипируется. \n\nВ субботу Альд находит ребят после их тренировочного боя и встречаются с Клубом исследователей всего. Ребята решают собрать всё золото, до которого дотянутся, помня прошлую петлю. В первую очередь идут в подвал общежития, чтобы убить слизь, и собрать с неё ингридиенты для зелий сопротивления разума Дрипли. Там же Локи просит Альда снять с него Обет, жрец не сразу соглашается, но делает и вместе со Снятием проклятья к Локи приходят обрывки воспоминаний *Зак кричит на Дрипли: ЭТО ТЫ ВО ВСЁМ ВИНОВАТ*. Дальше по подземке не идут. \n\nЗатем группа идёт к дому личинок, Дрипли переживает, что забирают задание у Тайвен, поэтому Янку просят под неё замаскироваться, но она решает по-другому. В сторожку стучится высокий темноволосый монах и уверяет Адама в том, что его левой и правой хватит. Пока ребята прячутся в кустах, Янка видит в доме старый рояль, начинает на нём играть, и как будто её игре внимает невидимая публика. Пробравшись в дом група видит картину маслом - Маркус играет великолепную увертюру на клавишах. Пока Локи и Рион проверяют дом на магию, Фред буднично убивает личинок Огненным шаром, а Дрипли повторяет трюк с раздеванием и чисткой труб (видел такое видео). Совместными усилиями ребята Рассеивают магию у секретной двери, натыкаются на сильную школу ограждения, Рион выпускает своего змея, но тот не может пройти сквозь стену из-за защиты, и тут возвращается дворецкий, даёт деньги и просит на выход. \n\nДалее группа идёт в лавочку Савочки, и закупается. Рион придумывает бизнес с продажей лат, Локи продаёт предметы из аудитории, Янка продаёт заклинания, Фрэд покупает свитки. Торговец даёт постоянную скидку 5% (для друзей и приключенцев). После ребята уходят на недельный перерыв на подготовку: Дрипли варит зелья, Альд вместо него раздаёт листовки, остальные тренируют новые заклинания, Янка не жалея себя. Помятуя дребезги в мост, ребята не зовут Каэла, но он помогает получить лицензию на спуск в подземелье. \n\n9 дня в субботу группа выходит к Храму удачи, взяв задание на разведку. Всё также находят развалины, но без совомеда, а далее нападают на пауков. Ребят быстро окружают, но в этот раз они готовы, Молния Янки уничтожает сразу трех и поджигает пару деревьев, Фред кастплеит Кайла и бросает Дребезги, падает дерево, Локи отвлекает копиями, Рион с Дрипли на передовой, их окружают, но Снаряд хаоса от Янки и последующий всплеск дикой магии с электричеством уничтожает пауков в щепки. Весь бой Рион увеличивал своего фамильяра, и в самом конце огромная змея убивает посленего убегающего паука. Дрипли собирает ингридиенты, остальные помогают и немного отдыхают.\n\nВсе усиляются перед битвой (максимум и временные хиты, зелье сопротивления, героизма и на концентрацию), по плану выманить аберраций, Дрипли кричит и зовёт их, ничего не происходит, Рион выходит вперёд, Альд понимает, что они тратят секунды (раунды) длительности заклинаний, и выбегает на середину моста, и вот тут уже появился аберрации.\n \nДрипли телепортирует Альда с моста, Фред, Янка и Локи стреляют издалека, Рион на передовой отвлекает внимание и танкует. Хекс, Вызов страха, Огненный шар и Мистический заряд делают своё дело, и за 30 секунд монстры подают в ущелье. Битва окончена.", "perks": "💲Выполнение задания - 60 золотых\n\n🧪Ингридиенты - 125 золотых (Слизь) \n\n🧪Ингридиенты - 200 золотых (Пауки) \n\n🧪Ингридиенты - 180 золотых (Аберрация)", "achievements": "5️⃣0️⃣ Аргентина - Ямайка: отыграно 50 часов\n\n💡Первое вдохновение - Янка"}'::jsonb),
  (14, '{"session_number": 14, "loop_number": 2, "played_at": "2025-10-09", "time_range": "20:00 — 00:30", "game_date": "2 петля, 9 странствий", "recap": "После победы над аберрациями, Локи осматривает Йотуном дно ущелья, там копошится нечто тёмное, ужасное, злое. Ребята не лезут вниз, но решают так: Дрипли отнесёт ингридиенты пауков и аберраций в город вместе с Янкой, которая выглядит ослабшей (после недельного марафона занятий). Альд отправляет Послание Маркусу, и все остальные обустраивают лагерь у фонтана, додаться подкрепления. Рион многократно увеличивает фамильяра, и обвивает им лагерь вокруг, для защиты. \n\nЗаканчивая средний отдых, к лагерю приближаются Энтони и Анарион, и видят только громадного змея. Энтони решает её уменьшить; герои по ту сторону замечают из-за змеи товарищей, готовых к бою. Анарион садится возле костра, как неожиданно на него нападеет сразу 5 змей из невидимости. Группа мгновенно реагирует, спасает товарища и убивает 4 змей, а в конце боя Энтони подбегает к Риону и бьёт его в живот с криками *На тебе сидит ещё одна змея*, но это был обёрнутый вокруг пояса фамильяр Риона. \n\nТоварищи проводят короткий отдых, во время которого Локи отправляет на разведку Йотуна, посмотреть вход в пещеру, Фрэд предсказывает *Горе*, Альд гадает с результатом *Рыцарь, слуги, нежить*, и встают как вкопаные возле моста не решаясь идти, остальные осторожно двигаются ко входу в храм. Локи создаёт три фамильяра, Рион отправляет змея, и начинается активное изучение помещений - тёмный, пыльный склеп, с захоронениями, колонны, изображения подков и тишина. Пока фамильяры исследуют коридоры, Анарион возвращается за мост разузнать о символах у Альда и Фрэда, те снова предупреждают об опасности, но чародей возвращается в склеп.\n\nВремя от времени на фамильяров нападают тени и даже убивают часть из них, приключенцы продвигаются внутрь и случайно разделяются: Рион находит в глубине меч на постаменте, Энтони догоняя его сталкивается с тенью, Анарион бежит их предупредить, Локи остаётся один возле алтаря. В это время Альд и Фрэд мило обсуждают предсказания и гадания, ждут представителей гильдии для передачи лагеря от разведки, сторожат вход на мост. \n\nПочти одновременно Энтони кастует Волну грома, Локи берёт драгоценные камни, Рион берёт меч, как вдруг тишина нарушается стуком крышек гробов, из которых по всему храму встают умертвия. Локи первый реагирует, создаёт иллюзии и выбегает в главный зал, выход преграждают умертвия, как и другим по всему храму, каждый сталкивается с 4-6 врагами. Энтони использует Невидимость и Отражения, Рион бежит напролом убирая меч в рюкзак находу, Анарион использует Щиты с помощью амулетов, каждый сам за себя и пытается выбраться. \n\nЛоки чудом выбегает первый, кричит Альду, тот бежит через мост на помощь. Фрэд непреклоннен, прикрывает тылы. На ходу Альд начинает кричать изгнание нежити, они освобождают выход и бегут внутрь храма, им навстречу по алтарю вбегает полуживой Анарион, следом бледный Энтони и Рион отмахивающийся от всех щитом. Жрец второй раз изгоняет нежить не так удачно, но лечит товарищей и все пулей вылетают из храма, пересекая мост. Умертвия не преследуют грабителей, остаются в храме. \n\nФрэд многозначительно заявляет всем выжившим *Я это предвидел*", "new_npcs_raw": "🥊 Тень https://dnd.su/bestiary/283-shadow/", "materials": "✉️ Послание:\nМаркус. Встречай Дрипли, Янку, отправь к мосту Анариона, Энтони. Передай Гильдии, выполнили разведку, пусть проверяют, отдадут вам деньги или принесут нам. Ждём у моста. Альд.\n\n♣️ Колода карт: \nВопрос *Какой враг нас ждёт за мостом*\nОтвет *Повешенный. Влюблённые. Рыцарь пентаклей*\nИнтерпретация *Рыцарь (воин) с поддержкой слуг, нежить*\n\n- Предсказание Фрэда *Горе, для неблагоприятных событий - Пиздец*\n\n- Карта первой части Храма Удачи", "perks": "🧪Ингридиенты - 400 золотых (Змеи) \n\n🔮Камни удачи - Локи\\Рион \n\n🔮Меч Дурака - Рион", "achievements": "🌭 Сосисочная вечеринка - партия без женских персонажей."}'::jsonb),
  (15, '{"session_number": 15, "loop_number": 2, "played_at": "2025-10-11", "time_range": "17:30 — 22:00", "game_date": "2 петля, 9-10 странствий", "recap": "За кадром Маркус выиграл на боях 100 зм и взял кредит 500 зм. Каэл тоже взял кредит под залог лавки. Так может сделать любой игрок. Каэл оправдал свой фатальный вдребезги по мосту паникой. \n\nДрипли, Янка и Маркус приходят сдаваться в Академию, по пути встречают в одном из тренировочных залов Дрюса, который уже щёлкает огненные шары. Выясняется, что в задании было прописано разбить полноценный лагерь со строительством укреплений, без этого никакой награды. Так же предлагают заработать на доставке писем и грузов 2 зм/день (все отказывают). \n\nПолученные ингредиенты относят в лавку к Каэлу, туда же чуть ранее подошла Роза, которая ищет Альда, чтобы тот помог ей с расследованием смерти няни. Все, кроме Янки, устраивают цирк с недоверием Розе, сначала неохотно приглашают её в клуб, потом не приглашают, короче договариваются на том, что помогут ей (в начале след петли), если она будет полезна на боевых вылазках. До вечера все шестеро жёстко варят хилки и зелья сопротивления некротике (спойлер: Маркус, которому влетело, не выпил зелье)\n\nНа утро 10 дня ребята возвращаются к Храму удачи с созданными Дрипли инструменты плотника и небольшими запасами для группы, все активно валят деревья и устанавливают чистокол по периметру фонтана, строят небольшую хижину внутри (тратят 4 часа). \n\nМост преодолевается без происшествий, Маркус как обычно пробегает первым (а ещё он снова большой), на входе в храм он видит двух бронированных мертвечин, которые явно не рады гостям. Каэл подходит ближе и даёт монаху ускорение, чтобы тот крошил кости. Маркус влетает в храм с кулаков (под песню Sweet dreams), замечает, что окружён уже 4 умертвиями, и только с одним ударом в спину убегает обратно. Сразу за ним добегает Дрюс, замечает 4 цели в тусклом свете и естественно даёт огненный шар куда-то за них. Янка и Роза остаются в отдалении, Роза успешно бьёт с хексом и критом. Из-за ниш выглядывают еще 6 скелетов, производя обстрел по ближайшим целям. Каэл не упускает возможность еще раз скастовать вдребезги, чуть не обрушая проход в храм. \n\nПродвижение дальше происходит медленно, кастеры заготавливают действия атаки по высовывающимся умертвиям, Маркус подбегает и вырубает врагов в нишах (3 крита), пытаясь туда же втиснуться. Скелетов становится всё больше. Кажется, их тактика заключается в том, чтобы максимально побить видимые цели. 20+ стрел летит то в Маркуса, то в Дрюса и его маленького духа, то в неудачно подставляющихся Янку с Дрипли (попадает обычно 1-3 стрелы). Вместе с Маркусом следует капля, через которую Дрипли хилит монаха. \n\nКогда герои преодолевают уже 2 зала, в общей сложности убив 16 умертвий, в темноте виднеется ещё одна группа из 8 лучников. Роза блокирует их дальнобойные атаки, кастуя голод Хадара, и ближайшую минуту атак не происходит (умертвия отошли в залы и собирают подкрепление). Во время этого затишья, Маркус на 330 футах скорости перекидывает всех дохляков в ущелье, ловит отходняк, остальные перегруппировываются в ближайшие ниши. \n\n17 раунд начинается с того, что тьма спадает, Дрипли самовольно первым высовывается из ниши, в него летит около 20 заготовленных стрел и большой топор. Несколько стрел попадает, топор врезается ему в грудь, он еле стоит на ногах, разворачивается и убегает нафиг. Янка тут же выбегает за ним, поддерживает, даёт зелье лечения. Стало понятно, что ресурсы уже истощены, пора валить. Маркус проносится мимо Янки и Дрипли и выхватывает последнего, донося его до другого края моста, Каэл перебегает в нишу на пути к выходу, Дрюс кастует за собой дрожь земли, Роза уходит в невидимость. Следующий залп стрел летит в спину Дрюсу, он падает. Каэл даёт ему выпить зелье лечения, сам выбегает из храма, но мёртвый генерал отдаёт приказ снова расстрелять поднимающегося друида. Стрелы летят в поднятую руку и отрубают ему кисть. Маркус выносит и Янку, и Дрюса с его кистью, и Розу, которая чуть не спалилась перед легионом нежити. \n\nФрэд многозначительно заявляет всем выжившим *Я это предвидел*.", "achievements": "🎲Три критических двадцатки от большого Маркуса\n\n🩸Первое критическое ранение (оторвало кисть) - Дрюс"}'::jsonb),
  (16, '{"session_number": 16, "loop_number": 2, "played_at": "2025-10-13", "time_range": "19:30 — 00:00", "game_date": "2 петля, 11-13 странствий", "recap": "Понедельник начинается с пар, на основах инвокации разбирают формование воды. Маркус заинтересован в формовании пива. Янка всех игнорит, отмахивается от Дрипли, снова считает ворон на уроках. После занятий приезжает дядя Маркуса, жрец Колин Грант, Альд и Фред тоже идут встретиться с ним, а Дрипли ловит Янку по направлению к выходу из Академии. Происходит небольшая эмоциональная перепалка, которую оканчивают слова Дрипли о том, что Янка является соосновательницей клуба приключенцев и теперь все решения проходят через неё тоже. Тем временем Маркус рассказывает дяде о петле вопреки сопротивлению других петлевиков. Дядя просит доказательств, заявляя, что это звучит слишком невероятно и дальше 6 секунд никому не удавалось отмотать время. Даже 9 круг лишь ограничивает время на короткий период в локальной области, точно не весь мир, возможно этому подвержена только Сиория (?). Фред предлагает воспользоваться предзнанием и предсказать грядущие события, на что Колин говорит, что у этого будет другое объяснение - предсказания. Вспомнив свою специализацию, Фред потупился. Альд пробует Снятие проклятья, но никакого эффекта не было. Тогда Маркус просит в качестве доказательства на следующий раз сообщить ему сейчас какую-то информацию, которую дядя никогда никому не рассказывал. Колин обещает подумать над этим. Так же дядя навестит мать Маркуса в больнице для душевнобольных и поинтересуется, не поступали ли к ним другие \"путешественники во времени\". \n \nПосле герои забирают награду за лагерь (200 зм.), деньги быстро разбирают (Альд в счет долга, Янка на еду, Фред для заклинаний, Дрипли для зелий). Собравшись в клубной комнате, ребята принимают решение завести более плотное знакомство с криминальным миром (узнать больше городских тайн и заработать денег). Они направляются в Гадкий Койот, паб, где не воротят носы от тёмных дел, жестокости и крови. Янка принимает облик какого-то друга Маркуса, тоже качка по имени Кассий. Маркус, победивший на местных подпольных боях в пятницу 8 странствий, уверено здоровается с местными завсегдатаямию, они копируют \"пьяный\" стиль студента в шутливом салюте. Поговорив с барменом, Маркус ведет всех в 3 комнату, где за игрой в бильярд их встречает Джуров Йово Иванишевич. Общий посыл Луперов \"Мы хотим на тебя работать, здесь и сейчас,\" - не встречает понимания у Йово, поэтому он устраивает проверку для компании школьников. Задание заключается в том, чтобы подкинуть свинцовый кейс в кабинет на втором этаже поместья на улице Грина так, чтобы хозяин и не узнал о его пропаже. В разговоре Альд случайно упоминает Локи, но понимает по глазам Йово, что тот его знает. Дрипли весь диалог перетягивает внимание и своим идеализмом заставляет чувствовать себя не в своей тарелке каждого в комнате.\n\n\"Отправившись на дело, не доверяй даже стенам\" - таким подходом руководствуются подростки, безуспешно пытающиеся поймать слежку в толпе. Они прячутся в переулок, Альд остается на стреме, но не обнаруживает в 30 фт зоне неожиданных источников магии. Затаив дыхание и ожидая подвоха, Дрипли с помощью капли приподнимает крышку кейса, и взглядам группы открывается подготовленное внутри пространство для хранения предметов габаритами листа А4, но пустое. Альд внимательно смотрит и не замечает ни одного следа магии внутри. Тем временем Маркус взвешивает в руке камень, понимая, что не добросит его до стайки стрижей, которые по его мнению следят за ними. Добравшись до улицы Грина с её богатыми поместьями и найдя нужное, ребята останавливаются в 100 метрах от цели. Решают, что пойдут Альд и Дрипли, для чего оба принимают зелья полета и входят в невидимость за счет концентрации жреца. Остальные таятся в ближайших кустах. Без проблем перелетев ограду, двое домушников окидывают особняк взглядом. Темные провалы окон скрывают за собой картины свершившегося грабежа: в поместье всё было перевёрнуто, книги выброшены на пол, не видно никого живого. Переговариваясь шёпотом, они подлетают к окну второго этажа, Дрипли непринуждённо вскрывает окно и вздрагивает от оглушительного сигнала тревоги. Альд влетает внутрь несмотря на звуки, проносится вихрем по комнатам, выискивая кабинет, видит через окно подбегающего Маркуса и в панике переносится из поместья наружу. Короткий разговор, и Альд шагает обратно, кладет кейс на стол и выходит наружу. В двор дома телепортируется наряд ЧОП. Луперы в спешке покидают территорию, разделяются, прячуься и  в итоге сбрасывают с плеч погоню. Дрипли потрясён: \"Альд, мы что, злодеи?\"\n\nМаркус, Альд, Дрипли возвращаются в Гадкого Койота, а убежавшие раньше всех Янка и Фред доходят до клубной комнате. Многие посетители паба успели уйти. Йово в комнате не доволен действиями группы, но выдает награду в 40 зм и советует заниматься честными делами, а к нему обращаться как клиенты. Йово может представить ребят организатору анонимных встреч - аукционов. Взнос 100 зм для обеспечения приватности и защиты гостей от прорицания. \n\nВо вторник после занятий Альд и Маркус посещают репетицию оркестра, где Янка играет на цимбалах. Они замечают, что Янка действительно отдаётся процессу, выглядит спокойно и даже расслабленно. Вечером Янка и Дрипли толкают зелья студентам, на полученные деньги варят еще. Альд просит Петра поменяться сменами и приглашает на ночевку в морге, чтобы подловить Саймона. Идут все, кроме Янки, она отказывает тут же. Ночью не происходит ничего необычного, разве что в какой-то момент Дрипли \"пропадает\", становясь просто полупрозрачной лужей (он так спит). \n\nВ среду 13 странствий, сбегая с последних факультативов, парни собираются в морге для засады, Янка в образе случайной прохожей поджидает снаружи храма Саймона (умный парень в очках) и равнодушно скользит взглядом по подъехавшей к моргу телеге с телами. Когда мимо храма проходит Саймон, Янка начинает преследование с несколькими сменами облика. Альд принимает 4 тела в морге, пока остальные ребята невидимы, тело девушки кладёт на рабочий стол. Её пеленают верёвками и ждут, когда же она \"оживёт\". Девушка открывает глаза, дергается, чтобы укусить оказавшегося рядом Маркуса, и получает по лбу. Парни начинают допрос, отродье вампира, пытаясь порвать веревки, нечленораздельно рычит. Не справившись, она сначала жалобным человеческим голосом просит ее освободить, а затем что-то шепчет. Маркус наклоняется, чтобы услышать, и отшатывается, когда его снова пытаются укусить. Девушка рвёт веревки и бежит к выходу, отшатываясь от солнца. Парни перестают сдерживаться, и начинается избиение. Вампирша пытается сорвать с Альда его сутану, но оказывается в захвате. Девушка сдаётся и плачет. Фред говорит, что у него есть план и её можно отпустить, но перед этим атакует ее разум и оставляет там \"маячок\" для слежения. Вампирша на радостях игнорирует боль в висках, быстро закутывается в плащ жреца и выбегает из храма. Парни переглядываются и сразу же бросаются в погоню. Дрипли быстро перед уходом оставляет фамильяра с посланием для Янки. Уверенно ориентируясь, девушка бежит по переулкам, поднимает решетку и спускается в канализацию, продолжая свой бег под улицами. Подростки преследуют её, не отставая ни на шаг. Поняв, что она не может оторваться, вампирша разворачивается и кричит: \"ЧТО ВАМ НУЖНО?\".  В ходе короткой беседы она называет своё имя (ее зовут Анна) и отрицает то, что она вампирша, со словами \"Нет, она не могла так со мной поступить\". Узнать больше информации пока не удается, Анна настаивает на том, что никого не убьёт, и просит её отпустить. Парни перешептываются и отпускают её, на этот раз не преследуя. Первые 15 минут. \n\nМагический маячок выводит героев на дом в трущобах. Анна носится по комнатам, быстро собирая немногие оставшиеся вещи и подарки своей возлюбленной. Раздаётся стук в дверь. Быстро пряча всё под тряпками, Анна спрашивает: \"Кто там?\". Дрипли непринужденно отвечает: \"Это мы! Мы можем помочь тебе!\". Вампирша уже, наверное, от бессилия, впускает преследователей в дом. Дрипли, используя свои познания о вампирах из легенд, настаивает на том, что Анна представляет опасность для людей, ведь не сможет сдерживать жажду крови (в качестве весомого аргумента выступает кровь Маркуса, которую он саморучно пускает из руки), а так же уверяет ее в том, что есть способ излечиться от вампиризма (снова умереть и воскреснуть). В качестве доброго жеста Маркус отдает Анне ту часть крови, что успела вылиться из раны; все убеждают девушку в том, что смогут доставать ей пропитание без жертв. Кажется, парням удалось договориться, ведь Анна делится информацией об Алисе Золтан, своей спасительнице и возлюбленной, а так же аристократке с большим фамильным поместьем в городе (хотя дом Золтан базируется на о. Улькуан-Ибаса).\n\nПока пачка заводит себе домашнего вампира, Янка следует за Саймоном вплоть до его дома. Парниша живёт в обычном домишке и, причём, является сыном знакомого Янке вояки. Чародейка этого не слышит, но Саймон говорит отцу *Я выполнил задание*", "new_npcs_raw": "Колин Грант - дядя Маркуса, жрец домена знаний\n\nДжуров Йово Иванишевич - тип из Гадкого Койота, который может подкинуть темную работу и провести на анонимный аукцион\n\nАлиса Золтан - вампирша из богатого известного дома, базирующегося на острове Улькуан-Ибаса\n\nРичард Лео Саймон - отец Саймона (мимолетно)", "materials": "Дрипли вспоминал легенды, в которых говорилось о каком-то из воскрешений, и вместе с Альдом они вспомнили более-менее похожую по сюжету сказку:\n\n\"Аврора, Астрей, Коварная Колдунья, Слеза Солнца.\n\nДавным-давно, в самом сердце срединного королевства жила принцесса Аврора, чья красота затмевала рассвет. Мудрый, но опасливый король, укрыл ее в высокой башне, и однажды мимо неё брела одноглазая ведьма, вся в лохмотьях и зависти. Дурным взглядом заметила она Аврору и прокляла ее на вечный сон, дабы похитить ее неувядающую молодость.\n\nКороль, в горе своем, взмолился небесам, и в ответ на его мольбы спустился с небес дивный цветок, золотисто-розовый, словно заря. Опали его лепестки, коснувшись глаз Авроры и замерла принцесса, старение оставило ее, но сон крепко держал в объятиях. \n\nОтчаяние поселилось в сердце короля. Тогда послал он глашатаев во все концы земли, с мольбой о помощи.\nЮный принц Астрей, чья любовь к Авроре была чиста и крепка, услышал эту мольбу. Загорелся он желанием спасти принцессу, отобрать у ведьмы украденную молодость и разбудить возлюбленную ото сна.\n\nОтправился Астрей на поиски колдуньи. Но ни меч, ни стрела не могли причинить ей вреда – металл покрывался ржавчиной, а стрелы обращались в пепел. Видя безграничную смелость принца, ведьма предложила сделку: она снимет проклятье, если Астрей добудет ей редчайшую Слезу Солнца, сверкающую ярче трёх сотен звёзд, способную заменить ей недостающий глаз.\n\nНа самой вершине высокой горы, таилась Солнца Слеза. Не жалея себя, принц Астрей отправился в путь. Долго он карабкался по отвесным скалам, пока не достиг вершины. Увидел он Слезу Солнца, и та ослепила его своим дивным блеском. Забыл принц на миг об Авроре, зачарованный красотой чарующего света. \n\nНо сила любви оказалась сильнее чар. С последним днем декады вернулся Астрей к своей возлюбленной. Отдал он Слезу Солнца ведьме. И в тот же миг, когда она сомкнула свой новый глаз, то отступила тьма от света, и Аврора открыла свои очи.\n\nЛиковал король, и радость наполнила сердца принца и принцессы. И жили они долго и счастливо, в мире и любви, а сказка об их подвиге передавалась из уст в уста, от поколения к поколению.\"", "perks": "💲Выполнение задания - 200 золотых (лагерь возле Храма удачи)\n\n💲Выполнение задания - 40 золотых (доставка кейса)", "achievements": "👻Иногда друзья значительно опаснее, чем враги - спасли нежить"}'::jsonb),
  (17, '{"session_number": 17, "loop_number": 2, "game_date": "2 петля, 15-17 странствий", "recap": "Расследование смерти няни Розы завело героев в маленькие посёлки возле Северного города Князевы Двери, последнего так далеко расположенного на север с железной дорогой и свеженьким портальным залом, на билеты в который Роза взяла кредит. Заодно узнали сколько стоит рвануть порталами до Ларса (~900 зм), где пляжный сезон продолжается.\n\nУ Розы абсолютно нормальная семья, а вот няню отравили, тем же ядом был отравлен Анарион. Проверили почту, решили посмотреть на отправителей. Пообщались с историком Вани. Узнали о загадочных смертях в первые дни петли: жрец Аланик умер в собственном храме (имущество забрала церковь), алхимика Лукава задрали кабаны возле дома. \n\nОтказались работать на артель старателей и учиться у них, и самостоятельно пошли в местные подземелья. (где на 3 уровне расположен городок старателей), искать руду. Рион и Энтони решили построить свой собственный туннель вниз, но ребята нашли спуск раньше. Где успешно столкнулись с мальками саламандрами за кадром. Там они почувствовали разницу в скорости восстановления у более бедного источника маны. Обратный путь предполагается проделать поездом за 8 часов, в плацкарте.", "perks": "🔮Зелье полиморфа в Горгону", "achievements": "🖤 7 игр без получения урона (инста смерть за кадром не считали) - Каэл"}'::jsonb),
  (18, '{"session_number": 18, "loop_number": 2, "game_date": "2 петля, 15-18 странствий", "recap": "После уроков в 15 день Янка хочет познакомиться и проверить Анну (порождение), берёт с собой Дрипли для защиты и Маркуса для прикормки. Дойдя до её дома в трущобах, Янка проходит внутрь и обнаруживает пустое помез=щение, собиранные вещи, оставленные украшения, никакаих записок и писем, только две медные монетки на полу. Маркус их подбирает, предполагает, что это как в морге на трупы делают, и Янка с интересом спрашивает *А если положить такие монеты на глаза, человек умрёт!?*. В тот же день Маркус участвует на боях с противником с 3 реакциями, выигрывает 100 зм (Анарион за победу забирает еще 75) \n\nВ понедельник 18 числа из путешествия в князевы двери на уроки возвращаются Анарион, Рион и Каэл. На ритуале связывания с фамильяром все получают\\перепривязывают своих животных:  Анарион - плешивого кота по кличке Депресняк, Каэл сову, Маркус пса Красавчика, Янка ворона, а Рион второго фамильяра ворона, попимо его змеи. (Тут начинаются шутки по типу, почему выбрал такого, это из-за того, что Он увеличивается в размерах, любишь тискать ужика, а у змеи один глаз, она умеет чем-то плеваться?!). Дрипли замечает на занятиях Альда, понимает, что тот не разговаривает, и протягивает ему зелье Снятия проклятья, думая, что Альд сам не может с себя снять, потому что не может говорить. Альд его успокаивает и с печальным видом уходит восвояси. В клубной комнате ребята размышляют, что делать дальше: идти в Храм Удачи или спускаться под Храм 8 путей не хотят, Дрипли говорит *Вас просто убьют, а меня выпьют*, возвращаться в Князевы Двери тоже не вариант, так что в конце концов все решают проведать официальный вход подземелья Сиории ради драчки. Тут присутствие Каэла как всегда на руку. \n\nОбычные тоннели тёмного камня, 30 минут пути по безопасной зоне первых 3-ёх уровней проходят спокойно, и группа выходит к развилке из трёх путей. Янка педалирует *Раз шли прямо, идём снова прямо*, но Каэл предлагает *Подумать и действовать по принципу лабиринта - выбрать одну сторону и следовать всегда ей*, тогда все идут направо. Рион зачаровывает на Свет новые обмотки на руках Маркуса, ребята спокойно идут по тоннелю шириной 20 футов, который где-то вдалеке начинает расширяться, как вдруг... \n\nРезкое давление психического воздействия обрушивается на разум приключенцев, выдерживают только Дрипли, Капля и Рион, остальные ошеломлены и пускают слюни на пол. Дрипли берет Янку и рвётся с ней вперёд, выпивая зелье смелости и вливая ей тоже. Рион ищет источник воздействия и замечает впереди зону тьмы, подходит к ней вплотную, просовывает голову и использует Волну грома. По пещере разносится громкий рокот, а из темноты слышится рык и шевеление. Кайл просыпается, Дрипли  бегает и вливает зельы смелости всем остальным, Маркус и Янка тоже спустя 6 секунд очухиваются. Анарион продолжает чилить.\n\nВдруг темнота спадает, и друзья видят 5 троллей, часть из них тоже ошеломлена, другие уже встали. Они замечают друг друга и начинается драка.Дрипли сразу кидает паутину в узкой части тоннеля, чтобы замедлить троллей, но Янка от неожиданных врагов выпускает Молнию, поджигая паутину. Рион кидает дребезги в троллей, Каэл ему вторит, Маркус снова становится большим, а Анарион только-только просыпается. Посреди боя все слышат невнятный мужской голос *Вставай-вставай жалкое отродье*. Тролли идут в атаку в узком тоннеле, бьют Маркуса, два тролля окружают Дрипли и за 2 удара размазывают его по стенке. Анарион встаёт, кидает несколько заклинаний, но промахивается. Рион пробирается между троллями, касается слизи, и Дрипли приходит в себя. Начинается заварушка в узком для троллей и Маркуса тоннеле, взмахи дубин, всполохи заклинаний, вспышки света в темноте, форменный хаос. Приключенцы замечают, что несмотря на огненные заклинания, у троллей продолжают затягиваться раны, и защита у них выше, они с щитами и дубинами.\n\nМаркус успевает на ходу отхлебнуть пива, отходит назад и защищает большим телом магов, как вдруг в эту группу влетает Огненный шар, от которого Маркус падает. Анарион лишается депресняка, а Рион - своей змейки. Дрипли с Каплей лечат всех зельями, Каэл издалека замедляет 4-ёх троллей, Янка кидает хроматический шар и взрывается всплеском дикой магии (2 на кубе). Стресс окончательно вырвал из-под контроля необузданные силы чародейки. Рион где-то позади троллей видит фигуру мужчины, создаёт Вихрь искривления и переносит Погонщика в середину боя. Маркус, который на мгновение потерял сознание, только видит его, ударяет, но тот мгновенно телепортируется назад. Каэл снова кидает дребезги, но на этот раз в потолок. \n\nДрипли кричит *Рион, солнышко, давай, мой сыночек, давай! Чуть-чуть осталось*, и конус огня, выходящий из маленькой Капли, накрывает всех троллей, которые уже начинают теснить ребят, 5 на 6. Когда все окончательно соглашаются с тем, что нужно бежать, в спины героям снова летит Огненный шар. Маркус, взявший Дрипли, не оборачивается на взрыв, Янка в огне теряет сознание, превращается в горшок с цветком, но он в ту же секунду трескается, тело чародейки возвращается обратно - короче говоря, ее конкретно штырит. Дрипли подбегает к ней и вливает зелье лечения. Каэл сохраняет сознание, кидает в троллей фирменные Дребезги, двое из них уже лежат, но остальные продолжают наступать. Янка, шатаясь, поднимается обратно на ноги, напоследок кидает в потолок Звуковой шарик, и тоннель обрушивается, преграждая путь троллям. Маркус подхватывает Дрипли и Янку в руки, бежит к выходу. Каэл поднимает Риона и убегает, Рион обращается к сырой мане и использует лечение ран на Анариона, получая за это мини-безумие *прятать свои руки ото всех*. Рион кричит *Отсупаем*, бежит с поднятым товаризем, а тролли остаются где-то в пыли (живые, но не преследуют)\n\nПока Маркус с огромной скоростью бежит по тоннелю, Янка продолжает взрываться волнами дикой магии, хрупкое тело чародейки извергает чистую магию, это выглядит пугающе. Сначала всё её тело загорается светом, ослепительно ярко заливая всех вокруг. Маркус из-за этого просто оставляет ее посреди тоннеля, Дрипли это не устраивает, и он возвращается обратно. Хорошо, что Дрипли не успел дойти до того, как вокруг Янки сконцентрировалась некротическая энергия, вытягивающая силы из окружающих по принципу вампиризма. И только Дрипли подбегает, как  кричащая Янка просто исчезает. Время как будто замедляется, Янка оказывается в мистическом пространстве, окутанном неизвестной тревожной энергией, как из пустоты вырывается ворох глаз, один за одним, заполняя всё пространство вокруг чародейки. Это длилось лишь мгновение, но встреча с потусторонней силой вызвала в нестабильном сознании Янки краткосрочное безумие - даже после возвращения с астрального плана перед ее глазами только темнота. Из нее вырывает магическое Смятение на всех вокруг, но подбежавшие ребята успешно ему противостоят. Маркус обратно подхватывает Янку и Дрипли, параллельно Дрипли пытается ее успокоить, но в ответ на помощь в него прилетает только 8 Магических стрел (хорошо, что у Дрипли остался Щит).\n\nСекунды затишья, всплеск дикой магии прекратился. Янка только как мантру повторяет *Где мы? Что происходит?*. Маркус, несущий ее, был бы и рад ответить на эти вопросы, но он забыл все, что было после рассеивания тьмы в подземелье. Похоже, череда резких падений в каменных залах подземелья плохо сказывается на памяти.", "new_npcs_raw": "🥊Тролль https://5e14.dnd.su/bestiary/304-troll/", "perks": "🔮Дорогие украшения из трущом вампирши - Янка (240 зм)"}'::jsonb),
  (19, '{"session_number": 19, "loop_number": 2, "played_at": "2025-10-24", "time_range": "20:00 — 23:30", "game_date": "2 петля, 19 странствий", "recap": "Уинифред Прескотт и Клим Бэлан с 1 дня (2 петли) ощущают, что что-то не так. Они помнят, как умерли во время вторжения в прошлый раз, но проснулись невредимыми. Они помнят, что пары были точно такие же, что зелёный парень развешивал листовки с рисунками северных волков и приглашал в свой клуб, но в этот раз картинки почему-то отличаются. Они помнят, что посреди месяца трагически погибает 9 студентов академии, и об этом трещит вся Сиория. Но вот наступает 18 день и ничего до сих пор не происходит ...\n\nПосле уроков герои встречаются в Петухе. Клим осушает очередной стакан: странные события слишком сильно давят на его голову, поэтому он предпочитает забытие. Тут в таверну врывается паладинша, подходит к самой подозрительной кучке студентов, бьет кулаком по столу и громко предъявляет, какого хрена половина из них жива и что вообще происходит. Путешественники просят девушку представиться, она извиняется и называет своё имя. Энтони позволяет себе ехидно заявить: \"Да, дом Прескотт славится своей бестактностью\". В ответ Уинифред резко меняется в лице, вытаскивает меч из ножен и приставляет его к горлу изобретателя: \"Ещё раз ты что-то скажешь про мою семью, я снесу тебе бошку с плеч\". Пока конфликт решается мирно. Ребята признаются, что знают о просходящем не больше, чем она. Всё это время Клим пытается не палиться, что подслушивает разговор с соседнего столика, но у него не получается. Паладинша хватает парня за шкварник и садит за столик *пробужденных* (новое название от Локи), а Клим и не сопротивляется \n\nГерои обсуждают нахождение в петле, делятся деталями своих смертей, рассказывают о других путешественниках. Уини заключает: \"То, что здесь происходит - это чистое зло. Куда бы вы не пошли, я пойду с вами\". Локи считает, что основная ценность, которую они могут извлечь из ближайших петель - это знания, а ценные знания потенциально находятся в подземельях (например, почему за 12 дней до вторжения вооружённые тролли уже сидят там с волшебником с другого континента). Клим в тему вспоминает про своё задание, которое брал ещё в прошлый раз. Для него требуется команда с боевой подготовкой, чтобы сопроводить груз в подземный склад, ведь в конце пути из ожидает засада. Деталей он не помнит, но у разбойников точно были револьверы. \n\nЗадание успешно берут у торговца (2 зм награда), Роза забирает и подписывает все накладные. Ребята сопровождают повозку с 10 ящиками с неизвестным содержимым. Пункт назначения - 2 уровень подземелья. Доходя до моста, на котором в прошлый раз была засада, группа останавливается поодаль, для наблюдения за повозкой Роза оставляет своего ворона. Локи отправляет на разведку невидимого фамильяра в форме крыски. Йотун обнаруживает на утёсах 4 громко перешептывающихся разбойников (2 справа и 2 слева). Чтобы незаметно подобраться к мосту, Локи кастует иллюзию большого густого тумана, покрывающего ребят. Кажется, план не совсем удался, ведь с помощью чувств Йотуна Локи слышит голос разбойника: \"Эй, там что-то странное, давай кинем туда гранату\". Локи успевает удачно среагировать и пронзить гранату зелёным лучом до того, как она прилетит на мост. С утёса на другом краю моста (где стоят герои) летит ещё одна граната и поражает всю группу. Локи теряет концентрацию, туман рассеивается. Начинается бой. \n\nСо всех сторон летят выстрелы, идущую впереди Уинифред сильно ранят меж пластинками лат, Энтони тоже выходит вперёд, что-то нажимает на своём устройстве (бип-бип-бип, а потом бьёт по нему кулаком). Вокруг изобретателя создаются 3 аналогичных отражения. Волшебники, пользуясь тактикой самих разбойников, прячутся и заготавливают заклинания на случай появления бандитской рожи. Роза и Клим стреляют в показавшихся разбойников, но они отвечают, и Клим падает. Роза поднимает Клима, тот быстро сообщает, что вспомнил о растяжке на той стороне моста, рывком взбирается на утёс, выстреливает и ложится.\n\nПоследующие атаки летят в Этнони, которого несколько раз Уини защищает своим щитом, и в лежащего Клима (он снова падает без сознания, жёстко сталкиваясь с поверхностью камня и ломая нос). Роза  замечает лишь пятку горечародея наверху, но этого хватает, чтобы полечить его. Фред на пару с колдуньей кричат Климу, чтобы тот слезал. Клим полностью игнорирует просьбу, продолжая лёжа выцеливать врагов. Тем временем Уини и Этнони наконец пересекают мост. Энтони успешно мучает одного из разбойников раскалённым металлом; паладинша толкает изобретателя назад и перерезает ловушку. Граната срабатывает, но никого не задевает. Уини пробирается дальше, бросает щит и готовится атаковать разбойников в рукопашную. \n\nЙотун ныряет в штаны одного разбойника, отвлекая того от боя, а Локи создаёт иллюзию большого тарантула, в которого сразу стреляют и обнаруживают, что это мираж. Локи продолжает изображать неподдельный страх от появившегося паука. Фрэд взбирается на другой утёс и кастует ужас на 2 разбойников, они кидают пистолеты и пускаются наутёк. Крыса выбегает из штанов разбойника, тот кричит своему товарищу в раскалённой кирасе: \"Вставай, что разлегся! .. Эй, ты живой?\". На другом утёсе паладинский меч наконец находит жертву. Вдребезги, Огненный шар, Погребальный звон и бласты Розы с Климом (которые теперь лежат на утёсе вместе) добивают наконец ещё 2 разбойников. Выжившие бандиты трусят и пытаются сбежать через реку. Один не добегает, Уини сначала карает его божественной силой, а потом отрубает голову; другому Энтони делает шибари. Водичка всё равно не спасает уплывающих, Роза и дальнобойная палка Клима выцеливают их, превращая в трупы. \n\nБой оканчивается с одним пленным. Энтони допрашивает с пристрастием, пытаясь узнать сразу всё про нападение, команду и заказчика. Серёга (так зовут разбойника) отвечает, что не может ничего рассказать, иначе умрёт (Обет). Роза угрожает пленнику только что отрубленным пальцем у его мёртвого товарища, Уини приставляет меч. Энтони спрашивает: \"Вас много?\". Серёга в страхе отвечает \"Нет\" и тут же умирает. Лут: 3 револьвера на 300 зм и по 20 зм в карманах у разбойников (всего 80 зм) \n\nВсе, что остаётся ребятам, чтобы утолить любопытство, это вскрыть хотя бы один из ящиков груза. Внутри каждого из 10 ящиков оказываются куколки шелкопряда по 10 зм ящик. Фрэд вспоминает, что они используются для заклинания Полиморф. Починкой груз возвращают к нетронутому виду, ребята стучатся в массивную деревянную дверь склада с защитными чарами. Им открывает стража, впускает внутрь, Роза протягивает накладную, проверка, всё в порядке. Один из стражников замечает невидимого паука Локи и приказывает его убрать. 20 верзил в помещении выглядят угрожающе, и приключенцы не вступают в конфликт, а просто уходят.", "new_npcs_raw": "🥊Разбойники", "perks": "💲Лут с разбойников 80 зм\n\n💲Выполнение задания - 2 золотых (доставка груза)\n\n🔮3 магических револьвера на 300 зм"}'::jsonb),
  (20, '{"session_number": 20, "loop_number": 2, "played_at": "2025-11-20", "time_range": "20:30 — 00:30", "game_date": "2 петля, 20 странствий", "recap": "На следующий день после доставки ценного груза в подземелье Локи, Уинифред и Роза рассказывают об увиденном в клубе. Уини знакомится с Янкой и Дрипли. В дверь раздаётся стук. Роза открывает и видит перед собой другую студентку, держащую в руке закрытый конверт. \"Я по приглашению\" - говорит незнакомка, проходит чуть внутрь и окидывает взглядом разношерстную компанию, в которой выцепляет два лица: свою одноклассницу-паладиншу и Янку Мавики, метательницу молний (Бенисек растрепал). В конверте оказывается письмо Альда с советами, такое же, которое было отправлено Британии в начале петли, а незнакомка представляется как Карина Форамен, жрица бури, сменщица Альда в морге и очень большая поклонница молний.\n\nПриключенцы делятся информацией с разных вылазок друг с другом, чтобы продумать план дальнейшего действия. Янка рассказывает, что отец Саймона, Ричард, занимается подготовкой артиллерии для фейерверка, орудия находятся за городом. Роза делится деталями поездки в Князевы двери. По ходу рассказа Локи протягивает мысленные ниточки между няней Розы и её знакомыми, которые тоже погибли в начале петли или до неё. Возможно, всё это дело как-то связано с вторжением некромантов в Сиорию. \n\nСловом, за обсуждением старых походов ребята решают, куда отправиться дальше (а Карина разочарованно замечает, что хотела бы присоединиться к компании раньше). В Академии нет новых заданий, но зато они узнают, что Храм Удачи был зачищен от умертвий, правда в глубине были найдены следы монстров поопаснее - лиловых червей, гигантских ядовитых тварей (даже подготовленная группа решила не встречаться с ними; но добыча это ценная). Посему ребята решают, что лучше вернуться в подземелье к троллям достать погонщика. \n\nДо 22 дня компания готовится к вылазке, а именно отдаёт все свои деньги Дрипли на варку зелий. В пятницу на факультативе Янка рассказывает Ильзе, что уже несколько дней не занимается магией, потому что боится, что та выйдет из-под контроля. Девочке интересна природа её необузданной силы, и преподавательца полагает, что дикий дар связан с особенностями её рода или наследством. Чтобы не подвергать других опасности, Ильза советует Янке обратиться в лечебницу для исследования (сообщит об этом матери). Женщина уверяет, что Янке дадут возможность поучаствовать в летнем фестивале, но уроки ей лучше не посещать\n\nПосле занятия чародейку встречают Карина и Дрипли. Янка отрешена и потеряна от мысли о том, что её магия напугала даже опытную преподавательницу, но она определенно не намерена дальше сидеть сложа руки. Если её магия снова разбушуется, то все равно им умирать под огнём вторжения, так что ну эти предосторожности. Янка спокойно помещает заклинание молнии в кольцо хранения Карины, при этом почему-то все трое становятся невидимыми на минуту (упс). Карина даёт Янке от руки составленную натальную карту с поддерживающим гаданием. \n\nПлан на вылазку - закинуться зельями для защиты от урона психикой и обмазаться маслом скольжения для лавирования между паутиной, а там дело в шляпе. Локи становится *невидимым* (прячется в карманное пространство кольца, переносимого Йотуном), чтобы исполнить свой маленький план. Так как прошлый маршрут остался заваленным, группа двигается прямо на развилке. Этот путь приводит их к углублению 120 футов длиной и 30 футов глубиной (дальше тоннель продолжается). По периметру грота расположились лозы-убийцы и грибы с ядовитыми спорами - источники полезных ингредиентов для алхимии. Уини выпивает экспериментальное зелье полета и спускается к одной из лоз, сначала проверяя враждебность растения броском подсвеченного камня, а потом замахивается мечом, напитанным священной энергией. Лозы вздымаются и планируют дать отпор. Зелёную тварь приговаривают быстро, Локи даже не считает нужным участвовать (рассматривает свой гардероб в карманном пространстве). Но когда ребята собираются проследовать дальше, с поверхности камней поднимаются другие обитатели подземелья - альфа грики.\n\nСтая больших ползучих тварей окружает Уини и подошедшего Дрипли, магички атакуют с края тоннеля (Карина, используя божественное проведение, выпускает из кольца очень мощную молнию). Один из побитых гриков пытается улизнуть, уползая в воды подземного озера, но группа приключенцев оказалась для него меньшим злом. Из озера поднимается фигура огромного монстра, похожего на дракона-сороконожку. Он без труда заглатывает альфа грика и устремляется к продолжению обеда. 20-футовый Бехир подползает прямо к Уини, вляпываясь в паутину, и доедает очередного бедного побитого грика. Половина группы уже собирается бежать. Янка запускает в большую тварь кислотный шарик, который отлетает по двум рядом стоящим грикам. Роза кастует голод Хадара, чтобы скрыть дракона-сороконожку за тьмой. Дрипли кричит, что с монстрами ещё можно разобраться, но поздно - пока чудовище не выпуталось, все покидают пещеру. Остаётся только невидимый Йотун и его хозяин в кольце, которые перелетели на ту сторону тоннеля, минуя битву.", "new_npcs_raw": "🥊Лоза-убийца\nhttps://dnd.su/bestiary/2641-assassin-vine/\n\n🥊Альфа грик\nhttps://dnd.su/bestiary/189-grick-alpha/\n\n🥊Бехир\nhttps://dnd.su/bestiary/42-behir/", "materials": "💫 Гороскоп для Янки от Карины: \nЛевиафан 22 странствий - Ваша творческая энергия поможет многим даже без прямого взаимодействия. Сегодня вы вдохновляете и мотивируете одним своим появлением. Доклад о ваших успехах многими будет воспринят как руководство к действию. В финансовом плане все не так радужно, но осторожность в тратах позволит сохранить и приумножить активы.", "achievements": "💅 Girl Power - в группе больше девочек, чем мальчиков"}'::jsonb),
  (21, '{"session_number": 21, "loop_number": 2, "played_at": "2025-11-25", "time_range": "20:00 — 00:00", "game_date": "2 петля, 22-23 странствий", "recap": "Группа залуперов выбралась из тёмного и влажного подземелья, сбежав от Бехира. Спасибо паутине и инстинкту самосохранения. Миновав опасность, ребята потеряли Локи. Невидимый плут остался где-то там, в темноте, и Дрипли призвал сопартийцев вернуться за другом, но взять с собой подмогу. Быстро прибыли Маркус и Рион, (гвардия сильных и смелых, не видевших будущее). Маркус просто решил навалять подземцам, а Рион услышал от Розы, что злобный подземный полудракон стоит оч много деняк, в районе 2 тысяч золотых монет, если считать в ингредиентах. Так или иначе, ребята вернулись ко входу в подземелье. Войдя внутрь, Маркус заметил невидимого Йотуна, парящего под сводом туннеля. Он схватил летуна, и Локи выбрался наружу из кольца, сказав что очень признателен за его поиски — с ним всё в порядке. Чуть обсудив исчезновение Локи, группа в течение получаса вернулась в пещеру с озером.\n\nИспарения, сок растений и кусочки плоти живых лоз-убийц аккуратно собраны в склянки слизистого парня. Пока Локи разглядывал поверхность воды, Рион без предупреждения умыкнул под воду, быстро спускаясь вниз. Сообщающиеся сосуды подводного туннеля искривились буквой U, после чего боевой маг вынырнул на той стороне. На дне его не смутили кости и застывшие во времени и коррозии обрубки мечей и копий. Рион нашёл другую пещеру, ещё краше и больше прежней, усеянную острыми как бритва сталактитами. Бехир был бесшумен для своих размеров, и ловко проскользнул мимо каменных глыб, атакуя Риона. Пара ударов хвостом и зубами - и изобретатель скрылся в жуткой пасти. Змейка фамильяр забился в истерике на той стороне, где остались другие приключенцы. Маркус не теряя ни секунды рванулся плыть за товарищем, следом за ним двинулись Дрипли и Локи. Дрипли крикнул Янке и Розе, что сейчас вытащит Риона магией, но это было крайне наивно для юного слизне-парня. Завязался бой.\n\nСпустя мгновения ребята оказались в другой пещере. Фрактал Риона проник внутрь монстра, окутав волшебника своим телом, чтобы защитить от желудочного сока. В Бехира весьма успешно полетел шматок паутины, вокруг появились копии Локи из кольца заклинаний Йотуна. Казалось, что сейчас град заклятий обрушится на монстра, но быстрый бой завершился, только начавшись. Бехир собрал молнии на языке, и буквально вызжег Маркуса, отправив в того мощнейший электрический заряд. Обугленное тело осело рядом с застывшим в ужасе Дрипли. Ребята поняли, что дело дрянь, и Локи скрылся под водой, уплывая обратно. Йотун и копии Локи отвлекли тварь, Дрипли скастовал новую паутину и группа ретировалась. Вернувшись в основную пещеру, Локи создал иллюзию огромного Бехира с розовой кожей, а Янка бахнула хроматическим шаром по потолку, чтобы Бехиру досталось по башке, пока ребята убегали вглубь по туннелю. Без Маркуса и Риона, разумеется. Вернувшись в город, группа рассказала о случившемся Ильзе. Посыпались новые запреты на посещение подземок, а у опытных приключенцев появились новые заказы на зачистку территорий. \n\nВ коридорах Академии Роза, Дрипли, Янка и Локи встретили нового залупера — Бальтазара Аннигилятора. Высокий, под 2 метра ростом, бард-лидер музыкальной группы \"Кровавый Снегопад из выколотых глаз распятых грешников\". Он признался, что они отмечены Апокалипсисом. Верное дело, видимо на 30-й день он устроит концерт под шум огненных файерболов, летящих с небес.\n\nТут же подвернулся Зак, в спешке появившийся перед группой. Он призвал срочно готовится к нападению и тренировать боевые навыки. Из ниоткуда родился конфликт между Заком и Бальтазаром — студенты сошлись в короткой магической дуэли. Спустя какое-то время по-дружески Дрипли и Бальтазар решили выяснить на тренировочном поле, кто сильнее — слизь взяла верх.\n\nПод конец партии Локи сдружился с Каэлом, своим соседом по дома Имайи, и они позвали Дрипли на чай, похимичить зелья в подвале дома.", "new_npcs_raw": "Каэл Тверинов", "perks": "🧪Ингридиенты - 240 золотых (Лозы-убийцы)"}'::jsonb),
  (22, '{"session_number": 22, "loop_number": 2, "played_at": "2025-11-28", "time_range": "20:00 — 00:30", "game_date": "2 петля, 23 странствий", "recap": "Жаждующие приключений и ответов, герои возвращаются к Храму Удачи, который ещё полон тайн. Возможно, они хотели увидеть там совсем другое... По пути к храму Энтони замечает чарующий синий огонек, тот как будто говорит с ним, призывает: \"Я расскажу тебе всё, что ты хочешь узнать. Даже о том, кто подставил твою семью\". Не в силах противостоять навождению, бронник непременно идёт к свету, игнорируя хватку Розы, доводы Карины, Зака. Друзья не бросают товарища, и все продвигаются примерно на 100 футов вглубь леса. \n\nНа открывшейся поляне отчётливо виден источник света: большая неземная тварь, похожая на рыбу-удильщика с фонариком из высокого отростка, сидит на камне и подманивает к себе путников. Энтони успевает подойти почти вплотную к монстру, но Карина встает между ним и тварью, пытаясь снять проклятье (ничего не меняется). Жрица кричит: \"Он не один. Засада слева, справа!\". Зак стремится защитить девушку, потеснив ее из пространства перед звездным удильщиком. Латы самоотноверженного чародея покрываются тонким слоем изморози, и он пытается проткнуть рыбу рапирой, но лишь водит остриём перед тушей (1 на попадание).\n\nКаэл пытается выцелить неизвестных существ за деревьями. Роза проклинает главное чудище и поражает белым лучом. Дрюс управляет растениями, заставляя их опутать удильщика, а так же призывает духа дикого огня, чтобы телепортировать Энтони подальше. Когда монстр пытается ударить впереди стоящего Зака, после первого же укуса его отталкивает силовым полем дальше в заросли за камнем. Боевой чародей провоцирует на себя медведей, вышедших из-за леса. Неизвестный лесной монстр выплёвывает клейкую субстанцию на часть ребят, с другой стороны паук начинает хватать героев по одному и заматывать в кокон из паутины. Из-за ещё одного дерева вылетает крылья тварь, пытающаяся сцапать маленькую огненную лису, но тело горящего зверька проходит через когти. В следующем ходу летун уже хватает Зака, поднимает над земльей и жёстко бросает вниз. Лязг доспехов, кашель, кряхтение, но побитый Зак всё ещё в сознании. \n\nУдильщик, притаившийся в зарослях за камнем, продолжает подманивать к себе жертв. Энтони снова достигает \"кукловода\", но на этот раз вовремя приходит в сознание. Для пущего эффекта изобретатель увеличивает себя, а затем хватает отросток с синим фанариком, пропуская в монстра магический ток. Совместными усилиями - замедлением, вдребезгами, молнией, огненным шаром, мистическими снарядами и облаком кинжалов - удаётся  повалить две медвежьи туши (по 160 зм) и странного очаровывателя (тоже 160 зм). После смерти удильщика оставшиеся в живых монстры разбегаются.\n\nПеред тем, как заходить в злополучный храм, герои отдыхают в ранее возведённом лагере. Пока Зак перематывает раны, Карина предлагает ему расслабиться и позволить снять с себя проклятье (теоретически это вызовет новую волну воспоминаний, но нет). Зак предупреждает, что он против покушений на свои мысли, на что Роза решает подшутить и передать парню телепатическое сообщение. Похоже, ему нужно научиться противостоять этому. \n\nПриключенцы пересекают мост, входят в храм, проходят мимо покинутых гробов. Энтони проверяет несколько лежачих трупов на признаки жизни посредством пинка, но тела никак не реагируют. В темноте перед героями открывается вид на будто бы изъеденные стены храма, скорее даже грунт, в котором они были построены. Дыры имеют гигантские размеры и покрыты лиловой слизью. Инстинкт самосохранения подсказывает ребятам, что лучше дальше не соваться, чтобы дожить до вторжения.\n\nПо пути обратно в город команда несколько разделяется, исследуя окресности. Кто-то пытается найти лагеря, служащие плацдармом для вторжения, но ничего подобного в округе Сиории не оказывается, как будто войска пришли сразу, чуть ли не появились прямо на фестивале. Одна морская метафора на тему будит в Заке отдалённое воспоминание, где он, будучи в открытом море, оказался застигнут врасплох появившимся из пустоты кораблём с неживыми матросами. Карина рассказывает, что среди моряков ходят легенды о пиратском корабле полном нежити, от которого невозможно спастись - либо ты отдаешь всё ценное, что есть на борту, либо вся команда обращается в слуг-мертвецов. \n\nЗак, Роза и Карина забираются на холм, с которого открывается хороший вид на пушку для салюта. Территория ограждена и скорее всего защищена оберегами, сооружений для жизни на нём нет, приходит сменный караул. Расстояние от соседнего холма до объекта - 2600 футов. Наблюдая за войсками, \"пробужденные\" пытаются построить план действий на 30 день. Зак планирует расправляться с захватчиками, а Роза категорически против находиться в гуще событий, да и в целом не очень верит в повторы, поэтому могла бы понаблюдать за событиями из-за пределов Сиории. На будущие петли, если они будут, ей пришла идея навести шумиху у властей с помощью распространения слухов, подкупа газетчиков, возможно даже собственного подстраивания событий. Когда трое возвращаются в Сиорию, они пытаются договориться с Ильзой об экскурсии на завод фейерверков, посмотреть на предварительные залпы или что-нибудь подобное. Роза упрашивает, пользуясь положением бедной девочки, которая потеряла няню. Ильза обещает, что спросит, но скорее всего будет возможность только после фестиваля.", "new_npcs_raw": "🥊Звездный удильщик\nhttps://dnd.su/bestiary/15717-star-angler/", "materials": "Карта - Положение пушки для салюта\n\nКарина про начало второй петли:\n\nленты дорог сквозь поле\nпрямо ведут в овраг\nжизнь ничего не стоит\nпамять — наш лучший враг\nбыстро сжирает пламя\nвысохшую траву\nжизнь постепенно тает\nвремя — наш худший друг", "perks": "🧪Ингридиенты - 320 золотых (медведи)\n\n🧪Ингридиенты - 160 золотых (звездный удильщик)"}'::jsonb),
  (23, '{"session_number": 23, "loop_number": 2, "game_date": "2 петля, 30 странствий", "recap": "Альд заканчивает обет молчания, обращаясь к своему куратору *Мне нужна помощь, познакомьте с верховной жрицей*. Батак, защищающий её, не хочет этого без весомой причины, Альд указывает на великий дар провидицы, и под Областью истины говорит откуда знает (игра 10). Высшее восстановление (снять проклятье, вернуть память) на Альда не работает, он настаивает на встрече с верховной, и Батак с соглашается.\n\nНебольшой дом, который снимает игривая, жизнерадостная и энергичная Офелия Эрос. Собираясь на бал летнего фестиваля в великолепных розовых доспехах, реагирует на стук в дверь. На пороге стоит мрачного вида Бальтазар Аннигилятор, в непривычно белом одеянии. Он сухой форме утверждения приглашает Офелию на бал, жрица соглашается, но из-за радикальной честности барда понимает, что была 7-ая в очереди. Это её задевает, но энергия жизни и азарт (а может что-то ещё) толкают её навстречу грядущему.\n\nКарина получает Послание от Альда, и стремится остановить Саймона и получить больше информации. Поэтому она зовёт Зака, чтобы засветиться на балу, а самим искать Саймона. Зак уговаривает Карину потанцевать, но бал ещё не начался, поэтому они идут к убежищу, проверяя эвакуационные выходы. И возле входа в само убежище встречают Анариона, увлечённо читающего учебники.\n\nПока товарищи думают, откуда лучше следить за нападающими, где занять оборону и как выяснить планы Саймона, Офелия и Бальтазар, появившись на балу не нашли ничего интересного, и логично пошли на место бойни - жрица увидеть убежище, а Бальтазар понаблюдать снаружи за отмеченными апокалипсисом.\n\nТак все пятеро замечают друг друга, жрицы узнают, что обе среди Прозревших, небольшой диалог о насущном, и группа решает спуститься в убежище, проверить всё ли в порядке, может Саймон внутри. В просторном зале под землёй, они находят единственную дверь, взламывают её и обнаруживают рубку управления, которая не реагирует на их сигналы. Зато сигнализация начинает пищать, но тут же замолкает, без вмешательства ребят.\nПочинив дверь они выходят наружу в ожидании часа Х.\n\nБальтазар играет нестройную мелодию, Офелия играет на свирели и вызывает свою Сову, к ней присоединяется Депрессняк Анариона, который сам сидит на крыше убежища, а в момент затишья Карина просит Зака научить её танцевать.. Час спокойствия..\n\nВ полночь раздаётся первый выстрел салюта, группа видит единственное место, откуда он стреляет (холм с пушками), а уже второй залп осыпается огненным градом. Ребята замечают, что снаряды попадают точечно в общежитие, ратушу, арсенал и другие конкретные места (не видно какие). Видно, как огни после взрыва разлетаются и из них выходят фигуры (элементами). \n\nКупол над академией гаснет, в небе собираются клубы туч, сильный ветер, яркие молнии и раскат грома, который оглушает ребят, но Бальтазар уже начал свою оду апокалипсиса, никого не слыша. Пошёл град, снег, ливень, как будто кто-то точно управляет погодой, направляя Грозу гнева на город. \nВдалеке, с юга, грохочет земля, рушатся здания. Из под земли тут и там вылазят стаи волков, в небе видятся железнокрылы, из-за домов выходят тролли.\n\nВ этот момент первые группы студентов выбегают на улицу, ребята отстреливаются из убежища, но когда среди студентов замечают Саймона, Карина использует Удержание личности и ребята уводят его под руки вниз.\nВыбрав угол, они его обступают, Офелия отбирает у Саймона жезлы, склянку с дымом и странную руну, которую не может прочесть. Пока Карина спрашивает у него *Кто тебя послал, какие ваши дальнейшие планы?*, Анарион читает его мысли *Вот чёрт, не дождётесь, дилетанты*, тогда ребята хотят связать ему руки.. И заклинание заканчивается..\n\nСаймон хочет поджечь сумку Офелии с колбой, но та создаёт Щит и отводит огонь, тогда Карина кастует Удержание, Бальтазар поддерживает Искусной остротой, но Саймон реагирует Контрспэллом, неудачно, Саймон в ловушке.\nПодходит староста и ругается, что мы обезумели и она всё расскажет Ильзе, на что Карина психует и кричит *Да делай что хочешь, тут бомба*, и забитое убежище взрывается паникой.\n\nВ этой шумихе Карина решает кончать предателя, Нанесение ран (87 хп), он в сознании, сверху Бальтазар добивает психическим взрывом. Анарион создаёт область Умиротворения вокруг, Бальтазар пытается всех успокоить, но тщетно. До ребят доберётся Зак, защищавший последних уцелевших, а следом за ним Кайрон, который видит тело Саймона в бинтах от Нетленных останков. Группа объясняет, что он предатель при нём было оружие и яд и т.д. Преподаватель объявляет всем, что на город напали, армия разбита, Сиория пала и они сейчас в западне, и нужно как-то выбираться..\n\nВ этот момент вокруг Офелии из руны появляется 9 фигур, они замечают что всё идёт не по плану, и разлетаются по убежищу, сея панику, взрывая под себя и вокруг Огненные шары. Начинается бой, Кайрон и ребята расправшяются с 4 врагами, Офелия и Карина всех успешно лечат под Маяком надежды и Аурой живучести, Анарион создаёт нечто потустороннее, а Бальтазар аккомпанирует, усилия товарищей, но..\n\nОдна из волшебниц принимает облик студентки, теряется в толпе, и из под земли вырываются лиловые черви, хватая и унося с собой Кайрона, Бальтазара и Карину. Анарион по обыкновению проходит спасы от смерти на земле. Кайрон тут же возвращается, но его хватают в клетку и область тьмы (не знаю заклинаний). Бальтазар борется в желудке  твари, но погибает от кислоты. Карина из последних сил создаёт Молнию внутри червя, тот её выплевывает, затем глотает опять, но Дребезги заставляют выплюнуть добычу снова, и в темноте тоннеля Карина всё-таки погибает.. \n\nОфелия, как жрица любящая жизнь, вырвалась вверх по лестнице, через щель в двери Туманным Шагом выскочила из силового поля, и решила бежать в направлении севера. Там её преследуют железнокрылы, она удачно защищает себя от острых перьев, притворяясь что погибла. Подождав немного, она продолжила путь на север..", "materials": "Карина про Зака:\n\nгубы отогрели\nямочку щеки\nи ладонь вспотела\nот чужой руки"}'::jsonb),
  (24, '{"session_number": 24, "loop_number": 2, "game_date": "2 петля, 25-30 странствий", "recap": "В понедельник на 25 день компания (без Янки) под предлогом группового проекта интересуется у Ильзы, кто отвечает за защитные чары Академии (которые очень кстати оказались выключены в день вторжения). Та направляет ребят к лучшей специалисте в области магических формул - Норе Буул, преподавательнице соответствующего предмета, а ещё кураторше Локи. Завидев своего ученика, Нора отвлекается от забот и тут же предлагает ему разработать схему кольца хранения заклинаний (с прототипом для исследования, конечно). Локи тактично переводит тему на проект, просит провести экскурсию в охранный кабинет, который расположен в одной из башен Академии, но Нора отказывает в доступе. Нужно поискать менее легальный способ попасть туда. \n\nКабинет защищён от посторонних стандартным магическим замком, настроенным на ману конкретных заклинателей. Наблюдение даёт понять, что охранников работает двое, каждый по 12 часов, смена происходит в 8 утра и в 8 вечера (пересменка длится примерно 15 минут). Охранники на вид обычные уставшие от жизнь мужчины (читайте: скуфы). Обсуждение плана проникновения включает вариант забить или охмурить одного из бедолаг, но самым гуманным способом видится просто применение небольшой иллюзии с внушением. Если Нора не хочет проводить экскурсию сама, то ученик сможет заменить её. Для подстраховки Локи так же обучает внушению Каэла. \n\nВо вторник 26 странствий в 16:00 студенты снова в сборе перед дверью в охранный кабинет. Локи выбирает своё бежевое платье и прихорашивается в иллюзорном образе преподавательницы. Дрюс флиртует с \"Норой\", а Локи ему подыгрывает. Охранник оказывается достаточно сговорчивым, пропускает группу студентов на экскурсию и охотно рассказывает про устройство комнаты. В контрольном (основном) зале находится сигнализация, работающая на объекты Академии, которая выводит изображение места по нажатию на кнопку. Пульт управления работает за счёт *живущего внутри духа*. Есть коды доступа. Так же в помещении две других двери: одна ведет в магическую котельную, где кристаллизованная мана перерабатывается в энергию, и другая - в инженерные системы (доступ есть только у сигнатуры Норы Буул). В целом всё спокойно, единственная жалоба - птицы иногда тащат руду. ЛжеНора предлагает охраннику, Павлу Ненадовичу, взять под своё крыло двух новых техников, которые прибудут вскоре; тот охотно соглашается за прибавку к зарплате. Дрюс тоже \"признается\", что всегда мечтал стать охранником, даже принимает облик Павла в доказательство. \n\nРебята решают, что вернутся к кабинету во время вторжения, чтобы понять причину отключения щитов, Локи оставляет заранее своего невидимого фамильяра. Да начнется бал!\n\nЯнка заходит в залу в красивом черно-белом платье с буфами и кружевами на воротнике, её руки облачены в чёрные перчатки, поверх которых сверкают магические браслеты (блокераторы магии, подарок от Ильзы для безопасности), а лицо скрывает простая, но изящная маска. Она приходит в паре с кавалером, облик которого известен лишь части присутствующих, а именно выпускникам Академии. Дрипли пару раз почему-то называют Саймоном Вирионом, но потом быстро понимают, что обознались.\n\nЛоки приходит с Уинифред, но быстро бросает свою спутницу, чтобы проследить за подозрительными гостями. Любопытство вызывает один известный человек, Ватима Тинк - глава гильдии магов, совершенно пропавший в туалете. Энтони удаётся пробраться в вип зону, притворившись новым официантом. Он мельком читает по губам разговоры, одни важного вида гости обсуждают некие чёрные залы в Суламноне, которые удалось продлить на 1 день. \n\nВ разгар вечера Янка вальяжно протягивает Локи бокал с розоватым шампанским, пузырьки которого при внимательном рассмотрении напомнили бы сердечки, и уходит обратно танцевать с Дрипли. Колдун медленно потягивает напиток, наблюдая за парочкой, и постепенно в его сердце что-то начинает трепетать. Прекрасное, знакомое окрыляющее чувство, как будто прямо сейчас он смотрит на истинную любовь, возможно, всей своей жизни. Ту самую любовь, что танцует рядом с рыжеволосой девочкой в маске. Пару минут он даже пребывает в замешательстве: как же подступиться, как рассказать о своих чувствах; нужно посмотреться в зеркало и оценить свой внешний вид, подумать, что же сказать.\n\nПодавляя любую нерешительность и желание предстать перед Дрипли в другом свете, воодушевлённый Локи прерывает танец одноклассников и приглашает парня присоединиться к своей компании. Пока Янка находится в шоке, Дрипли соглашается потанцевать с другом и поддержать беседу. Правда, постепенно беседа приобретает всё более странные оттенки, кажется, в некоторых фразах Дрипли распознаёт неприкрытый флирт, про который сам же Локи рассказывал. Когда колдун со всем присущим очарованием предлагает загримированной слизи свой поцелуй, Дрипли отшатывается и выражает непонимание «зачем с ним, конструктом и плодом алхимии, делать что-то подробное».\n\nПримерно часовая заминка с любовным зельем, вскружившим голову Локи, немножко путает планы луперов, и они выходят из зала позже обговоренного срока. Не смотря на выходку колдуна, Янка следует плану и отправляется вместе с ним исследовать помещения Академии, тогда как Дрипли остаётся защищать студентов, которых будут вести к убежищу. Напоследок, как прощание и завершающий аккорд этого почти испорченного вечера, чародейка целует Дрипли в щеку, оставляя на ней чуть заметный зелёный след от губ - грим постепенно отходит. \n\nКогда Уини, Дрюс, Каэл, Локи, Янка и Тони подходят к комнате охраны, Павел Ненадович за дверью убеждает их, что не может впустить по приказу выше. Дрюс и Энтони предлагают выпить прекрасных напитков с празднования, Янка, пока Локи ещё пребывает в романтических мыслях, пытается договориться с охранников, убедительно пародируя голос Норы Буул. Удивительно, но Павел не узнаёт свою начальницу. Начинается вторжение: издалека слышны сперва фейерверки, потом взрывы, пол содрогается... Студенты пытаются выломать злосчастную дверь, но по периметру комнаты собирается защитное силовое поле, не подвластное рассеиванию. По ту сторону, в рубке, кто-то ядовито смеётся над нерадивыми студентами, и в характере его голоса слышится ибасанский акцент. \n\nПонимая, что с защитой академии они уже ничего не смогут сделать, герои бегут смотреть на состояние залов телепортации, а долг паладина зовёт Уини присоединиться к студентам, прямо сейчас пытающихся преодолеть орды монстров на пути к убежищу. Рыцарка застаёт в бальном зале первокурсников, строящихся за старостой, на бегу вынимает меч из ножен и обгоняет толпу, чтобы выйти наружу. Оказавшись на улице, где прямо сейчас происходит настоящий хаос, Уинифред замахивается мечом прямо в своды эвакуационного выхода. Точный удар обрушивает проход, преграждая студентам путь на верную смерть, а сама паладинша остаётся снаружи, тут же подключаясь к защите невинных. \n\nТем временем в зале телепортации кучка ибасанских магов контролирует будку управления, пропуская добровольно сдавшихся в плен гостей фестиваля. Военные уверяют, что соблюдают международные договоренности, и телепорт приведет магов в более безопасное место, чем Сиория сейчас. У Локи рождается план выведать то, что находится по ту сторону телепорта, и он подговаривает Каэла на небольшое представление. Колдун перевоплощается в Ватиму Тинка и представляет Каэла как своего бастарда, которого нужно отправить на ту сторону. Военные не реагируют на значимую фигуру главы гильдии, не отдают ему честь или что-то подобное, просто спокойно принимают волшебника в плен. Когда набирается необходимая для телепортации группа, Каэл переносится в каменное помещение с неестественной тишиной, блокирующей любые заклинания. Из окон тюрьмы мельком видно горизонт, разделённый морской гладью (вероятно, он попал прямиком на соседний остров). \n\nНе находя больше ничего интересного в телепортационной, Локи присоединяется к Янке, задумчиво наблюдающей за горящей Сиорией. Оба могут увидеть поднявшуюся в воздухе фигуру древнего лича, сметающего сопротивление одним только взмахом черной костяной руки. На голове мертвеца красуется большая корона, и, вне всяких сомнений, это Кватач-Ичл.", "new_npcs_raw": "Павел Ненадович - охранник в Академии\n\nВатима Тинк - глава гильдии волшебников (упоминается)"}'::jsonb),
  (25, '{"session_number": 25, "loop_number": 3, "game_date": "3 петля, 1-2 странствий", "recap": "Начало петли, луперы просыпаются как обычно. Как договаривались, все встречаются в клубной комнате и рассказывают, как провели конец петли, обсуждают, что делать дальше. Энтони и Рион вспоминают, что в Князевых Дверях в прошлый раз подозительно умерло несколько человек, и всё связано с няней Розы. Товарищи собираются для поездки, экипируются и выежают, Норвина отправляет Послание Розе, чтобы та их ждала. \n\nРоза в этот момент использует свиток Разговора с мёртвыми и спрашивает у няни *5 личных вопросов, в одном из ответов звучала Магия душ*. Роза лезет в нянин тайник, достаёт оттуда письма, в которых есть переписки с Лукавом Текло (алхимиком) и Алаником Зоском (жрецом), собирает вещи и идёт встречать товарищей на станцию. Пока ребята едут, Рион крафтит свою великую броню, Карина с Офелией как одноклассницы обсуждают свои дела, Маркус всю дорогу глушит пиво, а Энтони вспоминает величие семьи... \n\nГерои прибывают в 8 утра, их встречает Роза на боевом коне, они быстро обсуждают план действий, смотрят письма и решают идти к дому Лукава. Там происходит странный разговор: Роза пытается предупредить алхимика, что тому грозит опасность (умирают люди, связанные перепиской с няней), а Рион придумывает на ходу, что это информация от некого предсказателя. Лукав не очень верит, но впускает ребят в дом, немного беседует, говорит, что будет готов, и отпускает. В это время Карина помогает Маркусу писять и избавляет от опьянения. Это было очень вовремя, потому что, заходя в дом, монах хотел что-то ляпнуть. \n\nДрузья решают, что до расправы с кабанами ещё долго, и можно заняться расспросами местных, Маркус стучится в близжайший дом, ему отвечают, что главный на селе сейчас на покосе. Часть группы идёт туда, Рион остаётся следить с помощью фамильяра за Лукавом, но тот не выходит из дома (что-то варит). Маркус здоровается с мужиками, выпивает с ними, рассказывает, что их, как студентов Академии, отправляют на помощь в населённые пункты вокруг Сиории в качестве практики. Мужики говорят, что у них спокойно и ничего не происходит, а Лукав хороший мужик, всем помогает, его нужно беречь. Хорошая репутация дополнительно мотивирует героев подготовить засаду на том месте, где в прошлый раз Лукава растерзали кабаны. \n\nВечером  Лукав выходит из дома, как из неоткуда появляются разъяренные кабаны, бегущие в его сторону. Алхимик кидает в них зелье, ожидаемого эффекта нет, он застывает на месте в растерянности. Студенты тут же реагируют, Рион первым хочет спасти Лукава, но тот не поддаётся на магию извне. Маркус влетает в кабанов и встаёт между ними и жертвой, а остальные на расстоянии разносят тушки. Кабаны оказываются на удивление живучими или, скорее, уже мертвыми. Алхимик даёт Риону себя телепортировать из боя, после все изучают тела кабанов, сжигают их, но одного закапывают для доказательств. Лукав понимает, что его предупреждали не зря, и сейчас Аланик в опасности. Все тут же отправляются к нему. \n\nНа месте перед храмом-крепостью следующая картина: впереди башня окружена 12-14 стрелками с автоматическим оружием, в самой же башне Аланик отстреливается в помощью бойницы. В центре круга из стрелков стоит так же двое магов, один из которых заряжает магией какой-то предмет (выглядит опасно). Студенты вместе с Лукавом намерены спасти Аланика, поэтому влетают в самое пекло. Офелия создаёт Маяк надежды, Энтони и Карина выдвигаются вперёд, Риона и Маркуса телепортируют раздавать тумаки прямиком в центр круга, Роза стреляет издалека. \n\nЗа пару мгновений герои роняют магов, но все стрелки переключаются на студентов. В Риона летит около 20 выстрелов, но все отскакивают, Карине везёт меньше. Офелия успешно лечит нуждающихся. Во врагов летят самые мощные разрушительные заклинания, часть стрелков бежит прочь. Рион, Энтони и Карина догоняют беглецов, в то время как Маркус, Офелия и Роза переключаются на помощь. Отступающие тоже не просто удирают, а разворачиваются и закидывают бомбами погоню. Лукав превращается в горгону, чтобы помочь расправиться с остатками стрелков, Аланик из башни вызывает огненный вихрь, 1-2 наемникам удаётся скрыться, один даже пытается взорвать пояс шахида, окружённый Маркусом, Офелией и Кариной, но жрица в последний момент высасывает все его жизненные силы. Последнего хватает Маркус, усыпляет и убеждает остальных, что хотя бы его стоит оставить в живых.\n\nМаркус и Роза сетуют, что убивать убегающих было не обязательно, Рион и Энтони в защиту подмечают, что магия в принципе летальная, и вообще они первые напали. Начинается небольшая перепалка, которая заканчивается, когда из храма выходит жрец. Аланик обращается только к своему другу, Лукаву, а остальных как будто игнорирует. Ребята говорят, что спасли ему жизнь, но воинствующий жрец довольно занозчиво отвечает, мол, у него всё было под контролем.", "new_npcs_raw": "🥊Ветеран - https://dnd.su/bestiary/421-veteran/\n\n🥊Кабаны-нежить", "materials": "Карина про поездку:\n\nсмотри далеко смотри\nтот вид как красив тот вид\nвбирай всё вокруг вбирай\nдома города дома\nлюби просто так люби\nте дни навсегда те дни\nбросай налегке бросай\nсама всё в себе сама\nдыши глубоко дыши\nжива до тех пор жива", "perks": "🔮4 магических револьвера"}'::jsonb),
  (26, '{"session_number": 26, "loop_number": 3, "game_date": "3 петля, 1-2 странствий", "recap": "Начало петли, просыпается Миряна, и понимает, что она снова здесь, может продолжать свои научные изыскания и начинать свои проекты. Студентка 3-го курса параллельного класса удачно скрывалась от остальных, и никто не понял, что она тоже Прозревшая.\n\nАльд, Дрипли, Янка встречаются в аудитории, по договорённости каждый из Луперов должен прийти, чтобы поделиться информацией и вдруг с кем-то что-то случилось. Они встречают *группу собирающуюся в Князевы Двери (игра 25)*, но в аудитории нет Анариона, Дрюса и многих других. Альд через *Поиск предмета (курительная трубка)* находит Дрюса в Золотом петухе, и узнают, что Анариона видели в общежитии.\nТоварищи приходят к комнате Анариона, стучатся, но он не открывает, начинают кричать и привлекают внимание Миряны, которая живёт через стену и выходит посмотреть, а в этот момент Дрипли вскрывает дверь. Маряна в шоке, ребята как-то объясняют что другу нужна помощь, и девушка от них отстаёт, но понимает, что в прошлой петле этого не было, и отправляет своего конструкта подслушать.\n\nРебята попадают в комнату Анариона, он в депрессии (таблица травм), Альд проводит беседу по душам, что без него им ну никак не справиться (проверка медицины 20 и Малое Восстановление) мотивирует Анариона. Янка, которая всё это время держит Дрипли за руку замечает, что их подслушивают. Конструкт едет по коридору к двери Миряны, ребята стучатся к ней и говорят, что нехорошо. Девушка отнекивается, а Дрипли начинает с ней заумный разговор про конструктов. Альд задаёт ей прямой вопрос про Петлю, секундное замешательство и вот уже они в комнате Миряны.\nПрозревшие что-то обсуждают о своём, Миряна показывает свои записи, заумные слова на изобретательском, девушка делится своими догадками, в этот момент соседка по комнате немного в шоке, но подруга её успокаивает. Тут Миряна вспоминает, что возможно один её одноклассник тоже Прозревший, они решают это проверить и идут в таверну (Какое-то претенциозное название).\n\nНа втором этаже за столиком в творческом беспорядке что-то творит Лекс Лексингтон, кидая листы бумаги и оскорбления в своего конструкта. Товарищи находят его за этим занятием, и он начинает воодушевлённо, сбивчиво и по именам обращаться к каждому, что всё не так, в прошлый раз произведение было идеальным, они снова всё испортили, а его конструкт как на зло ничего не помнит. Так за выпивкой новые товарищи обсуждают подробности петли, у кого какая полезная информация, и что делать дальше.\nДрипли агитирует новичков, что геройские герои должны становиться сильнее, пытаться остановить вторжение и спасти всех. Сначала встречаются с Тайвен, где уничтожают личинок и получают награду. Затем все идут к Савочке за покупками, а затем отправляются в подземелье, проведать погонщика с троллями и вдруг что-то изменилось.\n\nПо старому пути они выходят к туннелю, но не дойдя до прошлого места из-за поворота неожиданно высовываются лапы и морда красного дракона (25 игра, наконец-то подземелья и драконы). Он дышит огнём, но Миряна понимает, что это иллюзия, запрыгивает за него и видит убегающего паука. Альд за ней, они убивают его и иллюзия спадает, но тут они слышат уже знакомый гул и грохот троллей дальше в туннеле.\nНебольшая подготовка, Дрюс делает насыпь земли, Альд всех бафает, Дрипли готовит залп Паутины, Янка выстрел Шарика, Анарион зону холода, Миряна озвучивает план, Лекс судорожно записывает.. Тролли выбегают, в них летит Опутывание, и другие подготовленные заклинания, монстры мгновенно вязнут, Янка мощно стреляет, двое из них падают. Дрюс превращается в медведя. Но двое погонщиков, Рассеивают часть заклинаний, оказывая поддержку монстрам, но ловушки играют на руку студентам, и враги начинают отступать. Товарищи решают их догнать, перепрыгивают ловушки, но перед ними возникает каменная стена. Студенты её рассеивают, но перед ними возникает ещё одна.\n\nАнарион в порыве адреналина обращается к сырой мане, у него вместо рук вырастают костяные бивни-наросты, и он не может кастовать. А Янка из-за всплеска дикой магии неожиданно стала 7-ми леткой. Студенты решают не рисковать в начале петли и отсупить, захватив тело мозгопаука и тролля с собой наверх. Альд использует Невидимость на себя и Анариона, чтобы не привлекать внимание, а охрана входа в подземелье в шоке от тела тролля, которое притащили на импровизированных носилках Дрипли и остальная команда (кроме Миряны)", "materials": "💫 Гороскоп для Янки от Карины:\nНеровный день, но запомнится он, скорее, позитивом. Трудности не исключены, но азарт и хорошее настроение помогут справиться с ними без особых усилий. К тому же в вашем активе поддержка друзей, которые возлагают на сотрудничество с вами определенные надежды.\n   В личных отношениях конфликтов удастся легко избежать, если не припоминать обиды, у которых давно истек срок годности. (ахаха ага буквально ВЧЕРА было)", "perks": "💲Выполнение задания - 60 золотых\n\n🧪Ингридиенты - 125 золотых (Слизь)"}'::jsonb),
  (27, '{"session_number": 27, "loop_number": 3, "game_date": "3 петля, 2-4 странствий", "recap": "Тело тролля сдали страже (Тело троля было продано на ингридиенты для зелья леченья). Приглашённый капитан просит Лекса, Дрипли и Янку пройти за ним в участок (остальные не объявились перед стражей). Там их разделяют и опрашивают поодиночке.\nЛекс передаёт властям имеющиеся у него записи и четвёртый вариант рукописи. Дрипли оказывается достаточно разговорчив, а Янка отмалчивается.\nИльза Зилети выручает студентов, подтверждая, что девочку (Янку) не похищали.\nВ результате противоречивых показаний ребят (оценки разнятся: по их словам, троллей было от 4 до 35) и благодаря телу тролля в качестве неопровержимого доказательства, официальные входы в подземелья были закрыты до конца расследования.\n\nРазочарованные сорвавшейся возможностью исследовать подземелья, часть Залуперов собирается в экспедицию к Храму Удачи, взяв задание на разведку и обустройство лагеря. По знакомому пути им встречаются прежние враги (ледяные пауки, 5 шт. — 200 зм).\nСражение с аберрациями приводит к гибели Альда от извлечения мозга. \nРион и Локи, и магия невидимости проводят успешное ограбление Храма Удачи, избежав прямого противостояния.", "materials": "💫 Гороскоп для Альда от Карины:\nСветит некая прибыль. Эти деньги лучше приберечь, к тому же для дорогих покупок день не самый подходящий. О делах: кто-то может вас подвести, что-то забыть, так что рассчитывайте в основном на себя.", "perks": "🧪Ингридиенты - 200 золотых (Пауки) \n\n🧪Ингридиенты - 360 золотых (Аберрация)\n\n💲Продажа револьверов - ? золотых\n\n🔮Камни удачи - ? золотых \n\n🔮Меч Дурака - ? золотых"}'::jsonb),
  (28, '{"session_number": 28, "loop_number": 3, "game_date": "3 петля, 5 странствий", "recap": "Девичьи посиделки у Офелии, Бальтазар, по поручению отца, провожает на них Янку.\nРешили пойти познакомиться с Анной, пока она не умерла. Дома её нет, понял Бальтазар, выбив дверь мистичеким зарядом. На другой адрес идём, решил Бальтазар, убирая найденное ожерелье за пазуху. \nПоместье которое арендует Алиса Золтан, слежка, вечером Анна покидает поместье. Её провожают до дома. Запугав девушку и Обманув стражу, Бальтазар приводит Девушек обратно к поместью. Открывает горничная, Анна юркает внутрь,  Бальтазар уверенно называет имя и просит о встрече. Горничная просит подождать. Вместо неё, дверь открывают телохранители и просят покинуть частную собственность. Уинифред чует, что с ними общается нежить. \nБой, ворвались в холл, испугали троих, и загипнотизировали остальных солевых. Залуперы решают отступить из опасной ситуации, попутно хулиганствуя: разбивая стекла и срывая шторы. \n\nСбегая из дома Золтан, Карина отправляет послание Батаку, чтобы тот вызывал инквизицию. В тот же вечер собирается группа, в составе которой есть воинствующий жрец Аланик (Рион не застаёт того в храме). Налёт идёт не по плану, все отродья телепортируются из особняка.", "materials": "Карина про Альда:\n\nнесущий свет\nне видит след\nсияя вне\nна самом дне\nсовсем ослеп\nлишившись глаз\nна этот раз\nувидел смерть\n\nПодарок от Янки Карине", "materials_url": "https://t.me/c/2576013907/1762/10532"}'::jsonb),
  (29, '{"session_number": 29, "loop_number": 3, "game_date": "3 петля, 6-8 странствий", "recap": "6-го числа. Знакомство с Доминикой проходит с недоверием. Она сообщает, что выживала при каждом конце света и готова показать, где. Компания собирается в путь.\n\nВо дворе академии Бенисек беседует с Бобом Саймоном. К ним подходит Роза, чтобы узнать подробности. В итоге разговора она назначает Бенисеку свидание на выходных. Саймон прощается, говоря, что заходил просто поздороваться со старым другом.\nВ этот момент Бенисек слышит в голове телепатический голос неизвестного. Анарион, считывает мысли уходящего Саймона: Тот доволен, что так быстро нашёл того, кого искал.\n\nПока герои обсуждают, что делать дальше, Доминику просят отойти в сторонку.\nКаэл сообщает об интересных и многообещающих историях, связанных с древним капищем в 48 милях от Князевых Дверей. Информации мало: известно лишь, что оно связано с наследием ведьмовских ковенов и до сих пор не изучено. Он собирает команду для экспедиции. Путь на поезде занимает 8 часов.\n\n7-го числа. Через 4 часа пути группу ожидает неожиданность — снег в августе. Герои разворачиваются и возвращаются в Князевы Двери, чтобы купить тёплую одежду и припасы (по 1 зелью сопротивления холоду на каждого). На это уходит ещё 5 часов.\nПутешествие продолжается. В сумерках на них нападает стая из 7 волков. Расправившись с хищниками, оттащив 5 туш от дороги и пройдя ещё 1-3 мили, группа возводит убежище из земли, снега и палок.\nКарина, выпив зелье, остаётся бодрой и стоит на страже. Отвлекшись на миг, она замечает высокую человекоподобную тень, исчезающую среди деревьев. В ту же секунду вспыхивает сигнал тревоги, и стену укрытия проламывает вендиго, чтобы спустя 12 секунд пасть, залив стены своей кровью. Добыча оценивается в 2200 зм (ингредиенты). Доминике, сражавшейся в нижнем белье, оказывают первую помощь.\n\n8-го числа. После 8 часов путешествия группа разбивает лагерь. Судя по ориентирам, до каньона остаётся примерно час пути. Разведка с воздуха с помощью фамильяра приносит команде сведения: капище находится на дне каньона.", "materials": "Карина о снеге:\n\nсбросили ели иглы\nеле в тумане дышат\nвместо росы и пыли\nснегом их профиль вышит\nвышли на крышу дети\nи улетели в космос\nокна вдогонку светят\nснизу почти как звёзды\nкошка бежит вприпрыжку\nмесяц лежит на туче\nдухи из мрака вышли\nи загорелся лучик\n\nРазведданные с капища", "materials_url": "https://t.me/c/2576013907/1762/10549"}'::jsonb),
  (30, '{"session_number": 30, "loop_number": 3, "game_date": "3 петля, 6-8 странствий", "recap": "Герои находят под дверью записку от Киллиана Дрейфуса, Дрипли после уроков вешает на дверь клуба свою шляпу в знак принятия. Новый путешественник присоединяется к обсуждению дальнейших планов. После смерти Альда Дрипли пытается определить, чем отличается хорошее приключение от плохого, а так же извиняется перед Локи за нервный срыв и затрещину. Помимо строительства лагеря возле храма удачи, пока решительно не понятно, как действовать дальше. Но Киллиан намекает, что можно связаться с его знакомым - Йово \n\nТем временем в Князевых дверях Офелия и Рион в тренируются у Аланика Зоска. Жрец предлагает студентам выпить неизвестное зелье, которое оказывается сильным галлюциногеном. Под действием зелья герои чувствуют пределы своей души и не могут противится допросу Аланика. В душах обоих содержится какой-то неизвестный конструкт, тесно переплетенный со всеми частями души. Они видят воспоминания из прошлых петель. \n\n8-ого странствий Бальтазар приходит в клуб и спрашивает про девушек: Офелию, Карину, Розу, Уини и Янку. Это выглядит подозрительно, ведь Бальтазар знает про северную экспедицию и то, что Янка сидит прямо в клубной комнате. Маленькая чародейка тут же уползает ниже под стол, Маркус вдавливает её рукой. Бальтазар даже не поправляет, когда Локи обращается к нему \"Балт\". Киллиан пытается обнаружить следы магии, использованной на однокласснике, но ничего. Лекс встаёт из-за стола и отходит к окну, изображая отрешённость, а на самом деле применяет рассеивание. Бальтазар тут же как будто пробуждается, только что он находился в странном тесном пространстве из красного камня. Последнее, что он помнит - как ложился спать. \n\nЛекс, Дрипли, Локи, Киллиан и Маркус отправляются в общежитие в поиске улик, а Янка, как та, кого искали, боится идти и тихонько предлагает Дрипли остаться в клубе или спрятаться. В итоге маленькую чародейку оставляют одну, она укутывается в плащ, пытаясь быть незаметной (крит 1 на скрытность), и добежать до, как ей кажется, безопасного школьного туалета. Ещё на половине пути неизвестное вмешательство телепортирует её душу в то же самое каменное пространство, которое к тому же трясет. Овладевший телом оставляет в клубе записку о том, что их подруга в заложниках, и чтобы ее освободить, должны прийти все названные (и только) по адресу. \n\nОбщажная комната барда выглядит весьма аскетично: стол, стул, матрас на полу да гитары. Рядом с \"кроватью\" герои находят отрез шёлка, как раз необходимого для сотворения Нестуловой ложной ауры. Возвращаясь в клубную комнату, они читают записку, тут же в панике обращаются к Кайрону, и он немедленно собирает команду для штурма похитителей. Студенты подкрадываются к нужному дому следом и наблюдают знакомых им товарищей, которые повздорили с вампирами. Тех встречает фигура в плаще, вытягивает руку и произносит заклинание, которое рассеивает маскировку. Бой не успевает свершиться - множество магических залпов летит в похитителя, и активируется \"защита\" дома. Разносится иссушающая некротическая энергия, мгновенно лишающая жизненной силы Кайрона, Ниртака, Ильзу, Юлиана, Карабриеру и самого смертника, даже задевает соседние дома (6 Кругов смерти). \n\nВбегая внутрь, герои видят в центре комнаты бездыханное тело Янки с чёрной розой в руках. Маг в плаще оказывается очередным вампирским отродьем, Дрипли трясет его в припадке отчаяния и бьёт об стену. Локи, пока полиция ещё в пути, обшаривает преподавателей. Спустя какое-то время, уже вернувшись домой, Дрипли обращается к отцу с вопросом, может ли тот воскресить Янку с помощью алхимии. Лайонел отвечает: \"Она уже мертва, я не могу вернуть её к жизни\".\n\nПропущенная сцена (2 петля, после 25 странствий): \nДрипли заходит на чай к Локи, который снимает комнату вместе с ещё одним новым студентом - Каэлом Твериновым. Каэл не прозревший, но хорошо разбирается в алхимии (ему даже оборудовали подвал для проведения экспериментов). \"Ты единственный человек, который пережил плач\" - говорит Каэл с горящими глазами в ответ на историю создания Дрипли. К сожалению для Каэла, профессор Лайонел не открыт к диалогу про свои исследования.", "materials": "Карина о Янке:\n\nчто делать если\nэти глаза пусты\nлица покрыты жестью\nБриллиант застыл\nНебу направив письма\nдумая ни о чём\nПауза слов повисла\nбог Её предпочёл."}'::jsonb),
  (31, '{"session_number": 31, "loop_number": 3, "game_date": "3 петля, 9 странствий", "recap": "Янка просыпается около 2-х ночи в 4-й петле от крика ужаса после своей смерти в результате активации множества «Кругов смерти» после похищения вампирами с сильной душевной болью. К ней заходит мама и пытается её как-то утешить и успокоить, обнимает, но Янка выгоняет её из комнаты. \n\nДуша Альда, находясь в кольце разума, «видит» проход в посмертие в виде бесконечной реки. Затем возвращается назад в пространство кольца и видит реку в виде окошка. Что-то в этом окне явно не так, будто бы когда долго смотришь на реку, река начинает смотреть на тебя в ответ.\n\nДрипли просыпается от странного сна, где он танцует с Янкой на балу в честь Летнего Фестиваля, будучи в человеческом обличии – явно не чувствует себя в своём теле, что-то точно не так. Осматривается по сторонам, и стороны начинают осматриваться на него  тысячами разных глаз – разных размеров, цвета, структуры. Были глаза с несколькими радужками, были светящиеся, были фасеточные, как у насекомых. Он просыпается и спускается к завтраку, в голове и вслух продолжая биться над проблемой возвращения человека к жизни, его отец с тяжелой грустью продолжает настаивать на невозможности этого. \n\nМаркус просыпается с тяжелым сердцем и видит посылку с налобной повязкой и подписью «настройся на меня», что и делает, получая заметный прирост интеллекта. Зак просыпается в своем поместье с некоторой апатией – он точно знает, что Янка вернётся. Лекс просыпается в «Вине поэзии», продолжая исступлённо биться над проблемами своего романа – что-то явно не сходится. \nВсе, включая Локи, собираются на специальных занятиях, посвященных защите от некромантских воздействий. Ряды одноклассников заметно поредели – многих забрали родители, в классе выделяются два новых человека, ~20летние Саид (темнокожий и лысый) и Аида (с азиатскими чертами лица), собранные и молчаливые, снабженные пропусками в академию и обвешанные волшебными палочками и зельями. Ребята понимают, что это телохранители зеленоволосой Копривы Рейд – их одноклассницы, якобы связанной с организованной преступностью.\n\nМаркус пытается завести с ней разговор и разузнать про новых гостей, но разговор явно не клеится – сказывается его недостаток осведомленности и несколько скверный характер самой Копривы, к тому же он делает несколько неосторожных ремарок, которые можно принять за угрозы. Ксвим начинает занятие с того, что аккуратно проходится по тому, что он думает о компетентности погибших профессоров – вопиющее нарушение рабочей этики. Даёт задание по группам – попытаться смоделировать врыв в особняк порождений вампиров, имея знания о нахождении там заложника.\n\nУ группы \"Луперов\" получается представить неплохое решение. Ксвим сдержанно их хвалит, но намекает на проблемные моменты, которые не желает пояснять. Маркус вступает с ним в открытую перепалку, демонстрируя незаурядный интеллект и выросшие способности к нахождению аргументов. Лекс его поддерживает. Ксвим нехотя признает свою неправоту. Далее «луперы» вне уроков высказывают Маркусу подозрения и он признается в использовании повязки интеллекта.\n\nКоротко занявшись своими делами (покупки и прочая рутина), «луперы» идут в церковь, где происходит служба в честь Янки. Батак и её мама говорят там свои речи. Многие гости дают конверты и мешочки с деньгами маме Янки, на сумку которой положил глаз Локи. Бальтазар играет на органе. Процессия продвигается на кладбище, а затем в одну из столовых, у входа в которую Маркус замечает подозрительно припаркованную темную карету с магическим двигателем. Происходит магическяа разведка кареты, внутри замечают русоволосую девушку лет 25-ти с магической сферой для создания изображений. Группа выдвигается к ней, карета пытается уехать, но Дрипли меткими выстрелами разваливает колесо, а Зак запрыгивает на крышу, карета переворачивается.\n\nПерепуганная девушка явно похожа на частного детектива, у неё забирают сферу и удаляют найденные изображения с фокусом на группу школьников (около церкви, на кладбище и у входа в кафе). Её бегло допрашивают, она явно говорит правду, но несколько раз ее ловят на прямых противоречиях фактам. Такое сочетание полной уверенности в правдивости вместе с очевидной ложью позволяет Локи и Дрипли понять, что они имеют дело с заклинанием \"Находчивости\" (https://5e14.dnd.su/spells/179-glibness/). Она говорит о том, что её наняли для создания изображений с последующей передачей магической сферы по названному ей адресу в складском районе недалеко от них. \n\nПосле того как на девушку особенно сильно надавили, она телепортируется от школьников при помощи пространственных врат и группа, починив магическую карету, отправляется по указанному адресу. Зак в восторге от самой кареты и от того, что он оказывается умеет ей управлять. Группа пытается провести разведку склада издалека, но фамильяр Маркуса гибнет от магического выстрела. Они отправляются внутрь через главный вход и окно, Маркус же обходит склад сзади. Внутри они находят ту самую девушку и двух порождений вампиров. Девушка превращается в ужасное нечто, у нее удлиняется шея и ломаются кости, она начинает парить в воздухе и использовать сильные заклинания – облако яда, тьму, выпускать множество мистических зарядов.\n\nВ результате сложной битвы едва не гибнет Дрипли, но им удается победить колдунью и оба порождения – колдунья просто распадается облаком эктоплазмы и развеивается, остается лишь её одежда, револьвер и защитный плащ. Группа, довольная победой, отправляется в \"Золотого Петуха\". В процессе битвы колдунья успевает проговориться, что ни одного вампира в Сиории больше не осталось и им никогда до них не добраться (в основном потому что она думала, что убьет зарвавшихся школьников, но ошиблась).", "new_npcs_raw": "Орфея - якобы(?) частный детектив, колдунья, работает за одно с вампирами", "materials": "Церемония прощания. Художественно, подробно.", "materials_url": "https://docs.google.com/document/d/1Uhu-518TzwopR-WOdRBS5NJs3Nij8jk-Pqhb9ZMdLQY/edit?tab=t.0"}'::jsonb),
  (32, '{"session_number": 32, "loop_number": 3, "game_date": "3 петля, 13 странствий", "recap": "У Локи удачно получается продать \"меч дурака\" за 5000🥇. Каэл и Миряна записывают себе \"Огненный шар\" в книги заклинаний. Группа собирается в Князевых дверях 11-го числа, закупается зельями лечения и сопротивления холода, и к 13-му числу без приключений добирается до большого ледяного каньона. Сверху открывается хороший вид на происходящее – все видят экосистему, завязанную на борьбе за сильный источник сырой маны в центре, в которой участвуют элементали, мефиты, ледяные ящеры, великаны, белый дракон и другие не самые приятные существа. Также заметен явно созданный магией изменения лагерь с каменными стенами и оставшимися в порядке оберегами погоды, к которому группа и решает выдвинуться.\n\nСтоило им зайти внутрь, поднялся шквальный ветер и на группу напали два воздушных элементаля при поддержке множества ледяных мефитов, которые по какой-то причине старались держаться поближе к земле. Завязывается бой, Локи создает большую иллюзию огненного элементаля, которую пытается прокусить один из мефитов, но тот разочаровывается и враги понимают подмену. Каэл и Миряна замедляют врагов, Карина призывает молнии, убивая по несколько врагов за раз, Роза обстреливает противников издалека, Энтони стойко выдерживает множество ударов, будучи в окружении. Доминика сражается при помощи хлыста, в какой-то момент элементаль подхватывает её потоком воздуха и швыряет в сторону, потом это же происходит и с Миряной. Миряна видит, что враги встали чересчур удачно и закидывает в них огненный шар, хоть и понимая, что неизбежно заденет Доминику, заранее кричит извинения.\n\nМолнии Карины и мистические заряды Розы вместе с огненными снарядами волшебников помогают закончить бой. Все более-менее в порядке и решают отдохнуть, а затем спуститься вниз к явно оставленным прошлой группой исследователей припасам. Роза не поддается на уговоры и остается наверху. Группе внизу удается вовремя заметить спящего у камня великана (благодаря невидимости Энтони), Локи отвлекает его иллюзорным воем волков и все удачно прокрадываются мимо. На группу вскоре наступает метель, которую развеивает Карина, показываются йети, начинается бой – Локи удачно накладывает гипнотический паттерн выключая пару йети, волшебники времени снова всех замедляют. В какой-то момент появляется особенно отвратительный гигантский йети и всё начинает становиться для группы хуже. Энтони парализован холодным взглядом, Доминика ранена, Оставшаяся без маны Миряна стреляет из револьвера, привлекая внимание спящего недалеко великана, но удачно раня главного йети.\n\nРоза видит идущего к друзьям великана и начинает обстрел издалека, но ловит большущий булыжник в ответ – веревка по которой все спускались падает вниз. Группа как раз успела разделаться с оставшимися йети – Локи выпускает очень сильный огненный хроматический шарик, который перекидывается с одного йети на другого, выжигая их насмерть, но заклинание оказывается не совсем стабильным и мощно попадает в Каэла – его спасает наличие кафтана сопротивления элементам. Карина активно лечит всех, наложив предварительно Маяк Надежды. \n\nРазозленный великан, продолжая получать снаряды от Розы, кидается камнями и в остальную группу – сильно достается Локи и она теряет сознание, от очередного камня падает и Доминика, но в итоге Великан, сильно раненный Розой и огненными снарядами Каэла и Энтони, падает от пуль из револьвера. Все приходят в себя, лечатся, собирают ингредиенты. Фамильяр Розы спускается за упавшей веревкой и при помощи шлямбуров её закрепляют назад, и все, довольно потрепанными, возвращаются в лагерь, споря что им делать дальше – продвигаться вперед или вернуться в Князевы Двери, пока никто не умер.\n\n[Персонаж с высоким пассивным анализом] (Каэл, Энтони, Миряна, Локи) на обратном пути решает проверить кучу снега у спуска/подъёма, счистив слой, находит обломки крыши лагеря, вместе со сломанными баллистой, приставной лестницей, и поломанными болтами, при большом желании возможно починить", "new_npcs_raw": "🥊 Великан\n\n🥊 Йети\n\n🥊 Йети побольше?", "materials": "Карина о походе на капище:\n\nглубокомыслен помысел\nне созерцать луну\nто, что упало в пропасть\nто пусть идёт ко дну\nневозмутимой линией\nтянется белый брег\nнебо всё то же, синее\nтак же летает снег"}'::jsonb),
  (33, '{"session_number": 33, "loop_number": 3, "game_date": "3 петля, 15 странствий", "recap": "Ротация: Локи и Энтони возвращаются в Князевы двери, а Анарион, Рион и Бальтазар (верхом на гигантской мухе) присоединяются к экспедиции. За прошедшие 2 дня герои смогли поднять (по частям) и восстановить баллисту, утром 15 странствий Карина оценивает обстановку в провале. Она видит, как возле пастбища мамонтов как из неоткуда выныривает ледяной дракон и хватает крупное животное, утаскивая под воду. Видно кровавый след, ошмётки плоти и шерсти, но сам дракон скрылся в реке. Карина нервно сглатывает. Если честно, ей уже давно не нравится торчать в этой опасной снежной пустыне. \n\nОборачиваясь на прошлый опыт, герои решают поставить себе реалистичную цель - дойти сегодня хотя бы до оставленных припасов, а там будь что будет. Почти все привычно спускаются по веревкам (Доминика со скакуном остаётся в лагере), Бальтазар спускается на своей мухе. Но злопамятные элементали насылают на приключенцев сильный порыв ветра, и Бальтазару не удаётся удержаться на насекомом. Он срывается, благо, Миряна вовремя реагирует падением перышком (а ведь она хотела сэкономить ману). \n\nУспешно спустившись, герои застают внезапную бурю внизу, ничего не видно дальше 5 футов. Миряна снова вздыхает и начинает ритуал для создания леомундовой хижины, чтобы переждать метель. Когда стихия успокаивается, они неспешно продвигаются на встречу припасам, скрываясь среди деревьев. Наконец, когда героев отделяет от припасов всего 300-футовый крутой склон, Карина замечает подозрительно заваливающиеся деревья сзади, слышен треск снега, и всего через пару секунд группу настигает гигантская снежная лавина (300x150x30). Миряна успевает достать из сумки флакончик с ртутью и проронить каплю вниз, чтобы создать парящий диск, Рион крепко прижимает к себе Карину и левитирует вверх, а Розу удерживает в воздухе её фамильяр. Стремительный поток сносит всех, кто не успел среагировать: Каэла, Анариона, Бальтазара и Миряну, диск которой оказался слишком низко для лавины. \n\nОказавшись погребёнными под толщей снега, ослепленные и скованные в движениях, герои задерживают дыхание и пытаются выбраться. Каэл определяет верх и вызывает где-то над поверхностью свою сову, чтобы та кружила над местом погребения волшебника. Карина его находит и начинает выкапывать. Где-то снег просаживается от заклинаний - скоро Бальтазар и Миряна вылезают наружу. Анарион несколько раз пытается выкарабкаться, растапливает снег вокруг огненными ладонями, но лишь погружается ниже. Из последних сил он выжигает путь наверх, как раз когда Карина нашла его с помощью поиска предмета. Жрица неловко падает в ледяную ямку и заливает в друга зелье лечения. \n\nВсё это время Роза с Рионом обстреливали ехидных йети, которые и сбросили лавину на приключенцев, думая, что их не заметят. Когда возмездие свершилось, Рион притащил разделённые трупы (300 зм), и Миряна укрыла всех под ещё одним тёплым куполом. Теперь припасы тоже погребены под снегом, придется потратить время на то, чтобы их выкопать. В бочках оказывается множество пайков и снаряжения, а так же тубус с записками той самой группы. Содержание заставляет героев ещё больше сомневаться в том, что стоит продолжать экспедицию. Голосование разделяет мнения практически пополам, нерешительный голос Анариона склоняет больше к тому, чтобы дойти до капища. Ох как он жалеет о своём выборе, когда рядом с капищем оказываются три гигантских спящих саламандры и стая безобразных гуманоидов. Без боя к алтарю не подобраться. \n\nГерои притаиваются на деревьях в 100 футах. Роза начинает обстрел, Карина призывает грозовое облако, из которого бьёт молния. От звуков ударов ледяные саламандры просыпаются, уверенно и грозно приближаются, но тут же погружаются куда-то под снег. Множество огненных шаров прогоняют и тварей поменьше, но только чтобы через считанные секунды они вылезли вслед за саламандрами прямо под деревьями с магами. Раскуроченная промерзшая земля не удерживает деревья и роняет их вместе с героями, в воздухе остаются только Роза, Рион и Бальтазар. Летят заготовленные атаки, одну саламандру удаётся загипнотизировать, других замедлить, в ответ героев обдает пробирающий холод из пасти гигантской ящерицы. Гуманоидные твари накидываются на Карину и Анариона, исцарапывая их тела, а потом и вовсе сковывая в мучительных \"объятьях\". Постепенно их тела обмякают без сознания; Рион приказывает Нилу (своей змее) вытащить Карину из хватки твари, но Анариона спасти не удаётся - замерзающий труп утаскивают вглубь. \n\nАрктический воздух наполнен огненными всполохами. Рион кричит: \"Помоги жрице!\". Каэл заливает зелье в Карину, та охрипшим голосом дарует товарищам надежду на выживание. Бальтазар пытается расстрелять тварей, окруживших Миряну. Девушка еле успевает прикрываться щитом между чтением заклинаний, отталкивает двух угнетённых от себя, но их слишком много для неё одной. Она схвачена, истерзана, на неё оборачивается леденящий, голодный взгляд саламандры, и гигантская рептилия разрывает Миряну острыми зубами.\n\nГероям удаётся убить с десяток уродливых гуманоидов и похоронить в огне одну саламандру, но какой ценой. Оставшееся рептилии пытаются заморозить выживших напоследок, а потом утаскивают то, что осталось от Миряны, туда же в пучину. Всё, что осталось вокруг - это кровавый снег.", "new_npcs_raw": "🥊 Морозные саламандры\nhttps://dnd.su/multiverse/bestiary/6757-frost-salamander/\n\n🥊 Заблудший угнетенный\nhttps://dnd.su/multiverse/bestiary/7027-lost-sorrowsworn/", "materials": "Карина о гибели Анариона и Миряны:\n\nмогли взглядом скользить по крышам\nмогли небо ночное слышать\nмогли падать в объятья лета\nмогли чувствовать шёпот ветра\nмогли планы любые строить\nмогли не замечать пустое\nмогли вырвать из жизни время\nмогли счёт не вести потерям\nмогли знать в чём таится сила\nмогли просто любить...\nмогилы..\n\nСмерть Миряны", "materials_url": "https://t.me/c/2576013907/1762/11646"}'::jsonb),
  (34, '{"session_number": 34, "loop_number": 3, "game_date": "3 петля, 12-15 странствий", "recap": "Тренировка на площадке, Тайвен замечает, что Никандр рванул в тренировках вперёд, и Маркус возможно скоро отстанет. \nМаркус соглашается, но сам его ответ изобилует витиеватыми речевыми оборотами, не свойственные Маркусу, Тайвен подмечает это, видимо сильно ударили. Друзья встречаются, подкалывают друг друга, идут спарринговаться. \nНикандр размахивается молотом два раза, попадая по Маркусу, используя размах пытается попасть ещё два раза, но соперник читает движения и уворачивается. Продолжается бой, Маркус использует все свои умения, но Никандр на удивление хорошо знает даже новые и с помощью своих навыков побеждает Маркуса. Разговор по душам, и Маркус выясняет что Никандр тоже *проснувшийся*.\n\nДрюс знакомится с куратором, и пытается добиться от него каких-то тайных знаний. Славалюк делится с ним, показывает редкие фолианты, и оказывается, он уже умеет превращаться в сильных зверей. Куратор показывает Осьминога Пусю, медведя Потапыча, и Дрюс показывает себя отлично в диком облике и изучает новых зверей для этого. \n\nНаши товарищи встречаются в аудитории, Маркус знакомит Никандра с другими приключенцами, ребята пытаются проверить его, чтобы не было как с Бальтазаром, но без магии и кажется всё в порядке, зовут его на первое дело. Пока Локи едет в Сиорию, товарищи идут в морг и пытаются узнать у Петра, нет чего подозрительного. Дрюс перед входом превращается в импровизированного брата Альда, чтобы расспросить у Петра про смерть жреца и втереться в доверие. Но Пётр, ничего не понимает и просит их уйти. Все ходят из морга, но Дрюс возвращается в облике медведя, начиная пугать Петра, но Дрипли усилиями выводит друида наружу. \n\nНебольшая перепалка, Дрипли делает упор на том, что они герои, и герои так не поступают. Зак хочет просто убрать жреца, Маркус против насилия, Никандр свидетель спора. Договариваются, что нельзя идти напролом, нужно подождать ночи и пробраться, а пока следить, вдруг 13-го числа снова появится Саймон. Но его нет.\n\nЛоки приезжает в Сиорию, тоже знакомится с Никандром, вместе придумывают план, как попасть в морг без крови и добыть ключ от подземелья. Локи превращается в Тайвен, товарищи в виде дружины приходят к Марцеллу, и обманывают его в том, что им нужно в составе дружины по наводке начальства проверить подвал морга на наличие враждебных сил, уведомить настоятеля, засвидетельствовать наличие или отсутствие их, чтобы Марцелл при них провёл проверку. Настоятель соглашается, спускаются в морг, ключом открывает ход в склеп.\n\nДрюс в облике паука и невидимости ползёт мимо умертвий по потолку, в это время товарищи готовятся, и когда Друид добирается до развилки коридора, Локи и Зак отправляет Дрипли и Маркуса туда же в невидимости, но монах громко приземляется. Некромант оборачивается на звуки, ему в лицо летит 5 склянок с кислотой от Дрипли, Маркус бежит к нему, и враг кидает облако яда, но тут же его оглушает удар. Заварушка, некромант явно проигрывает. Умертвия никак не реагируют, Локи и Зак делают цепочку из телепортов и отправляют Никандра на помощь друзьям, но видит, как Дрипли смертельно ранит некроманта, а Маркус вбивает его лицо в пол до лужи крови. Мрачная комната, тёмный ритуал, круг магии, гроб.\n\nДрипли переживает об убийстве человека, товарищи успокаивают, а Дрюс находит на теле некроманта чёрный кинжал. Маркус кричит Заку, а Зак передает дальше Локи, что задание выполнено. Пока проходят минуты затишья, товарищи с помощью заклинаний узнают следующее: в гробу лежит девушка, на ней нетленные останки, от кинжала исходит проклятая энергия, а дальняя стена крипты это иллюзия стены, с проходом в канализацию. В это время подходит Марцелл, фиксирует обстоятельства и рассказывает, что девушка умерла два года назад, а её неутешный парень искал способ её воскресить и кажется это он. Из-за попыток обуздать некротическую энергию просыпаются трупы старых героев в виде умертвий. Кажется, это не те некроманты, что убили Янку.\n\nЛоки предлагает продать кинжал на благие цели, но друзья не восторге от идеи. Марцелл забирает кинжал, чтобы передать его инквизиции, просит помочь вынести гроб наружу. Пока товарищи решают, как идти дальше, Локи с помощью магии выносит гроб, и пока никто не видит пытается с помощью магии своровать у Марцелла кинжал, но проваливается.\n\nНастоятель реагирует, отправляет послание Тайвен, но оно приходит настоящей девушке, приходит ответ, и Марцелл закрывает вход в склеп. Ничего не подозревающие друзья выходят через канализацию, и группа настаивает на возвращении в морг, сдать задание и извиниться перед Петром. Локи пытается обманом отговорить ребят, но не получается и пока они беседуют мимо проходит стража и слышит их перепалку. Дрипли громко обвиняет Локи, что герои так не поступают, прямо на глазах у стражи говорит про морг, Маркус держит Локи за руку и гарнизон ведёт их к храму.\n\nМарцелл встречает их, Локи приходится объясняться, он меняет свой облик обратно, и под областью истины товарищи выпаливают не стесняясь всё про кинжал, откуда они знают про склеп, про петлю времени и откровенно конфликтуют прямо перед свидетелями, как будто не боясь последствий. Марцелл и стража решают, что они больны или выжили из ума, всех ведут на допрос, после чего Локи за нападение определяют в тюрьму, а ребят в лечебницу. Всех, кроме Никандра, он убедил стражей в том, что случайно сюда попал, просто пошёл в дружину, а тут такое.\n\nУчастники рейда должны не выезжать из города и посещать лечебницу каждый день, могут ходить на занятия, но из дружины их выписали. Дрипли на следующий день посещает Локи в тюрьме, приносит ему стопку книг про героев, сказки и легенды. Локи их забирает и заканчивает свидание. \n\nN.B. В морге ещё до допроса, Локи передаёт Марцеллу некое кольцо со словами *Не верите живым, спросите у мёртвого*. После всех разборок настоятель в своих покоях обращается к кольцу и слышит оттуда голос Альда.", "new_npcs_raw": "??? - стражник, приставленный к отряду дружины (упоминается)\n\nСлаволюб Пенкало - наставник Дрюса по друидической магии\n\nСергей - некромант, пытавшийся воскресить свою возлюбенную под храмом 8 путей \n\nКатерина - труп девушки под храмом, под нетленными останками", "materials": "Карина отправляет Послание Дрипли  \n\nРазмышления Локи в тюрьме", "materials_url": "https://t.me/c/2576013907/1762/11994"}'::jsonb),
  (35, '{"session_number": 35, "loop_number": 3, "game_date": "3 петля, 17-24 странствий", "recap": "К Розе подходит Карина, спрашивает о планах возвращения в Сиорию, заряжает нянино кольцо новыми заклинаниями и даёт ей своё кольцо, со словами «Если пойдёте за Локи, пригодится». Роза возвращается в город 17-го дня, встречает в аудитории ребят, Зак замечает смену облика колдуньи, и отмечает «Чтобы самой меньше быть похожей на вампиров». Киллиан и Никандр знакомятся со всеми. \n\nПо пути в аудиторию Дрюс встречает Елену, не помнит её, но закуривает и начинает разговор по душам, к ним подходит отец Елены, Тахи Франьо, он хочет познакомиться с участниками дружины, уничтоживших некроманта. Приближаясь к аудитории, слышат перепалку из-за двери. Открывает Роза, и Тахи предлагает сотрудничать с ним, как начальником гарнизона, помочь выследить некромантов, но без лишних глаз, поэтому предлагает освободить Локи под залог 5000 золотых, в обмен на их лояльную службу. \n\nТахи с Еленой уходят, друзья решают как поступить, Киллиан предлагает узнать у Йово, идёт к нему один, и рассказывает про  ситуацию с заключённым, и дилер предлагает незаконный вариант за 1000 золотых. Киллиан возвращается к товарищам рассказывая про этот вариант. Друзья немного спорят и думают как поступить.\n\nВ это время к Локи приходит адвокат Джорнак Докочин, посланный Тахи, узнаёт обстоятельства дела, волшебница рассказывает всё, кроме петли. Адвокат уточняет про облик Тайвен, а ещё про кольцо Альда, предлагая линию защиты, что кольцо собственность Локи.\n\nДрузья спорят, но сходятся на том, что вариант Тахи лучше, но до выхода Локи ещё два дня. Роза идёт с Заком, но по пути их встречает Бенисек, спрашивает почему она не пришла на свидание, Роза плачет, обманывает его смертью своего кота, и с помощью Зака отмазывается от назойливого парня.\n\nКиллиан отказывается у Йово от помощи в побеге, тот предлагает задание, птичка напела, что ищут Карину, Офелию, Розу, Бальтазара, а Уини почему-то нет. Волшебник возвращается, говорит всё товарищам. В это время Дрюс отправляется к Тахи принять предложение, скачет к дому Елены, рассказывает, что они хотят помочь отцу, но его нет дома, но процесс освобождения Локи уже запущен. \n\n18 день. На тренировку Маркуса и Никандра приходит Тайвен, предъявляет ребятам за перевоплощение в неё. Маркус сквозь удары по лицу как-то вяло объясняет ей, она вроде понимает, но требует привести на тренировку Локи, щёлкая костяшками.\n\n20 день. Друзья ждут выхода Локи. Адвокат выводит её из тюрьмы и садятся в карету, ИМЯ рассказывает подробности освобождения, связь Тахи Франьо. Привозит на место сбора, стрёмный склад на окраине города, карета уезжает, но Локи не заходит внутрь, замечая блеск болтов в окне,  и уходит отсюда.\n\nДрузья встречаются и едут за Локи в место сбора, Елена с ними в тайне от отца, Роза использует невидимость, все садятся в карету адвоката, на пол пути до склада встречают идущую Локи. Её затаскивают в карету. Локи шёпотом замечает, что им не нужно на склад, но ребята не разделяют её паранойю и уговаривают ехать. \n\nДоезжают до склада, внутри развёрнута большая операция, более 20 гвардейцев с оцеплением. Ребятам дают экипировку и задание следить за выходом, если полезет нежить. Группа захвата входит, взрывы, вспышки,всё готово. Ребята заходят внутрь, проверяют, это правда нежить. Задание окончено. Тахи приглашает всех на бал 22 дня.\n\nТоварищи собираются в поместье Новеда, Локи видит плакаты *Добро пожаловать*, *с освобождением*. Киллиан напоминает, что Йово говорил про поиск Карины, Офелии, Розы и Бальтазара, имя Уинифред не звучало. Друзья переживают за неё, но ни к чему не приходят. Локи хочет посетить свой дом, но не одна, Дрюс предлагает поскакать на нём, Локи соглашается и они скачут к ней домой. Волшебницу встречает Имайа, переживает, что приходила стража, спрашивает всё ли хорошо с Каэлом Твериновым, Локи проведывает в подвале алхимика. Каэл экспериментирует с каким-то странным элексиром. Впереди вечеринка в поместье Зака. Товарищи неплохо провели время за выпивкой.\n\n21 число, Локи уезжает в Эльдемар за золотом и покупками, под другой личной, выкупая отсек для транспортировки самоходной кареты. Никандр получает от Маркуса привязку интеллекта, но тот не надевает её. Друзья занимаются своими делами. \n\n22 число. Бал Франьо, роскошный пир в особняке богатого начальника гвардии, большой праздник. Дворецкий приглашает группу в кабинет Франьо. Робе, который теперь приставлен к ним как руководитель группы, отмечает их хорошую работу. Бал проходит без происшествий. \n\n23 день. Киллиан снова приходит к Йово, спрашивая про статус задания, оно ещё активно. Волшебник рассказывает товарищам и они предлагают такой план: в поместье Новеда товарищи располагаются вместе, Роза как приманка спит в комнате, а друзья наготове встречать врагов. Обсудив детали, Киллиана отправляют принимать задание, волшебник открывает точное нахождение Розы.\n\n24 день. Второй этаж особняка, две смежные комнаты, в одной замаскированный Дрюс под Розу, вокруг товарищи, а в другой комнате сама Роза. Никаких специальных подготовок, в какой-то момент Зак замечает мышь, стреляет в неё, та взрывается облаком тумана, и все в комнате теряют сознание, кроме Розы в другой комнате, и вышедшего на звуки Киллиана, который не замечает врага в невидимости. Тот пробирается в комнату, видит вместо Розы тело друида, и нападает на настоящую Розу. \n\nПока Киллиан будит Маркуса и Зака, враг вонзает кинжал в Розу, та падает от сильного яда, и ей перерезают горло. Мгновенная смерть. Товарищи обрушиваются на врага, в него летят заклинания, но тот ловко выпрыгивает в окно, и даже рухнувший на его голову Маркус не смог остановить беглеца, монах и сам едва не погиб от новой порции яда. Товарищи хотят зацепить врага из окна, но тот умело скрывается в кустах и убегает, оставляя за собой подарок в траве...\n\nК розе подходит Зак.", "new_npcs_raw": "Франьо Тахи - аристократ, занимает не последнее место среди силовиков, расчитывает за счёт успешной операции обойти конкурентов за пост повыше\n\nЕлена Тахи - аристократка, дочь Франьо Тахи, спутница Дрюса на первом балу и член отряда дружины\n\nДжорнак Докочин - юрист, адвокат, нанятый Франьо Тахи для освобождения Локи\n\nНоа Тисгук - отец Розы, владелец крупного предприятия по производству обуви", "materials": "К розе подходит Зак", "materials_url": "https://t.me/c/2576013907/1762/12317).."}'::jsonb),
  (36, '{"session_number": 36, "loop_number": 3, "game_date": "3 петля, 30 странствий", "recap": "После того, как увозят тело Розы, вплоть до 30 числа Зак терзается запоем. В один из дней Лекс предлагает вместо бала в Академии устроить вечеринку в поместье Новеда, на что Зак легкомысленно отвечает: \"Делай что хош, организуй. Только не приглашай Дрипли\". Лекс худо бедно убеждает каких-то студентов, но они соглашаются только на афтерпати после полуночи, в числе согласившихся есть Бенисек.\n\nНа 30 день в Сиорию возвращаются Офелия, Бальтазар и Уини. Паладинша всё это время пряталась в заброшенном храме в другом городе, чтобы избежать преследования, но долг звал ее поучаствовать хотя бы в последней битве.\n\nПока Зак очухивается у себя дома, Лекс уже встречает Бальтазара вместе с Никандром, мимолётно комментируя внешность последнего как привлекательную. Бальтазар цепляется за эту фразу и пытается убедить Лекса, что тому нравятся мальчики (не понятно, было это убеждение или запугивание).\n\nПостепенно все заваливаются к Заку, тот встречает гостей вымученной улыбкой и лёгкой неуклюжестью из-за похмелья. Ребята делятся последними новостями, знакомятся с новыми лицами. Бальтазар считает своим долгом не только поделиться тем, что текущий собутыльник и сожитель Зака (Лекс) находит парней привлекательными, но и убедить Зака в скрытой гомосексуальности. Бальтазар так напирает, что Зак не выдерживает и решает тут же продемонстрировать свою натуральность. Недолго думая, парень смотрит на Офелию и наклоняется через стол, чтобы её поцеловать, но девушка мягко его останавливает. Бальтазар бросает взгляд, полный ненависти. Замяв неловкость, герои планируют заключительный день. Зак настаивает на том, что нужно пойти попиздится, Офелия же осторожничает и хочет провести разведку, узнать, где прячутся и откуда нападают монстры. Обе стороны сходятся на том, что можно отправиться в подземелья и хорошенько подраться, проводя разведку параллельно. Лекс как раз знает одного опытного человека, который может обеспепечить доступ. \n\nАвантюрист по имени Торвин отдыхает в одном из трактиров Сиории со своими друзьями. Заведения и улочки сейчас полны людей - весь город празднует летний фестиваль. Группа подростков вваливается в таверну, и Лекс пытается убедить Торвина проводить ребят в подземелье, пользуясь предвидением и отсылками к другой временной линии. Подвыпивший и расслабленный, Торвин вообще не понимает, что городит этот малой. Бальтазар старается взять ситуацию в свои руки и грозно смотрит на отдыхающих авантюристов, прибегая к магии. Единственная девушка из их команды кричит и подрывается со своего места, остальные же смиряют студентов возмущенными взглядами, приглашая выйти разобраться на улице. Когда они послушно покидают таверну, Зак уже разминает кулаки, готовясь к драке, но Лекс улаживает вопрос горстью золота. Сотня монет наличными тут же делает Торвина более сговорчивым, и он соглашается проводить школьников в подземелье. Они останавливаются в том же самом месте, где Лекс в прошлый раз бился с троллями. \n\nПеред ними знакомая развилка, на которой ребята решают пойти налево. Там их встречают глухие стены подземелья и раздающиеся эхом чавкающие звуки. Мерзкие причмокивания исходят от трех крюкогоблинов, окруживших труп какой-то твари с щупальцами. Маленькие существа, похожие на помесь изуродованного карлика и летучей мыши, непременно сами оказываются добычей. Зак, Уини и Ник окружают их, протыкая их плоть, отсекая конечности и прибивая молотом к сырому полу. Кричащие твари в ответ только разбрызгивают зеленую едкую кровь, которая неприятно въедается в доспехи и кожу. Пока крюкогоблины ещё издают какие-то звуки, Офелия пытается понять их речь, но, похоже, она так же осмысленна, как рычание собаки или карканье птицы.\n\nОсвободив тупик от этой стайки, герои решают разбить тут небольшой лагерь, из которого как раз будет слышно выход врага из ближайших тоннелей. Никандр устанавливает зачарованную сигнализацию (ожидаемо от сына стражника), которая протрубит в случае приближения врага. Лекс возводит леомундову хижину для того, чтобы скрасить ближайшие 6 часов ожидания.\n\nОни коротают время за разговорами и мелкими увеселениями. Как и в прошлом месяце, Зак приглашает девушек потанцевать. Кружа бронированную паладиншу с неожиданной изящностью, Зак интересуется происхождением девушки. Ее сердце не меньше заковано в броню и закалено испытаниями, чем тело, но между ними есть нечто общее - она также осталась единственной в своем роду.\n\nБлиже к полуночи в обстановке подземелья наконец что-то меняется. Герои замирают, услышав грохот приближающихся троллей, лязг железа и свирепое рычание. Парочка волков отделяются от стаи, учуяв туши крюкогоблинов, и пересекают невидимую сигнализацию. Пещера заливается предупреждающим звуком, но, благо, волки не способны понять его источник, а маги уже ушли достаточно далеко. Разнюхав еще немного, звери убираются прочь, обратно к стае. Все это время Офелия очень настойчивым шепотом просит Никандра выключить сирену. Еще через минут 10-20 подземелье становится вовсе тихим, как будто все обитатели покинули ее. Кажется, самое время выдвигаться на разведку.\n\nСледуя по правому тоннелю, куда ведут следы многочисленной орды монстров, герои доходят до расширения, освещенного двумя магическими факелами. Впереди оказывается нечто похожее на полевой лагерь с наскоро сооруженными палатками, загонами (вероятно, для монстров) и недавно потушенным костровищем. Офелия останавливает всех перед факелами, обозначающими вход, опасаясь ловушек. Зак уверенно телепортируется в центр лагеря и убеждает Лекса с Ником “не ссать”. Вскоре все, кроме Офелии, проходят вперед, оставляя девушку в легком расстройстве, и ничего не происходит. Это место выглядит совершенно покинутым, ни одной полезной зацепки. Утомившись от предосторожностей и прикинув время, которое у них осталось до конца цикла, Зак бросается дальше в тоннели на полной скорости до тех пор, пока не наткнется на врага. \n\nРебята подходят чуть позже, по пути угодив в еще один тупик, и видят перед собой Зака, расстреливающего магов, которые прячутся за чем-то уже напоминающим нормальные защитные укрепления. Боевому чародею мешают подойти ближе расстелившееся по полу шипы и колючки, и вскоре он телепортирует одного из врагов прямо перед собой. Маг чертыхается, неприятно уголов пятки, но мгновенно реагирует хитрым разноцветным узором. Очарованные герои не успевают его поймать. Дальше воины уже идут напролом, не обращая внимание на препятствия. Бальтазар повторяет трюк вражеского мага, выводя из боя его товарища. Впереди гораздо более освещенная пещера, вероятно боевой лагерь, но обзор заслоняют тела подходящих троллей. \n\nОфелия, оставаясь на расстоянии, запускает в троллей цветной шарик и окропляет кислотой трёх громил, Лекс заряжает револьвер, Ник с разбега врезается молотом и непрерывно наносит 4 удара, Уини заносит меч, обхватив его двумя руками. Зак окружает себя аурой духовных стражей, похожих на маленькие силуэты крыльев, сотканных из света. Свет обволакивает вражеского волшебника, принося боль. Пока впереди разворачивается битва и приходят новые ибасанские силы, Бальтазар смотрит на всё это с решимостью в душе. Он набирает воздух в грудь и кричит приказ отступать своим союзникам. Нет, его товарищи не должны погибнуть здесь, в пекле сражения, корчась от ран. Он сам выйдет вперёд и защитит их. \n\nПропустив в голову голос Бальтазара и поддавшись команде, Зак разворачивается и бежит обратно, равнясь с Офелией. Когда навождение сходит, он громко ругается и клянётся заехать Бальтазару по лицу. Тем не менее Офелия пользуется близостью Зака и просит парня наложить невидимость на её фамильяра, чтобы тот мог незаметно пройти сквозь своды тоннеля и осмотреть находящуюся впереди базу. Когда чародей бежит обратно к сражению, он мимолётно читает заклинание невидимости, успевая выпустить из рук ещё пару силовых лучей. Следующий приказ Бальтазара адресован уже жрице, но её опыт позволяет ей успешно сопротивляться. Они определённо ещё поговорят с Бальтазаром об этом.\n\nИх цикл заканчивается в неравной битве. Несмотря на то, что противник значительно превышает их по силам и численности, все дерутся самоотверженно. Прежде чем быть распознанной, лисичка Церебро успевает передать своей хозяйке, что впереди развернулся действительно масштабный лагерь, защищаемый десятками боевых магов, а в центре этой территории завис большой додекаэдр. Внутри двадцатигранника переливаются потоки энергии, по описанию очень напоминающие портал.", "new_npcs_raw": "Торвин - авантюрист, опытный исследователь подземелий"}'::jsonb),
  (37, '{"session_number": 37, "loop_number": 4, "game_date": "4 петля, 1 странствий", "recap": "The Red Sea. The Red Sol. The Red Elixir Vitae.\nRed Stone. White Stone. Luna in Crescent.\n\nКальцинация. Янке 7 лет, она находит в своём шалаше маленького белого птенчика, приносит его домой, но через время он умирает у неё на руках. \nЯнке 10 лет, во время уроков по контролю магии учитель трагически погибает, чародейка не поняла, что произошёл первый всплеск дикой магии. \n3 петля, после гибери Альда Янка идёт подумать к провалу, играя на цимбалах к ней подлетает её новый фамильяр, ворон альбинос Альбус.\n\nСолюция. 3 день, Локи рассказывает Манкод про гибель Альда, они просят показать где еготело в споровождении, забирают его, на груди Альда Локи замечает алый камень. После событий 8-9 числа, Нильссон с дочерью уезжают из города вместе с телом Альда. \n\nСепарация. Дрипил просыпается в своих записях, читает про зелёного льва, вспоминает что убил некроманта, но можно ли считать такого человека живым, с этими мыслями он собирает книги для Локи в тюрье, и роняет сказку об Астрее и Авроре, внимательно перечитвает.\n \nКонъюнкция. Аланик снимает с Карины проклятье, она видит шторм и огромного морсого зверя, кусающего себя за хвост. Девушка делится с Офелией, та рассказывает о своих воспоминаниях. Вспоминает гибель Янки.\n\nКонденсация. Офелия едет в поезде, встречает странных женщин, одна из которых ей гадает, после чего видит навождение, поле. единорог и девукшка, которая истекает кровью, видение проходит, кажется она задемала. Вспоминает гибель Розы.\n\nЦибация. Альд в кольце рассказывает Батаку про петлю, уговаривая поделиться секретным знанием, наставкик делится отрывками знаний про возрождение, что только ищбранные спосбы, и это хранится в секрете, Альд запоминает слова заклинания и покидает кольцо.\n\nКоагуляция\nСублимация\nФерментация\nЭкзальтация\nМультипликация", "new_npcs_raw": "Нильссон Манкод - отец Альда, волшебник песни клинка и воин-самурай\n\nЭльпида Манкод - младшая сестра Альда, 4 курс академии, чародейка теневой магии\n\nЮрий Велюр - продавец драгоценностей в лавке *Ю.Велюр* \n\nКошка Нежа - питомец в храме, ловит мышей\n\nОливия Форсейл - воскрешенная подруга Локи", "materials": "https://t.me/c/2576013907/293/14275", "materials_url": "https://t.me/c/2576013907/293/14275"}'::jsonb),
  (38, '{"session_number": 38, "loop_number": 4, "game_date": "4 петля, 1-5 странствий", "recap": "Новая петля — старые хлопоты. Анарион, Янка, Роза, Бальтазар, Зак, Дрипли и Офелия отправились в Князевы Двери, чтобы спасти алхимика Лукава Текло и жреца Аланика Зоска. Быстро решив кабаний вопрос сожжением, луперы вместе с Лукавом добрались до храма жреца.\n\nНемного золота и просьба Розы — и с Анариона спали уровни истощения, полученные на капище. На этот раз Аланик встретил их сдержанно, выслушивая удивительную информацию. Сперва он проверил каждого лупера, по очереди сканируя их ауру. Как и ожидалось, он увидел одинаковые метки на душах всех присутствующих, в том числе Зака Новеда.\n\nНедолго думая, ребята выдали жрецу и алхимику всю правду, как она есть: \n— про некромантов из особняка Алисы Золтан\n— умертвия под храмом восьми путей\n— негодяя Саймона Боба и его отца-артиллериста Ричарда\n— вторжение с Улькуан-Ибасы, в том числе огромный лагерь монстров в подземельях\n— магический куб телепортации, названный Лукавом Вратами Бакоры\n— а также сведения про какой-то морской форт, куда Каэл переместился из магического круга во 2-й петле\n\nВ основном воинственного лысого мужчину волновали некроманты и всё, что с ними связано, уточняющие вопросы летели в их сторону. Спустя какое-то время, детки договорились, что Аланик будет держать их в курсе про все важные события, которые он предпримет. Со своей стороны, команда пообещала, что не будет лезть в неприятности и касаться этой истории с вторжением. Офелия запросила у Аланика письмо с текстом, чтобы им было легче убедить его в следующий раз. Понять, согласился ли жрец, не удалось.\n\nВернувшись в Сиорию, ребята занялись своими делами. Кто-то наполнял скляночки, кто-то — собирал волшебные предметы, до ночи засиживаясь под кипой пергамента. На 5-й день великолепная шестёрка — АЯРБДО — отправились добывать золотишко. Сперва пали пауки, следом за ними — змейки. И вот, вновь тот самый мост, видавший немало слёз. \n\nЗавязался бой с аберрациями, и на этот раз луперы были умнее. Укрепив сознание крепостью интеллекта, усилив тело магией жрицы, они не вылезали из-за деревьев, выманивая тёмных гадов поближе. Роза поливала аберрацию мистическим зарядом, Дрипли бил ту же тварь кислотными всплесками, Янка стреляла молнией, Анарион бил в колокол, Офелия поддерживала жизненные силы товарищей, а Бальтазар... \n\nБальтазар Неотразимый заставил аберрацию плясать под неудержимой пляской Отто. Какое- то время это вызывало смех. Это продолжалось недолго: мозгоед задоминировал парня, заставив его атаковать своих друзей. Это было управлением разумом. Хроматический шарик чуть было не взорвался над виском Анариона, но Офелия успела искусно отвлечь барда.\n\nПока одна тварь концентрировалась на заклинании, вторая уже летела в бездну, получив невосполнимое количество урона. Все так старались побыстрее расправиться с чудищами, что не жалели сил. Так, у жрицы жизни даже сломалась бузинная палочка снарядов, не выдержав мощного всплеска маны.\n\nБой завершился быстро. Аберрация ошеломила барда и чародея из Ларса, но союзники быстро телепортировали пострадавших, а герой Дрипли нанёс решающий удар по чёрному облаку с щупальцами.\n\nРаскинув лагерь, луперы получили награду. Разговор о том, стоит ли вторгаться в храм удачи, закончился наилучшим вариантом. За кадром Локи и Рион вновь обчистили храм, получив меч дурака и грудку камушков удачи.\n\nЗавершился день сдачей экзамена на сертификацию у преподавателя Кайрона. Все успешно выполнили плетение заклинаний 3-го круга, получив лицензию на доступ к заклинаниям 3-го круга в библиотеке Академии, а также свободное посещение подземелий определенных уровней. Как бонус — восхищение от студентов других курсов."}'::jsonb),
  (39, '{"session_number": 39, "loop_number": 4, "game_date": "4 петля, 2-6 странствий", "recap": "Приключенцы записываются у Ильзы к кураторам, затем идут в Петуха, за ними увязалась Неола, но Маркус её выпроваживает. В ходе разговора оказалось, что Энтони не настоящий, это его двойник, Тони, слуга, выполняющий опасные задания. Он тоже в петле, но только веселится и всё. Друзья хотят его проверяют, затем ведут к Заку, знакомят с остальными, зовут с собой жриц и другого барда, чтобы отомстить бехиру. \n\nВ подземелье легко убивают лозы и червей, бехир показывается из воды, но прячется в логове. Луперы идут за ним, но дракон устроил западню, однако сам попался и умер.\n\nДальше находят пещеру полную грибов, едкого тумана и большого кислотного дерева, которое манит запахом. Почти всех тянет ароматом, но пара удачных заклинаний и его уничтожают, разбивая лагерь прям там.\n\nДобывают ценные ингредиенты с монстров и дерева, по подсчётам это занимает 2.5 дня. Часть ребят возвращается наверх, передаёт информацию друзьям.", "materials": "Рекап от лица Альда", "materials_url": "https://t.me/c/2576013907/293/15116"}'::jsonb),
  (40, '{"session_number": 40, "loop_number": 4, "game_date": "4 петля, 1-7 странствий", "recap": "В 1 день все собираются в поместье Новеда, Лекс и Киллиан пишут для Розы письмо с извинениями, чтобы Зак передал его в Князевы.\n\n5 числа в поместье приходит Аланик и делится новостями, как обещал. Особняк вампиров накрыли, но верхушка сбежала. К расследованию подключены власти. Семью Саймонов пока не трогали. Аланик просит продолжать разведку, чтобы предоставить ему больше данных об ибасанцах - их лагерях и союзниках - в этот или \"следующий\" раз.\n\nВ этот же день команда пошла к Тайвен, у которой было некое задание. Поначалу она удивилась, что вместо 1 помощника пришли 6, и согласилась идти вместе только за 1/4 награды на всех луперов (50 зм). С ними пошли ещё двое крепких ребят - Ворчун и Мямля. Сначала задание шло гладко: попавшаяся на пути слизь оказалась простым испытанием. Но дальше половину команды отключило, Рион открыл разум и вышел на связь с пауками-телепатами. Он призвал союзников отступать, чтобы не провоцировать конфликт. Возможно и часы-то, которые нужно было найти, уже растворены в брюхе слизи. \n\nВ тайне от остальных Рион вернулся в подземелье для переговоров. Он усиленно пытался разобрать образы аренеа, пока на связь не вышла особь, говорящая на человеческом языке. Паучиха бессовестно рылась в его воспоминаниях, а парень старался направлять её в нужное русло. В ходе короткой беседы они поняли, что вторженцы - их общий враг. Паучиха сказала, что ей нужно подумать о сотрудничестве, она свяжется с ним сама позже. Она не готова предоставлять информацию о силах ибасанцев за просто так. \n\nНа следующий день Рион призывает всех расследовать дальше Храм Удачи (уже без Дрюса). Кажется, где-то в его глубине находится сломанный летающий корабль, который он видел в воспоминаниях. Умертвия уже были зачищены, поначалу путь был безопасным, они шли вперед в проеденные лиловыми червями тоннели. Риона направляло магическое чувство, настроенное на судно. Со временем, дойдя до рельс посреди пещеры, внимательные герои ощутили чьё-то присутствие. Вокруг было пусто, Рион применил видение невидимого. Наблюдателем оказался небольшой призрачный дракон, спрятанный на эфирном плане. Он несколько раз попытался овладеть телами путников, напугал Дрипли так, что тот по ощущениям постарел на 20 лет, а после сопротивления героев призвал на помощь 6 призраков с кирками. В этом месте пещеры явно были больше похожи на заброшенную шахту, чем на храм. \n\nРазгорелся трудный бой: магия плохо брала духов, и всё меньше товарищей оставались в рассудке. Сначала дракон сломил волю Лекса, но Янка положила его отскоком цветного шарика, после чего телепортировалась с телом подальше. Потом шахтёры вселились в Риона и Киллиана, запуская их руками огненные шары в соратников. Многочисленные травмы повредили Лексу позвоночник, поэтому он оказался парализован; Дрипли, кажется, получил \"сотрясение мозга\", у него звенело в ушах. Когда все враги по мнению призраков были положены, одержимые тела проследовали дальше в шахты, принимаясь за работу - долбить камень до истощения. \n\nЯнка хотела сдаться, уйти, передохнуть, на её руках лежал практически недееспособный союзник. Но Дрипли вручил ей зелье лечения и уверил, что он ни за что не оставит здесь своих друзей. Помешкав, Янка всё же оставила Лекса, чтобы проследовать за Дрипли, помогла барду наложить иллюзию и призвала для присмотра своего ворона. Дрипли сразил призраков деревянным мечом, напитанным божественной энергией, Янка запустила несколько светлячков, и друзья были спасены. Даже расплывающаяся фигура дракона, грозно приближающаяся к Лексу, не стала помехой. \n\nВ одном из проходов шахты, дальше по пути рельс, виднелся свет. Путники вышли наружу, чтобы отдохнуть и подготовиться к пути обратно. Они перескажут свои приключения дома.", "new_npcs_raw": "🥊 Угольная смерть\nhttps://dnd.su/bestiary/8031-ebondeath/\n\n🥊Призраки\nhttps://dnd.su/bestiary/312-wraith/"}'::jsonb),
  (41, '{"session_number": 41, "loop_number": 4, "game_date": "4 петля, 7-16 странствий", "recap": "В пещере с кислотной ивой Локи при помощи друзей разбирает дерево и монстров гораздо быстрее, и к вечеру 7-го дня уже возвращаются с кучей ингредиентов в поместье Зака. Роза всех провожает в винный погреб, предлагая оставить скраб там, чтобы не портился. Встречают в поместье Каэла, благодарят за продажу зелий без наценки, и видят надвигающегося Лекса, которого донесли с помощью Бальтазара ещё вчера. Друзья выслушивают историю Лекса о сотне призраков, которых они победили, и Альд лечит барда. \n\nТоварищи делятся заклинаниями, рецептами предметов, совместно крафтят и варят, и 8-го дня идут к Савочке продавать ценное. Пока делец ищет покупателя для Меча Дурака, студенты неделю занимаются своими делами, ходят на занятия к кураторам, учатся. Бальтазар заново знакомится со своей группой, брат и сестра озадачены резким изменением своего лидера, когда группа начала фырчать и думать, что Бальтазар размяк, он с помощью внушения заставил Септима улыбаться 8 часов без перерыва, а его сестре сказал \"как закончит — спроси каково ему и не думай, что я расслабился\". Альд следит за здоровьем и душой Оливии, а 13 числа решает проверить Саймона возле морга, тот проходит мимо как и всегда, но на этот раз за ним следит какой-то бродяга, кажется от Аланика. \n\nК 16 числу товарищи решают проверить, кто вскрывает дом Каэла и что там пропадает, так как волшебник до сих пор не узнал этого. План такой: Бальтазар приходит забирать Каэла в бар, в это время Роза и Альд в невидимости попадают в дом, а Локи и Лекс на подхвате со стороны улицы, Локи меняет облик и становится убедительным бомжом (Вдохновение за отыгрыш), а дальше реагируют по ситуации. Все занимают свои места.\n\nДалее уличные видят, как к дому приближаются два незаметных типа, вскрывают дверь и попадают внутрь, Лекс передаёт сообщение Розе, она отправляет гонца Каэлу и бальтазару, они бегут обратно. Лекс и Локи приближаются к дому, Альд только и замечает как воры быстро покидают дом (заняло 12 секунд), и кричит всем, что их нужно остановить. Улица возле дома, воры начинают бежать, сзади Альд и Роза, сбоку Лекс и Локи окружают их, пара запрещённых заклинаний и преступников заводят обратно в дом, не привлекая лишних глаз. \n\nЛоки в образе бомжа очаровывает воров,  и проникает им в голову, копаясь в мыслях. Альд создаёт область истины, начинают допрос дружескую беседу. Выясняется, что воры пришли забрать свиток, который был спрятан в тайнике учителя Каэла (Корбен Даллас не спрашивайте), по наводке их заказчика Любомира Магаша. Товарищи убеждают их показать что в тубусе, взамен они их отпустят, там оказывается свиток хронотургии, который Каэл с Локи определяют как очень сильный. Воры просят их отпустить, но студенты понимают, что они всё расскажут Любомиру, могут быть неприятности. Альд быстро гадает, что если они их отпустят, то это не принесёт крови. На том их со свитком и отпускают. \n\nТоварищи обсуждают, что это было, как поступить дальше, может ли свиток или эксперименты Корбена привести к петле времени, и решают посетить его дом на окраине города. Каэл рассказывает, что учитель пропал пол года назад, оставив записку *Не совершай моих ошибок*. Дом покидал не в спешке, взял нужные вещи, Локи находит книгу по хронотургии с полезными заклинаниями, больше дома ничего не оказалось. В процессе обсуждения мыслей и планов Локи случайно оговаривается *Когда Оливия умерла*. После этого в комментариях начался сущий кошмар.\n\nЛоки немного виновато смотрит на Альда, тот молчит, волшебник показывает иллюзией сцену из морга, как они спасли Оливию, и рассказывает их историю. Лекс и Каэл ведут себя сдержанно, а Бальтазар и Роза реагируют остро - почему товарищи им не рассказали раньше и скрывали это так долго? Альд объясняет, что они хотели рассказать, но не сейчас, и конечно плохо, что они так об этом узнали, они бы рассказали позже, когда настало бы время. Товарищи несогласны, упрекают в том, что не к чему было от них скрывать.\n\nЖрец делится опасениями, не только они умеют возрождать, но сильные мира сего давно это делают, это тайна, и таких людей охраняют и на них также охотятся, если кто-то узнает, что студенты умеют это делать, то их могут поймать, пытать и если будут проводить манипуляции с их душами, то это будет иметь последствия и в следующих петлях, Альд не хочет, чтобы из-за неосторожности он, Карина и Офелия пострадали. Тоже самое с Оливией, поэтому они скрывают её от полиции в поместье Зака, но Локи говорит, что это не обязательно, и продолжается спор, Альда обвиняют в том, что он вообще всё скрывает, ему нельзя верить и подобные вещи, неужели они считают, что союзники такие тупые, что подвергли бы опасности своих товарищей, и вообще они сомневаются, что если кто-то умрёт, то Альд бы возродил их. \n\nАльду надоедает выслушивать обвинения в свой адрес и что-то объяснять и выходит в окно из дома в сторону храма, Лекс его догоняет, чтобы немного успокоить и узнать вообще в порядке он или нет, из-за благодарности за исцеление и помня, как в прошлый раз вообще хоронил жреца. Пока другие остаются, Бальтазар говорит Локи, что ему легко рассуждать, что Альд *купил его молчание возрождением Оливии*, Локи тоже не намерен терпеть обвинения товарищей и догоняет Альда с Лексом, зовя их обратно, оставляя возмущённых в доме с Каэлом. Лекс делится переживаниями, а вдруг есть ещё луперы, и кто-то из них может быть даже злодей, памятуя слова Альда об осторожности, жрец говорит, что может обнаружить нужный след на душе, если нужно, советует Локи подумать об этом. Вспоминают про какого-то Зориана Казински, но никто его не видел и даже не знаком. Жрец со стеклянными глазами что-то вспоминает, создаёт послание со словами *Батак, нужно встретиться, позвольте поговорить с Килаей...* и оставляет товарищей, уходя в одиночестве по своим делам, не реагируя на оклики товарищей.\n\nБальтазар создаёт свои послания и отправляет всем луперам."}'::jsonb),
  (42, '{"session_number": 42, "loop_number": 4, "game_date": "4 петля, 10 странствий", "recap": "На следующий день после столкновения с призрачным драконом в храме удачи, Рион отправил своего фамильяра искать другие подступы к погребенному кораблю с высоты. В конце концов как такая машина могла упасть вглубь пещер, если наверху нет никакого \"кратора\". Но по возвращению Нил только отрицательно каркнул, не найдя ничего подобного (в переводе с птичьего помог Дрюс). Значит, в следующий раз пойдут теми же тоннелями. \n\nБлижайшие дни герои готовились к экспедиции: зелья, зачарованное оружие и пара колец хранения. \nМетаинфа, персонажи не знают: В какой-то момент во время обсуждения планов в поместье Новеда нечто коснулось мыслей луперов. Они определённо прочитали мысли Янки, но девушка этого даже не заметила\n\nУтром 10 дня Уини, Зак, Дрюс, Рион, Дрипли, Янка и Тонни выдвинулись. Больше людей - больше шансов, что они не окажутся на волоске от смерти. Уже в тоннелях впереди всех вела Уини, имеющая природное чутье на всякого рода нечисть. Именно она заметила эфирного дракона, возвышающегося над подземной водой. Янка дала команду заранее призванному Альбусу взять маленькое колечко и издать самое обнадеживающее карканье, которое он только сможет, а Уини попросила поддержки у своего крабика Бриньольфа, после чего спрятала его обратно под доспех (защита от добра и зла). Зак мысленно обратился к флакончику с кровью, созданному Локи, и произнёс нечто похожее на молитву, после чего вокруг него закрутились несколько маленьких крылатых сфер.\n\nВ подземелье раздался истошный рёв, призрачный дракон показал себя, но тут же скрылся в каменном своде. Героев окружили знакомые фигуры шахтёров, медленно подходящие ближе и пугающие своим обличьем. Первым захватили Никандра, убежавшего в небольшой закуток к одному из призраков. За ним выдвинулся Дрюс и в диком порыве исцарал когтями доспех товарища. К сожалению, друиду не хватило силы духа, и он оказался под контролем второго приведения. Тонни побежал к одержимым товарищам и завёл мелодию, очаровывающую Дрюса, и на несколько секунд это даже сработало. \n\nТем временем по основному тоннелю гулял электрический шарик Янки, рядом с Заком призраков прожигали стражи, а Уини не жалела божественной энергии, рассекая нежить мечом. Внезапно узкий проход поглотил сильный жар, а поворот к Нику, Дрюсу и Тонни перекрыла огненная завеса. Пламя огненной стены и последующие огненные шары выкосили несколько призраков, но и задели союзников, Дрипли растекся по полу. \n\nНа той стороне огня одержимому Никандру не понравилась ни музыка Тонни, ни кубик, отражающий причудливые узоры на стенах, и он замахнулся несколько раз молотом, отталкивая барда глубже, а потом влетел в него с разбега. Тонни чуть не размазало, он уже еле стоял на ногах. Благо хотя бы пламя расступилось - друид засмотрелся на гипнотический узор. Тут же из-за тоннеля полетели снаряды от Риона, Зака и одна мощная молния от Янки, прожигающая одержимых. Исход для призраков был предрешен. Бой закончила яркая вспышка света, исходящая от длинного лезвия паладинского меча и рассекающая призрачный силуэт дракона на две части. \n\nГерои устроили привал. Тонни пел песни возле костра, рассказывающие о жизни Энтони, Дрюс в это время с любопытством осматривал ящики, оставленные в пещере (и вовремя выдернул руку из пасти мимика), а Рион отправил фамильяра дальше на разведку. Постепенно грубый камень под телом змейки снова сменился на кладку, Нил встретил взглядом грузную фигуру бледно-серого монстра с тонкими вытянутыми руками, тоскливым выражением лица и черными глазницами, из которых как будто сочились слезы. Фамильяр тут же скрылся обратно в карманное измерение, а путники закончили приключение на сегодня."}'::jsonb),
  (43, '{"session_number": 43, "loop_number": 4, "game_date": "4 петля, 10-11 странствий", "recap": "Студенты ходят на занятия, свободное время проводят в поместье Новеда, готовя зелья и артефакты. 10 числа с вылазки из Храма Удачи возвращаются ребята, Уини говорит, что место проклятое и там много призраков, Янка наседает на Альда, что нужно там всё освятить, жрец не уверен что их сил хватит и нужно заклинание Святилище 5-го круга, и ему приходится обратиться к помощи Батака. Альд снова рассказывает наставнику про петлю, используя пароль и знания с прошлых раз, и Батак готов бы помочь, но не может тратить 24 часа на наложение, из-за своих обязанностей. Тогда ребята идут к Савочке, он может достать свиток, за пару часов, но за 3300. \n\nСтуденты решают, что сдюжат так, покупают у Каэла зелья, и на 11 день выступают в сторону Храма в обход не через мост, на пол пути на них нападают пауки, но студенты их разносят на ингредиенты. Добираются до запасного входа в храм с рельсами на земле. Уини и Янка предупреждают и напоминают, что возле воды появлялся тот призрачный дракон, разведка фамильярами ничего не дала, и товарищи решают не идти прямо, а свернуть вправо, в сторону *где должен быть какой-то корабль*. Дракон и призраки не появились, и Уини чувствует как проклятье остаётся позади, когда они выходят к новой кладке в храме, где Рион видел каких-то тварей. \n\nПроходят вглубь, и встречают Одиноких - существ тронутых планом теней, который высасывают эмоции, у них длинные руки, которыми они протыкают жертв как копьями и притягивают к себе. Маркуса и Уини протыкают, но Туманный и Громовой шаг решают проблему, Офелия всех лечит, Тонни контролирует Гипнотическим узором, Янка кидает Шарики, а Анарион поливает Огнём, а Карина бьёт Звуком. Победа. Передохнув час они двигаются дальше. \n\nТёмный коридор, в котором ребята провоцируют Сигнал тревоги, они быстро прячутся в тень, а в конце тоннеля в свете факелов виднеется чужой фамильяр, он замечает Маркуса, и тот выходит вперёд на свет, товарищи осторожно следуют за ним, Церебро Офелии сквозь стену замечает картину: гигантская пропасть, через которую ведёт каменный мост, в середине которого образован небольшой круг, на котором стоят 4 воина, а на той стороне пропасти ещё две фигуры магов. Маркус, вышедший вперёд рассказывает, что они студенты, просто нашли это место, и хотят пройти дальше, но его обыскивают, отбирают зелье и оружие (хы), приводят в круг и говорят, давайте мы вам сотрём память и мы вас отпустим. \n\nМаркус против, разбивает зелье и начинается драка. Воины щитами пытаются сбить монаха, но он крутится и даёт им в ответ по щам, но они стоят. Анарион, Тонни и Офелия мгновенно кидают в них Опутывание, Замедление и Огненный шар, но видят как заклинания опадают натыкаясь на невидимую преграду - область антимагии. Уинифред выдвигается на помощь Маркусу, Карина создаёт над всем мостом Призыв Молнии и бьёт в дальних магов. Воины не могут сбросить Маркуса вниз, монах выбегает из круга навстречу магам, но один создаёт Длань Бигби и сбрасывает его вниз. Бляяяяяяяяяя.... и стук тела о дно пропасти, но Монах встаёт. \n\nВ это время Анарион Дребезгами ломает первую часть моста, а Карина Молнией ломает противоположную, камень рушится вместе с одним магом, мгновение и круг в центре упадёт.. но он висит в воздухе недвижно, Офелия выходит вперёд, чтобы Развеять магию купола, но её Дланью тоже скидывают вниз. Бляяяяяяяя... и стук тела о дно пропасти, но Жрица встаёт. Маркус начал бег, но врезается в мягкую, чешуйчатую стену, которая начинает клокотать и шевелиться. Янка кричит, что возможно они живы, и Карине прилетает Послание от Офелии «Я жива. Ищу Маркуса. Здесь лиловые твари. Падайте, исцелю. Прорвёмся где-то здесь, надеюсь».\n\nКарина хватает спящего под Гипнотическим узором Тонни, кричит товарищам «Да пошло оно всё в бездну», бежит к пропасти и прыгает вниз, вместе с Уини и Анарионом, Янка в последним миг создаёт Падение пёрышком, а враги произносят «Отлично, покормим барбосиков».", "new_npcs_raw": "🥊 Одинокий - 7\n\n🥊 Маг-законник - 2", "materials": "Мысли Карины\n\nМысли Янки\n\nМысли Тонни", "materials_url": "https://t.me/c/2576013907/1762/16968"}'::jsonb),
  (44, '{"session_number": 44, "loop_number": 4, "game_date": "4 петля, 11 странствий", "recap": "Друзья оказываются в неприятной ситуации - Маркус, упавший на дно ущелья с 500 футов выжил, но был сразу проглочен лиловым червём, Офелия тоже поднимается там же в окружении двух монстров, Анарион, Карина, Тони, Уини и Янка прыгают во мрак пропасти спасти товарищей, о судьбе которых ничего не знают. \n\nЖрица создаёт на дне Дневной свет и видит что она в западне, Маркуса нигде нет, и один из червей её тоже глотает, пока друзья не останавливаются от падения благодаря Падению пёрышком от Янки. Товарищи сами оказываются в окружении двух голодных тварей, пара мгновений, жирная туша бьёт по Уини, та падает, Карине тоже крепко достаётся, но она устояла, а вот Тонни не повезло - второй червь его тоже проглатывает, и внутри желудка он натыкается на недвижимое тело Маркуса.\n\nХаос, но герои собрались, Карина лечит Уини, её из под носа червя на Громовом шаге уносит Янка, Анарион запрыгивает на голову червя, тот вместе с ним ныряет в темноту глубокого провала, но чародей бежит по его горбу, остаётся на ногах, из под острых зубов монстра спасаются Звёздными и Туманными шагами. А Тонни внутри червя создаёт Переносящую дверь и с Маркусом оказывается снаружи червя, Офелия внутри другого монстра призывает фамильяра и лечит себя изо всех сил, чтобы не перевариться. Исцелённый Маркус кричит всем бежать, помогает друзьям добраться до входа в тоннель, а сам продолжает защищать товарищей впереди всех, Уини с Мечом Дурака наперевес рядом, Анарион и Янка успели забежать внутрь. \n\nТонни, бежавший первый, вдруг тормозит, играет на лютне, подкрепляя Очарованием чудовища, и один червь с Офелией внутри неожиданно перестаёт нападать, ложится на брюхо как ручной, но на команды не поддаётся. Секунды замешательства, товарищи оборачиваются на пение и атакуют второго надвигающегося червя, но ему хоть бы хны. Карина не собирается убегать без подруги и кричит Тонни *Живо залазь внутрь червя и достань оттуда Офелию, иначе я тебя сама сожру*, но бард всё же не сумасшедший, не реагируя на угрозу продолжает играть и помогает товарищам остротами *Червь в моих штанах больше, чем ты с твоей мамкой вместе взятые*. В этот момент лисичка показала мордочку, Офелия меняясь с ней местами оказывается снаружи червя, Янка кричит всем бежать, и товарищи оказываются у входа в тоннель. \n\nВ последний момент второй червь успевает снова проглотить Маркуса, товарищи почти на издыхании без магических сил, но монах сам пробивает себе путь на свободу, выбираясь из клоаки монстра. Карина создаёт Маяк надежды, Офелия всех исцеляет, и студенты успешно избегают зубов червя, убегая вверх по тёмному тоннелю. Добегая до верха товарищи понимают, что они оказываются где-то на уровне моста, с которого они спрыгнули, и там ждут те же враги. Офелия использует Порошок исчезновения, вся команда становится невидимой, и без происшествий убегает из злачного места, прямиком к выходу через катакомбы старого храма. Анарион напоследок впитывает сырую ману, чтобы перекрыть преследователям отход, и получает очередную мутацию, подзатыльник от Карины и причитания от Янки.\n\nТоварищи решают передохнуть, в поместье Зака все купаются в бассейне, кроме Анариона, зато присоединяется Никандр, предлагая соревнование по задержке дыхания, победил неожиданно пришедший Бальтазар. Карина всех агитирует вернуться в храм, пока враги за ними сами не пришли, но её успокаивают и все решают пойти той же компанией в рыбный ресторан, отдохнуть и развеяться. Пока Офелия и Анарион демонстрируют владение этикетом, Маркус и Карина как деревенщины смеются с затейливых названий блюд. Друзья мило беседуют, Янка себя плохо чувствует из-за флешбеков с некромантами, и уходит в туалет, Карина её догоняет и немного успокаивает, даря амулет защиты от прорицания и рассказывая сальные моряцкие анекдоты. Вернувшись за стол, чтобы Янка не волновалась, жрица дополнительно касается её и накладывает Защиту от смерти, добавляя что-то вроде *Все мы смертны*, за эту фразу цепляется Маркус, но остальным вида не подаёт. \n\nИ волки сыты, и овцы целы."}'::jsonb),
  (45, '{"session_number": 45, "loop_number": 4, "game_date": "4 петля, 16 странствий", "recap": "Вечером, после Послания от Бальтазара, Анарион, Бальтазар, Каэл, Лекс и Роза идут в поместье Зака, встретиться с ребятами. \nТам уже Зак, Янка в комнате, Карина с Офелией готовят пирог, Оливия просит Локи денег, тот ненадолго отлучается, в этот момент в поместье врываются Роза и Бальтазар. (после этого в комментариях начался сущий кошмар). \n\nФабула: Роза и Бальтазар активно и пассивно агрессивно пытаются выяснить, почему шесть луперов объединились между собой, скрывая от остальных секрет Возрождения. Достаётся всем, Бальтазар сдержано обвиняет Офелию, Роза же в истеричной манере поносит Карину на чём свет стоит, хулит Офелию, оскорбляет Янку и даже унижает Оливию. Возвращается Локи, новая порция вони летит в его сторону, Лекс вразумительно резюмирует, почему они так недовольны, но всё тонет в потоке ругани.\n\nСитуация накаляется, когда Анарион услышав про Возрождение выходит из комнаты в окно, ворвавшийся в поместье Маркус на выходе встречает Бальтазара и прописывает ему в ебало, Карина что-то кричит вдогонку уходящей в гневе Розе, но та оборачивается, Локи просит не обижать Оливию, но девушка и сама не лыком шита говорит *Вы никакая не команда, со стороны вообще не похоже, что вы вообще способны работать вместе*. Шум, гам, моча съела говно. Так или иначе все стрелки полетели в отсутствующего Альда.\n\nВсе выговорились, выплеснув эмоции, Роза успокоилась, но попутно всё же не упуская возможности задеть колкостями. Жрицы рассказывают суть заклинания, что невозможно возродить кого угодно, типа погибших родственников или няню Розы, потому что нужны особые условия. Карина достаёт пирог, Анарион возвращается с пиццей, и пьяный рассказывает товарищам, что раз они не хранят тайны, то вот с ним связались пауки, как и рассказывал Рион. Акцент разговора плавно перетекает к этому, Локи подтверждает, что чувствовал, как его разума коснулась телепатическая сила, и кольцо защиты разума не помогает. \n\nАнарион продолжает: пауки предложили обмен - они рассказывают луперам некую полезную информацию, которая им поможет в борьбе с врагами, а луперы *впустят пауков в петлю*. Никто ничего не понял, как это возможно, Анарион невнятно продолжает, что пауки внедрятся в память луперов и каким-то образом смогут извлечь воспоминания из петли, хотя сами пауки забывают о событиях, но что-то прочитали в отголосках Анариона, Локи, Риона и бог ещё знает кого (всех). Локи подтверждает и товарищи судорожно думают, что им делать. Решают не соглашаться, дождаться следующей петли, чтобы пауки снова всё забыли и потом к ним не лезть, пока не поймут как защитить разум. \n\nА Локи вспоминает, что их одноклассница Тинами Аопэ увлекается фазовыми пауками, и просила найти питомца, можно через неё что-то узнать. Тут в поместью подъезжает карета, в дверях стоит Джорнак Докочин адвокат из прошлой петли, приглашает поимённо тех, кто был в Храме удачи с лиловыми червями (игры 43-44). Карина и Янка на измене - их нашли и снова хотят убить, Локи, Офелия и Лекс подозреваки но без паники, Маркус с Анарионом и Розой (почему-то) очень хотят пойти. Товарищи это обсуждают, и решают завтра решить этот вопрос.\n\nКарина и Офелия снимают проклятия с Лекса, Анариона, Маркуса и Каэла (у кого что было не помню), но Каэл независимо от этого сопоставляет свиток заклинания, который украли из его лавки с жестоким убийством визиря Суламнона, разорванного пополам. Все вспоминают про некромантов, проводят параллели с политическими подоплёками, объявление войны, нападение лича и т.д. Офелия ещё раз упоминает портал в пещерах под Сиорией, и что скорее всего второй такой где-то на севере.\n\nЛекс накидывает массу вариантов, как пробраться в стан врага шпионами, каждое следующее бредовее другого, но в конце блеснула идея - каждый из луперов попробует завербоваться к некромантам разным путём: кто-то в виде тролля, другой попытается прыгнуть через портал, третий притворится волком, пауком, крысой и т.д. \n\nИ все расходятся по комнатам/общежитиям/квартирам обдумать всё, о чём говорили вечером."}'::jsonb),
  (46, '{"session_number": 46, "loop_number": 4, "game_date": "4 петля, 12-13 странствий", "recap": "Группа идёт на задание - помощь, от которой позднее отказались. Нужно проверить, так как деревня поставляет полезные грибы.\nНа подъезде к деревне видят странное: голая женщина загорает, дальше в огороде ещё один голый мужчина, на мосту дети (одетые) бросают в воду удочки. Вайб спокойствия психушки, люди приветливые, не замечают за собой кринжа.\n\nПока Дрюс щемится к голой, останавливаемый Уини, Рион с помощью Нашествия проверяет свою теорию, а также сканирует магию, но ничего, Уини тоже не чувствует зла. Огородник кричит ему «Бей саранчу», Дрюс загораживает голому мужику солнце, а потом отражает лучи своей лысиной (маскировка). Дрипли учит детей рыбачить, Рион читает мысли, те думают на странном языке. Дрюс говорит с огородом, но без пользы. Из-за странностей ребята подозревают внушение или подмену, жители ведут себя как друзья растений. Фрэд зовёт всех к старосте, Янка, Фрэд и Уини выпивают зелье, на всякий. День приятный, деревенский уют.\n\nСтароста Ранвальд с сыном врут о каких-то волках. Рион ощущает, что местным диктуют мысли, следов магии нет, но в воспоминаниях есть некое «рождение» из кокона, вид с холма. Группе предлагают заночевать в пустом доме, на полу которого следы ногтей, а еда внутри сгнила. Милош, голый охотник, делится вяленым мясом (спас тела). Не ждут ночи, идут к холму, пока солнце садится, спокойный вечер.\n\nОбычный лес с широкой тропой, трое идут в невидимости, трое впереди замечают мальчика. Ему говорят идти домой, но тот пытается тихо преследовать героев. Малец слышит лязг лат невидимой Уини, Дрипли разыгрывает, как будто бьют его, попадая мечом себе по голове со словами «Беги, я проигрываю». Янка вторит, шкет уходит. \n\nВ низине рядом с холмом лежит та же голая и лысая девушка Оля, в пошлой позе под лучами закатного солнца. Фред идёт к ней, его заманивают в грот подальше от чужих глаз, но Дрипли и Янка следуют за ним, прячась. Рион идёт вперёд, на холме видит Милоша, на вершине большой цветок. \n\nОля тянется к Фрэду, крепко хватая, Риона пытается схватить мужик, делая вид, что споткнулся. Перед ними мясистый бутон тропического цветка, выглядит жутко. Внизу холма к Фрэду тянется лоза, Янка и Дрипли реагируют. Уини влетает на холм, бьёт растение критом (74 урона), из бутона выпадает другая голая женщина.\nРион читает в мыслях цветка «Помоги», Фрэд кидает Копьё, оглушая растение, Рион кричит: «Не убивайте, оно говорит со мной». Но Дрюс, не видя тело жертвы, Огненной стеной прожигает и цветок, и девушку. Рион, копаясь в мыслях Милоша, видит: разочарование, страх, планы сорваны, убита высшая форма жизни, а глубже - боль и ужас от переваривания в коконе, староста тащит его под руки на холм.\n\nДрузья стоят перед телом, Фред и Рион хотят его вскрыть, Дрипли, Янка и Уини против, а Дрюс в облике медведя уже копает могилу. Девушку хоронят, пока цветок разбирают на ингредиенты. «Ну больные» - говорит голый мужик и уходит. Вернувшись в деревню, герои замечают, что люди такие же странные, но с обычными мыслями. \n\nОстаются на ночь, Рион в патруле будит Фреда, чтобы раскопать труп. Янка замечает, как парни уходят, будит всех. В чужих окнах видят, что люди спят лицом в пол. \n\nРезультаты вскрытия: тело в кислоте, было в коконе 5 часов, изменений нет, всё обычное. Трансформация и ментальный контроль должны были бы прекратиться, может изменение разума. Дрюс забирает образец корня, говорит с травой, и выясняет, что двое местных вели насильно Марину «Успокойся, всё будет хорошо» (она же «Уехала жить в город» по словам старейшины; в её доме ночуют). \n\nНа след день Милош оделся, потому что «Нет солнца». Область истины и запугивание не дали результатов, староста грозится стражей из Сиории. Рион, копаясь в голове старосты, находит воспоминание: его затянуло внутрь растения, когда тот гулял на вершине холма, обнаружив новый цветок, неделю назад примерно. Ребята понимают, что они опоздали и не могут помочь местным, к тому же те к ним уже враждебно настроены. Студенты покидают деревню в надежде помочь в следующий раз.", "new_npcs_raw": "Ранвальд - староста деревни (есть сын)\n\nМилош - охотник \n\nМарина - девушка, которая \"уехала в город\" (скорее всего была схвачена трупоцветом недавно)"}'::jsonb),
  (47, '{"session_number": 47, "loop_number": 4, "game_date": "4 петля, 17 странствий", "recap": "Утром приходят к Джорнаку, внутрь заходят все, кроме Янки, вместо неё Роза. Адвокат даёт подписать документ о неразглашении, мрази из Храма Удачи заплатят 100 золотых каждому, кто будет молчать об увиденном. Студенты ломаются, поднимая сумму до 200, и подписывают, Локи тоже. На них по очереди накладывают Обет (длина год), Янка вместо Розы возвращается в маскировке, потому что проверяют личность. Позже в банке можно забрать деньги. \n\nДнём в поместье обсуждают Обет, позже снимут его, а пока Карина проверяет, пробует сказать Заку про что-то, и её бьёт психикой. Друзья думают, что делать дальше, найти паука или пойти на задание, но Локи спрашивает, знает ли кто Изгнание (https://dnd.su/spells/116-banishment/), Карина кивает, и плут предлагает использовать на нём, так как он родом с другого плана. Дрипли не хочет отпускать друга, Карина думает что опасно, в спор подключается Оливия и просит их отправить. \n\nКарина создаёт Розе в кольцо Изгнание, одновременно кастуют на пару, те с хлопком пропадают. Секунды тишины, но для ребят всё проходит не очень, они встречают нечто за пределом эфира. Карина отправляет Послание Оливии, но та не отвечает, и жрица оканчивает Изгнание, тело Оливии возвращается в гостиную, её лечит Дрипли зельем, та лепечет про *Глаза*, и Роза возвращает Локи. Но вместо него в гостиной оказывается монстр и истошно вопит на всё поместье. \n\nМиг, и в монстра летит кулак Маркуса, оглушая его, друзья быстро решают, что это может быть вернулся Локи, как и Оливия, но с ним что-то не так. Дрипли вливает зелье, Карина пробует исцелить, но только хуже, Янка готовится атаковать, Роза хватает верёвку. Маркус хочет оглушить монстра, но случайно (?) его убивает, и тот превращается в Локи, только синего цвета с красными глазами. Оливия кричит, Янка бросается к Локи, Карина пробует остановить процесс умирания, но поздно, тогда она накладывает Нетленные останки и смотрит на ребят вокруг. \n\nДействовать приходится быстро, пока Маркус, Дрипли и Карина спорят, как надо поступить, Роза тремя верёвками сматывает Локи, Дрипли пробует Опознание, Локи кажется чист, но подозревают сырую ману, Карина на панике начинает кидаться заклинаниями раз, два, три, но снимает Останки, кричит Офелию, но подруга не здесь, Оливия умоляет его возродить, и Карине приходится самой делать. Посмертие, ковёр из облаков, и ночное звёздное небо, Карина видит Локи, который оторвался от облаков, хватает его и опускает вниз. Локи просыпается. \n\nОливия и Янка бросаются на Локи, Карина в шоке лечит его, Роза и Маркус наблюдают. Проверяют вменяемость Локи, режут верёвки, лечат и спрашивают что было. Тот создаёт огромную иллюзию тысячи глаз на потолке гостиной, Дрипли что-то вспоминает из сказок, про первородное существо Панаксет и бросает фразу *форма опасной слизи с глазами*, и в этот момент Янка неожиданно для всех телепортируется в окно. Маркус следом за ней, даже успевает заметить как та прячется в кустах, но следом вылетает Капля, её видит Янка, и та на Громовом шаге улетает дальше. \n\nКарина удерживает Маркуса, пытавшегося удержать Янку, но монах освобождается и начинается спор, почему и кто решает, что он знает лучше что нужно другим. Янка в невидимости уже убежала далеко, Дрипли пытается её догнать, Маркус возвращается к погоне. В комнату входит Офелия, спрашивает что у вас происходит, но внятного ответа нет, кроме того, что Карина рассказывает подруге про возрождение Локи. \n\nЯнка добегает до края города, начинает плакать, пока Маркус прибегает к ней домой и прячется, а Дрипли тем временем взбаламучивают Лань, но убегает дальше искать Янку. Карина отправляет Послание Янке, та отвечает что-то странное про опасность Дрипли. Роза создаёт серию Гонцов, монах через Послание из свитка узнаёт, что Янка где-то на ЖД, через время находит её. Проникновенная беседа, но Янка всё же убегает дальше. Роза приглашает её к себе домой.\n\nВ поместье ребята пьют вино, обсуждают произошедшее, жрицы делятся деталями своих возрождений, Офелия покатывает к Заку и тот зовёт её на свидание. Все живы, но не все здоровы."}'::jsonb),
  (48, '{"session_number": 48, "loop_number": 4, "game_date": "4 петля, 18 странствий", "recap": "Поместье, Зак готовится к свиданию, Лекс подсказывает что лучше надеть, как себя вести и куда пойти, чародей идёт до дома Офелии, встречает жрицу и идут в ресторан. Карина отправляет подруге Послание «Удачи». За ними в Невидимости наблюдают Роза и Лекс, даже занимают столик вдалеке. Свидание проходит спокойно, парочка просто узнаёт друг друга получше. Роза тем временем предлагает Лексу какую-то схему, как обманом завладеть имуществом «невесты Лекса», но тот даже не знает где она до бала летнего фестиваля. \n\nКарина на занятиях привязывает фамильяра Куклю и показывает её товарищам. Все собираются, хотят продолжить спуск в подземелье, дальше за пещерой Ивы. Карина покупает новый бриллиант, так как прошлый потратили на возрождение Локи, у Каэла покупают зелья, и готовые идут, перед этим наложив на каждого Защиту от смерти. Жрицы сплетничают, Офелия рассказывает, что Зак вёл себя прилично, без кринжа.\n\nДо пещеры доходят без происшествий, небольшие разломы в полу подземелья, фамильяры обнаруживают впереди хилый каменный мост, через который лучше идти по одному. Неожиданно на пути становится харизматичный гоблин, приказывая группе «поворачивать назад или платить за проход, но сначала нужно отгадать загадку» - гоблин в розовом колпаке и плаще сует руку в карман и спрашивает – «Что это у меня в руке?! Три попытки!»\n\nОбескураженные товарищи начинают отвечать, в этот момент к Офелии сзади подкрадывается другой гоблин, пытаясь стащить её пояс. Тут Каэл выдаёт третий неправильный ответ, гоблин вытягивает руку и кричит – «А вот что», – и кидает в ребят три ореховые скорлупки, создавая Смятение. \n\nОфелия, Зак, Анарион, Каэл, сконфужены, жрица замерла, чародеи бьют друг друга рапирами, а Каэл размахивает книгой заклинаний. Лекс отступает от них, рядом Карина создает Маяк надежды. В это время тут и так их атакуют сбоку и сверху. Все успешно освобождаются от чар, Каэл прыгает к одним гоблинам наверх, Офелия разряжает в гоблина Волшебные стрелы, но тот мистически пропадает. Невидимая сила хватает Анариона и сбрасывает в щель с высоты 100 футов. \n\nКарина создает Дневной свет, и все видят гоблинов тут и там. Лекс выводит двоих Гипнотическим узором, Каэл сражается ещё с парой наверху, Офелия выходит вперед, доставая дорогую заколку из волос для заклинания, но неожиданно падает на колени и начинает молиться гоблину. Пока Анарион карабкается вверх из расщелины, Зак создает Духовные стражи и защищает жрицу, а у Каэла крадут плащ и книгу заклинаний. \n\nКаэл загадывает гоблину заумную загадку, и тот немного думает, а потом в ребят опять летит Смятение. Зак выпускает в гоблина мистические заряды, но тот как будто неуязвимый. Карина видит, что Офелия явно делала нечто странное, решает подбежать к гоблину, вытягивая впереди бриллиант:\n\n– Возьми плату и пропусти нас, пожалуйста!\n– О, отличное подношение, ребята, всем отбой! \n– И вы не будете нападать?\n– Кланяйся, ахаха, тогда посмотрим!\n– О Великий, - Карина нарочито торжественно кланяется, но запинается, – Как к вам обращаться, о могущественный!?\n– Нилбог, ахахаха! \n\nВ ходе краткой беседы, пока Карина просит их просто пропустить, Анарион лезет на верх, и в жопу гоблинам кидает Огненный Шар, Каэл уговором и Внушением возвращает вещи, а неугомонный Зак хочет мести. Так или иначе, Нилбог дарит Карине колокольчик, кричит «Догоняйте» и бесследно исчезает вместе со своей бандой.\n\nЗак носится по пещере несколько минут, спрашивая «Какого хрена вы творите» явно требуя крови гоблинов, пока ребята исследуют пещеру дальше, в ней проход к скоплению паутины и пауков. Враги замечают разведку фамильярами, прячутся, но студенты стоя в проходе поливают всё огнём, пауки вылезают, одни стреляют, другие умеют колдовать, но с помощью пары огненных шаров, дребезг, искусных острот и лечения ребята быстро зачищают пещеру, находя ценные вещи и ингредиенты.\n\nНемного отдохнув, товарищи возвращаются тем же путём, не встретив гоблинов или других врагов, потеряв заколку, бриллиант и немного достоинства.", "new_npcs_raw": "🥊 Нилбог\nhttps://dnd.su/multiverse/bestiary/6883-nilbog/\n\n🥊 Хитины\nhttps://dnd.su/multiverse/bestiary/6494-chitine/\n\n🥊 Холдриты\nhttps://dnd.su/multiverse/bestiary/6496-choldrith/"}'::jsonb),
  (49, '{"session_number": 49, "loop_number": 4, "game_date": "4 петля, 19 странствий", "recap": "Поместье, Локи с Заком вайбят, Лекс пишет книгу, Карина тренируется с Куклей, замечает в окне Альбуса и ворон. Жрица вспоминает, что Янка говорила про Дрипли, и начинается обсуждение «Что значит Дрипли злой?». Общее негодование, что это сказала Янка, которая с Дрипли «Не разлей вода (слизь)», полагают, раз она много с ним была, то что-то узнала, но рассказать не успела. \n\nВспоминают про Панаксета, Локи говорит, что нужно бы допросить Лайонела в облике Хаслуша, что он сделал с Дрипли и как его создал. Зак предлагает убить Дрипли, чтобы при Возрождении посмотреть на его душу.. Тут приходит Дрипли, товарищи делятся, что Янка его избегает, спрашивают что он сделал, но тот не при делах, даже соглашается на Область истины, но ребята верят так. И в этот момент в кармане Карины звенит колокольчик Нилбога.\n\nРебята на измене, за ними следят? Обнаружение магии фиксирует невидимую руку, но никого, Дрипли пробует Опознание на колокольчик, но ничего. Зак просит выбросить эту дрянь, вернуться и отомстить Нилбогу, тогда *зелёные* вспоминают миф про бога трикстера, который делает одержимым. Карина отправляет Послание Уинифред, та после слов «Нужна помощь со злым духом» бежит в поместье. Советуются, что отправить Посланием Нилбогу, Лекс предлагает «Нам понравились твои загадки, придём в гости, повеселимся», но ответа нет, только с издёвкой звенит колокольчик и его прячут в свинцовый сундук.\n\nПрозодя подземный путь до середины, герои натыкаются на стаю мозговых крыс, противясь чтенью дум во тьме долины. В крыс тут же летит море магических зарядов. Лекс не воодушевлён, друзья говорят, что это не случайно, натыкались на них в первый день, вдруг слежка от врагов. Дрипли собирает ингредиенты. Пустив фамильяров вперёд, но не дойдя до злополучного моста гоблинов, группа натыкается на 4-ёх троллей и 2 магов.\n\nУини и Зак встречают угрозу в лоб, тролли загораживают проход, и в ребят летит Облако Смерти, задевая тяжело бронированных и Лекса с Дрипли. Уини чувствует, как её фамильяр умирает и «возле сердца становится пусто». Локи, стоящий позади, Развеивает облако, а Карина кидает Дребезги в троллей. Зак создаёт Духовных стражей, Дрипли кидает кучу склянок, и одного некроманта просто разъедает, а Уини от потери Бриньольфа разрубает одного тролля пополам. Лекс создаёт Замедление, и жирные туши уже не страшны. \n\nОдин некромант лечит другого, но почти сразу в них летит Огненный шар, один опять падает. Зак и Уини сдерживают троллей, а второй некромант далеко телепортируется, Лекс отправляется в погоню, пока товарищи добивают врагов. Перед носом барда появляется каменная стена, но тот её Развеивает, некромант кричит «Да кто вы такие!?», и Лекс называет своё полное имя, тогда враг падает на пол и пропадает. Остальные тоже бегут за ними, пока Карина накладывает на мёртвого Нетленные останки. Лекс указывает на пол, Уини бьёт мечом, но пусто, Локи говорит, что это Слияние с камнем, и он там. Лекс кидает бусину силы, Дрипли кислоту, но в объёме камня никого нет.\n\nГруппа понимает, что он сбежал, и решает допросить труп некроманта. Локи принимает облик его союзника и начинает Разговор с мёртвым:\n- Куда забрать твоё тело? - В лагерь\n- Кто из начальников даст взбучку? - Альберт \n- Куда отнести твои запасы, где схрон? - У меня дома под порогом\n- Как думаешь, что задумал лич? - Нас тут бросят\n- Если хочешь ожить, скажи, где схрон? - В подземельях\n\nЗак предлагает его Возродить и допрашивать живым, но монеты уже спали с глаз, да и Карина не соглашалась. Понимая, что по имени Лекса враги выйдут на них и поместье Зака, ребята решают предупредить товарищей. Собирают ингредиенты и отдыхают. Зак агитирует бить Нилбога.\n\n... пропуск, вдруг пойдём дальше\n\nНа поверхности студенты с помощью Йотуна проверили порог и подвалы особняка, где скрывались вампиры дома Золтан, без результатов. Стало известно что Аланик оставил наблюдателей за домом. Карина и Локи думают, где скрыться до конца петли, Зак и Уини готовы встречать некромантов в поместье, Лекс кажется вообще не понял, что сделал не так. Дрипли просит помочь с созданием камня слизи, но всем не до этого. Где-то возле поместья кружит Альбус."}'::jsonb),
  (50, '{"session_number": 50, "loop_number": 4, "game_date": "4 петля, 19 странствий", "recap": "Никандр, Роза, Бальтазар и Анарион встречаются в Петухе. Ник рассказывает, что последние несколько дней провёл в больнице после неудачного боя, а Бальтазар - в запое. За пивом и чем покрепче герои узнают друг друга немного получше (и про личную жизнь Офелии тоже). Настроение «надраться и подраться»: Бальтазар раздает амулеты пьяницы, Ник взваливает на себя бочок пива, и все отправляются за заданием в Академию. Для подстраховки Роза так же просит у Карины вложить в кольцо Возрождение. Охота на браконьеров началась. \n\nРебят вводит в курс дела рослый лесник по имени Хагрид. Браконьеры охотятся на опасных цеповых улиток с антимагическими раковинами (их свойства используют для щитов от заклинаний) и на штормовых оленей. Обоих зверей можно заметить свысока, у улиток есть своё логово в одной из пещер. Лицензия на добычу таких ценных животных стоит 20 тысяч по прикидкам лесника. \n\nРион ведёт группу по более-менее безопасным тропкам, Бальтазар с высоты полёта бабочки высматривает охотников или их добычу. Когда бард понимает, что сосредоточить своё внимание у него сегодня не получается, на Вельзевула садится Роза. Она сразу же замечает вдали летающий ковёр с предполагаемыми браконьерами. Она им машет, но, кажется, её не видят в ответ. По крайней мере теперь они знают примерное направление. Спустя одну неловкую встречу с диким лосем и такое же неловкое падение с дерева (Анарион), ребята достигают домика в чаще, первым подлетает Бальтазар. Отправив Розе послание о том, что ковёр сел там,  где его видела колдунья, Бальтазар постучал внутрь. Жильцы дома пригласили Бальтазара войти, и тот рассказал им историю, мол, его дядька послал искать каких-то улиток, а сам он в этом ничего не понимает. Трое мужчин приглашают его к столу, но говорят, что никаких улиток они не видели, возможно стоит поискать под ногами. Бард платит за еду песней, и один из охотников, Милош, очень проникается исполнением. Бальтазар кажется ему чертовски славным парнем и он даже предлагает друзьям помочь тому с поиском улиток.\n\nВ это время остальная компания сама находит такую улитку. Роза считает, что тратить время на охоту, ещё и нелегальную, сейчас незачем, и бежит дальше к Бальтазару. Рион, Анарион и Ник пробуют победить грозную улитку. Однако дребезги Анариона лишь поглощаются панцирем и обдают всех, кто стоит рядом, болезненным свечением. Нашествие насекомых Риона тоже не приносит своих плодов. Тогда фамильяр Риона удерживает улитку в захвате, страдая от её щупалец, пока троица пытается расстрелять её из пистоля и арбалета. Ценой фамильяра им удаётся нанести урон, но ник также решает оставить добычу и направиться к браконьерам, ведь им выдали задание. Оставшиеся двое добивают улитку и Рион, используя на её панцирь левитацию, берёт панцирь с собой.\n\nНа улице браконьеры ещё раз предлагают Бальтазару осмотреться под ногами, что он и делает. В этот момент мечник из трио охотников бьёт его по голове навершием меча, но Бальтазар весьма крепкий и это его не оглушает. Милош призывает друзей одуматься и не мучить ребёнка, но те намерены разлучить Мориса (так он им представился) с его ценностями. Бальтазар приказывает мечнику бежать, но жрец хватает его удержанием личности. К счастью, Бальтазар вырывается почти сразу, а атаки из лука не достигают его — плащ из шкуры исчезающего зверя размывает контур музыканта. Тем не менее второе удержание личности опять срабатывает, и несколько ударов меча роняют Бальтазара.\n\nКогда Роза достигает домика и вламывается внутрь, следуя по кровавому следу, она видит связанного и раздетого Бальтазара, его вещи на столе и трёх бандитов. Приведя друга в сознание лечащим словом, девушка убегает, однако Милош оказывается намного быстрее. Схватка переходит на улицу и довольно быстро роза падает под ударами ядовитого клинка. В это время к домику прибегают Анарион и Ник, пока улитка Рион плетётся следом. Анарион сразу обрушивает на бандитов огненный шар, поджигая стену дома. Браконьеры угрожают прирезать девчонку если он продолжит, но её фамильяр вовремя угощает хозяйку зельем лечения, приводя в сознание. Анарион пытается успокоить их умиротворением, но видимо их жажда битвы слишком сильна. Бальтазар же, снова упавший, лежит без сознания в горящем доме. По указанию Анариона Ник бежит в дом и приводит барда в чувство, освобождая от верёвок. Тот в свою очередь хватает со стола весь свой скарб в плащ и выбегает, на ходу используя гипнотический узор на врагов. Все кроме Милоша застывают, но тот приводит в чувство жреца. Жрец обрушивает столб света на Анариона и подоспевшего Риона, спрятавшегося под панцирем. С Рионом всё в порядке, но вот отражённый от панциря божественный свет ранит всех вокруг, и опять роняет Бальтазара, лишая его левой руки. Роза спешит к упавшему, чтобы поднять его, пока остальные перебрасываются заклинаниями, в основном огненными шарами, а Анарион пропадает из этого мира. Ещё один гипнотический узор и жрец теряется в пространстве, возвращая Анариона обратно. Милош прячется за домом, многократно стреляя в Ника, но его броня со звоном отражает все выстрелы.\n\nРешив, что с этим пора заканчивать, Бальтазар, в которого Милош всё ещё верит, обращается к тому, говоря, что бой не кончится пока его товарищи продолжают драться, и их надо уложить чтобы все могли спокойно поговорить. Магическое внушение срабатывает и Милош двумя критическими выстрелами почти укладывает мечника навечно. Тот понимает, что дело приняло тяжёлый оборот и сдаётся Никандру, в то время как жрец пытается убежать. Бальтазар приказывает ему вернуться, и тот нехотя разворачивается как раз перед тем, как Рион забрасывает его на крышу горящего здания. Крыша рушится, жрец падает, но Роза вытаскивает его и связывает — Мечник уже в наручниках, принесённых Никандром. Милош считает что сделал что надо было и внушение спадает, так что он собирается уйти, однако Бальтазар говорит ему, что стрелок должен взять на себя ответственность вместе с товарищами и сдаться властям — они нанесли большой вред природе, детям и руке Мориса. Ещё одно внушение действует на мужчину и он считает, что да, ему нужно сдаться. Всех троих передают леснику.\n\nПанцирь Рион и Анарион обманом провозят в город, пока Бальтазар бухтит на Риона из-за потери руки. Тот предлагает протез, бард отказывается, однако слова Розы и цены на регенерацию убеждают его принять предложение. Чтобы порадовать друга, Роза жертвует своими средствами на новый модный протез, который Рион изготавливает сам. Помимо того что протез функционирует как рука, его кончик способен превращаться в фаллоимитатор фиолетового цвета, при касании стонущий голосом Мегеры из группы \"Кровавый Снегопад\", что радует Бальтазара. На этом приключение заканчивается.", "new_npcs_raw": "🥊 Цеповые улитки\nhttps://dnd.su/bestiary/614-flail-snail/\n\n🥊 Штормовые олени (упоминаются)\nhttps://dnd.su/bestiary/17358-tempest-hart/\n\nМешок Гвоздей (Милош) - один из браконьеров, поддался очарованию Бальтазара"}'::jsonb),
  (51, '{"session_number": 51, "loop_number": 4, "game_date": "4 петля, 19-21 странствий", "recap": "Британия вернулась в Сиорию, отправила нашла поместье и луперов, где Рион позвал помочь ему с расследованием взрыва на фабрике, и спасти брата. \n\n24 часа на поезде до места, там они предупреждают, что будет взрыв (провидец), им не верят, но главный инженер проводит экскурсию. \n\nСтудентам показывают, что под заводом роют шахту в источнику маны, и там товарищи находят камни маны, Рион вспоминает цвет взрыва, ребята понимают что это природный газ. \n\nВсё рассказали брату Риона, тот под угрозой потери денег и людей соглашается вывести людей, пока луперы обследуют кабинет инженера, который удачно уехал. Находят пустой сейф, переписку с другой страной и местом встречи, всё ценное забрал. \n\nКогда завод пустой, Рион идёт проверить все ли вышли, он магией видит беса, тот кидает бомбу, и происходит взрыв, но не такой сильный как в прошлый раз, Рион теряет сознание, а завод начинает гореть. \n\nДрузья успевают взорваться и утащить тело товарища, но тот уже мёртв, тогда Роза использует Возрождение, которое ей вложила в кольцо Карина. Люди целы, брат выжил, но завод полыхает.\n\nДрюс зажигает трубку и садится смотреть на огромный пожар."}'::jsonb),
  (52, '{"session_number": 52, "loop_number": 4, "game_date": "4 петля, 19 странствий", "recap": "*Интерлюдия, утро:\nРоза просит Карину вложить в кольцо возрождение, так как на другом задании с ними нет жреца.\nКарина понимая, что это шаг навстречу к миру, соглашается.\n— Будь осторожна, если что-то... нет, всё будет хорошо. Запомни - не дольше минуты!*\n\nЗакончив отдых, вместо Уини приходит Анарион после задания. Обсуждают, как поступить с Нилбогом, договориться, убить, и решают найти вход в логово гоблинов, а там уже поймут что делать.\n\nВпереди летят Депресняк и Кукля, группа спокойно доходит до моста с расщелинами, куда падал Анарион в прошлый раз. Вдруг Карина чувствует на себе руку, одёргивает Локи, но это не он, а невидимая магическая рука, которую видит Локи, как в прошлый раз в поместье. Зажигают свет, осматриваются, слышат какой-то грохот камней и Локи замечает неудачно упавшего гоблина в темноте, и тут же отправляет к нему Зака, кричит «Все вниз» и через Йотуна прыгает ниже.\n\nКарина хватает Анариона и сигает вниз, Лекс следом подхватывает их заклинанием, стоя на их плечах, но до Локи не достает, и тот в полете цепляется за Зака, которого уже успели поднять на 30 футов невидимой силой.\nДрипли быстро хватает веревки, связывает и ползёт вниз, попутно товарищи успевают кинуть под гоблинскую жопу пару заклинаний, но тот скрывается в узком тоннеле. Карина со злости бросает вслед дребезги, и обвал закрывает проход. \n\nЖрица извиняется, товарищи начинают разгребать завал, Дрипли слизью протискивается внутрь мимо мертвого гоблина, Локи через Йотуна прыгает вперед и оба видят пещеру, железная дверь с символами, рядом лежит мел. Несколько минут Карина переводит текст, товарищи что-то считают, а Лекс на интуиции (Никита дешифровал) подбирает нужный символ, открывая дверь. \n\nИх встречает темнота огромного зала со странными статуями, и знакомый голос «Вы принесли мне дары?», вперед выходит Зак, следом Дрипли со словами «Вот тебе подарок», целится в гоблина, но очаровывается и стреляет в Зака паутиной. Начинается бой.\n \nИз темноты укрытий в ребят летят психические клинки, Зака мгновенно роняют, следом сильно попадают в Карину, та создает маяк и отступает. Лекс создает узор, выключая пару зеленых, следом Анарион накрывает их огненным шаром, а Локи хочет телепортировать Нилбога, но тот обманом избегает эффекта. \n\nДрипли лечит Зака (делает вид, что без сознания) сам отступает, и кажется ребята могут выкрутиться, как вдруг гравитация меняется, и Карина с парой гоблинов подлетает под потолок, сильно ударяясь. Открывается одна из статуй в виде подарка, и Дрипли начинает истерично хохотать, пока Анарион кидает в Нилбога два огненных шара, из-за чего гравитация кончается, но Лекс успевает поддержать Карину от падания. Зак, вырвавшийся из паутины подбегает к товарищам, Локи заряжает палочку в Нилбога, но тот словно неуязвим, и во всех летит психический взрыв. \n\nЛоки увернулся, Лекс и Анарион падают. Зак видит, как Карина опускается пёрышком, со вскрытым черепом в струях крови, он подбегает, чтобы вынести тело, но подарок снова открывается, и Зак начинает неудержимо танцевать, пока вернувший контроль Дрипли лечит Лекса. Локи понимает, что время отступать (на нём лежит задача сделать редкие рецепты предметов), кланяется Нилбогу и выбегает в двери, закрывая их.. Зак получает несколько разрядов и падает без сознания рядом с Кариной (чел..)\n\nЛекс видит безвыходность ситуации, Карина и Анарион не реагируют на лечение, хватает Зака и вместе с ним выходит за дверь следом. Нилбог кричит «Схватить», гоблины окружают Дрипли, скандируя «Сдавайтесь. Вас-хва-ляй, Нилбог!», изобретатель теряет сознание, а в это время Анарион тихо умирает.\n\nЛекс лечит Зака, распахивает двери, на бегу кричит «О великий, как же ты нас переиграл и уничтожил, о хвала тебе», добегает до Дрипли, и вместе с ним телепортируется за дверь, которую закрывает Зак, Нилбог кричит «В погоню!», ребята создают магические ловушки, успешно выбегают из расщелины, оставив тела товарищей.\n\nВ поместье их встречает колокольчик и издевательски звенит, Зак пробует сломать его, но не выходит, и выкидывает его в окно."}'::jsonb),
  (53, '{"session_number": 53, "loop_number": 4, "game_date": "4 петля, 20-22 странствий", "recap": "Утром Бальтазар по повестке посещает участок, его опрашивает Хаслуш, он устанавливает детали дела о браконьерах, которые сами обвиняют студентов в нападении на обычных охотников. Бард отвечает честно, что они защищались и он даже потерял руку, а магию использовали только после взятия в плен Розы. Насчёт раковины и других вещей не знает, так как был без сознания. Хаслуш просит Бальтазара передать повестку товарищам, бард соглашается, но не ручается за них.\n\nЗак пытается уничтожить колокольчик, но не выходит, он относит его кузнецу, но тот не плавится, тогда Зак отдаёт его в храм, чтобы жрецы с ним что-то сделали. По возвращении домой колокольчик снова в гостиной, Каэл его немного исследует, но ничего. Лекс предлагает 10 золотых тому, кто *уничтожит* колокольчик, Дрюс хватает его и проглатывает, он глухо звенит в животе. Маркус убегает за жевательным табаком, друзья обсуждают куда им отправиться, Лекс вспоминает задание пропавших трупов на кладбище в деревне. Дрюс превращается в кота, чтобы не платить за билет, возвращается Маркус, Зака всё ещё бесит звук колокольчика из живота Дрюса, тот выблёвывает его, и Маркус затыкает колокольчик табаком, чтобы язычок не звенел. Каэл берёт предмет себе, чтобы позже исследовать. \n\nДобравшись до деревни на 300 человек группа замечает, что аборигены ведут себя как под грибами, зрачки расширены, речь заторможена, движения медленные. Находят старосту, тот им рассказывает ситуацию, кто-то ворует их трупы, и больше некому работать на грибных плантациях. Ребята удивлены, что значит трупы работают, староста приглашает отобедать к себе, чтобы объяснить подробнее. Студенты кушают полностью грибной обед, и вдруг хозяин начинает общаться с ребятами телепатически. Зак противится, Британия не ест, но и так может общаться телепатией. Старик объясняет, что это рой грибов, с которыми они договорились на симбиоз, поэтому трупы им нужны, они часть роя и их родня, не хорошо что их украли. \n\nДед ведёт всех в пещеру, приглашая познакомиться с грибами. Там стоит 9 стульев, ребята садятся на стулья, от которых нет магии, они мягкие, и стулья вдруг начинают диалог с группой. Оказывается, это большие грибы, которые знакомятся со студентами, и просят помочь с поиском тел. Дрюс находит под грибом споры, берёт их на память, и просит показать где психоделические грибы найти, ему указывают тропинку, друид выходит из пещеры. Зак не садится на гриб, Лекс его спрашивает *У тебя что, проблемы со стулом?*. Ребята собираются и идут на поляну, где работали трупы. Там они находят следы и мерзкую ядовитую жижу, то ли яд пауков, то ли что похуже. По следам они выходят в лес, где встречают гигантского лося, скрытно его обходят, и неожиданно видят впереди тела-зомби и три громадных плотоядных цветка. \n\nНачинается бой, Маркус и Зак в авангарде атакуют зомби и сам цветок, тот ранится, но проглатывает одного зомби, и ему как будто лучше. Лекс и Британия сыплют остротами вперемешку с психикой, заставляя два других цветка отступать и терять время, пока Каэл и Дрюс щедро поливают зомби и цветы огнём. Цветы то глотают, то выплёвывают зомби, которые после падения взрываются брызгами яда, да так обильно, что Маркус даже падает, но его тут же лечат. Два цветка уже погибло, последний начинает *убегать*, но его просто расстреливают с дистанции. В этот момент слышно звуки ломающихся деревьев, Лекс оборачивается встречать опасность, но лось добегая превращается в человека, про виду из деревни. Он тоже искал трупы, но нашёл ребят. \n\nКаэл собирает ингредиенты, Дрюс с Маркусом собирают носилки для тел, чтобы принести их в деревню, деревенский превращается в гигантского лося, Дрюс повторяет за ним и все возвращаются обратно. По возвращении, староста очень просит ребят никому не рассказывать про грибницу, а то *Не так поймут*, Зак махает на них рукой, Каэлу и Британии всё равно, Дрюс нашёл новых друзей. Уже когда никто не видел, Маркус идёт в пещеру и просит грибы дать с собой споры для телепатии.", "new_npcs_raw": "🥊Трупоцвет\nhttps://dnd.su/multiverse/bestiary/6576-corpse-flower/"}'::jsonb),
  (54, '{"session_number": 54, "loop_number": 4, "game_date": "4 петля, 22 странствий", "recap": "Собравшись в поместье, ребята знакомятся с Киллианом, приезжает Миряна и говорит, что с ней тоже связались пауки. Студенты в гостиной обсуждают, что с ними делать, может пауки влияют на неё, Уини проверяет одноклассницу, кажется всё хорошо. Сверху комком сваливается слизь, пока у Дрипли не получается эксперимент, он уговаривает товарищей помочь ему с созданием камня призыва слизи.\n\nСнова поминают Панаксета и Дрипли добрым словом, Киллиан рассказывает про слежку за Йово, что сфера влияния в городе меняется, снова разговор про зло, добро и серую мораль. Роза упоминает Янку, а Дрипли рассказывает, что к нему домой ворвались и написали МОНСТР, товарищи решают, что это точно Янка. \n\nЧерез послание узнают, что Бальтазар ходил к ментам, Роза игнорит их, а Миряна снова вспоминает про сообщение от пауков и понимает, что они телепатически общались с ней в Суламноне, значит были рядом. У волшебницы начинается паничка, Дрипли и Уини добавляют, что ещё Лекс назвал некромантам в подземелье своё имя. \n\nКиллиан предлагает пойти к Йово, чтобы отомстить заказчикам «Черная Роза», которые убили Розу в прошлый раз, девушка дарит Киллиану пощёчину по случаю. Перед концом петли ребята перебирают варианты, чем заняться, чтобы не испортить петлю по просьбе Аланика. Идут на задание в поместье с движимыми вещами, и пока готовятся к выходу, Миряна на занятиях получает фамильяра кошечку Мяу.\n\nОфелия с Уини получают задание, жрица случайно говорит про Розу, администратор просит её подойти в академию, но паладинка отмазывает подругу. Группа возле особняка, дворецкий даёт подробности задания, чтобы к приезду хозяев всё было готово, отдает ключ, и просит не уничтожать имущество, то есть одержимые предметы.\n\nОсобняк и сад, всё обычное, Уини подходит ближе, но перед ней втыкается болт, выпущенный баллитой на крыше дома. Миряна рассеивает магию на оружии, оно перестаёт стрелять. Дрипли и Миряна через обнаружение понимают, что деревья перед входом живые, и тут же Розе в голову прилетает от них булыжник. Одно дерево развеяли, второе сожгли.\n\nРоза ключом открывает дверь, внутри продолжают чувствовать магию преобразования, Миряна развеивает ковёр и две статуи, Уини не ощущает присутствие проклятий или зла. В гостиной на них нападают чашки и двигаются столы, Миряна кидает ледяной шар, выкатывается пара бочек, обливая маслом в основном Розу, и тут выбегает печка и дышит на всех огнём. Киллиан хочет остановить наступление мебели, и кидает силовой шар прям в печку, попадая по друзьям. \n\nКак раз в этот момент выбегает горящая Роза, видит лестницу в подвал, её пытаются схватить перилла, но она падает вниз, вслед за ней Уини прыгает, чтобы потушить подругу. Офелия, которая предусмотрительно не заходила в гостиную видит эту картину, и лечит неудачливых товарищей. Остатки мебели уничтожают, пока Миряна выбегает прочь из дома, садится на траву и начинает медитировать (для маны). В подвале на Розу нападает нож, Уини уничтожает пару оживших алебард, вниз спускаются Дрипли и Киллиан, волшебник видит квартет гробов и не дожидаясь их нападения кидает в них дребезги. \n\nГробы встают, окружают Уини, Дрипли и Киллиана, начиная пляску смерти, в ходе которой их хватают внутрь, в двух гробах пара скелетов, а вот Дрипли неожиданно знакомится со спящим внутри вампиром, который удивляется и просит гостя покинуть гроб, что изобретатель делает с удовольствием. Пока жрица спешит к друзьям на помощь, Миряну отрывает от отдыха проснувшееся дерево. Девушка достаёт револьвер, подходит к нему впритык и убивает окончательно, та же судьба ждёт ковер и статуи в доме. \n\nВнизу товарищи уничтожают гробы и выпавшего из него вампира, который не нападал, но Уини хватает его за грудки, тот начинает тлеть из-за её солнечного меча, и все вместе (кроме Розы) убивают нежить в пыль. Поднимаются обратно наверх, в библиотеке на них нападают стаи книг, но ребята их уничтожают, из полки вылетает волшебная палочка, успевает выпустить молнию, но студенты ломают её пополам."}'::jsonb),
  (55, '{"session_number": 55, "loop_number": 4, "game_date": "4 петля, 23 странствий", "recap": "Альд следил за луперами у поместья, проверяя защиту базы, искал фамильяра Янки в округе (не нашёл)\n\nБальтазар и Офелия выясняли отношения, точнее, как и что они не поняли и чего ожидали (дело не во мне, а в тебе)\n\nМиряна вернулась со своих экспериментов, предлагая ребятам заняться *чем-то полезным*\n\nДрюс за любую движуху, кроме голодовки, в идеале что-то поджечь (кого-то) \n\nТак они перебирают варианты с заданиями, чтобы успеть заработать какие-то деньги на рецепты, идут в подземелье за пещеру с Пауками, где видели проход дальше.\n\nТам они находят 2-ух магов и 2-ух войнов из армии захватчиков, быстро с ними расправляются, решают допросить труп одного, но слышат грохот марша дальше по коридору. \n\nУбегают из пещеры до моста Нилбога, там прячутся и видят, как маги начинают перекидывать троллей через провал, на этом они убегают, решая не рисковать."}'::jsonb),
  (56, '{"session_number": 56, "loop_number": 4, "game_date": "4 петля, 27-30 странствий", "recap": "За кадром, Янка уговаривает Альда приехать и помочь разобраться с состоянием Зориана. \n\n27 утро, Зак на кухне встречает девушку, которая заваривает чай и приветствует хозяина поместья. Она спокойна, знает где что лежит, как будто была здесь раньше. \nЗак зовёт Розу, Альд и Локи идут на звук, все знакомятся с гостьей. Тулуна из класса А говорит, что её принесла сюда рыжая девочка (Янка), луперы её спрашивают, как она тут оказалась и где была раньше, но друидка ничего не помнит, Альд с помощью глаз проверяет её, и говорит, что на ней тоже след петли.\n\nВ этот момент в зал заваливаются Дрипли и Рион, довольные камнем слизи, тут же на кухне пытаются варить зелья, но Зак их выгоняет в подвал. Позже призывают слизь во дворе, Рыцарь Желейка, Тулуна с интересом наблюдает за всеми, Роза помогает ей адаптироваться. Дрипли отправляет слизь патрулировать поместье, и с Рионом возвращаются к варке зелий. \n\n28 дня ребята узнают, что Бальтазар попал в тюрьму из-за Бенисека, вдруг в поместье врывается Ильза и разносит Зака, в которого превратился Локи, что у них тут оргии и вечеринки, прогуливают пары, он плохой пример для подражания для Тулуны и т.д. Наказывает всем быть на балу.\n\nВечером ребята выходят в город, кишащий приезжими, ощущение праздника, встречают «сумасшедшего», который предрекает КОНЕЦ И СМЕРТЬ, но всем по.. луперы садятся в Вине Поэзии, и начинают аккуратно рассказывать Туле, что на фестивале будет апокалипсис, морально готовя её. Рион неожиданно признаются, что принял предложение пауков-телепатов, и просит товарищей его понять и простить. Начинается холивар, так как они договорились этого не делать, но Рион готов рискнуть своим рассудком и судьбой всех луперов, «впустив их в петлю». Роза отправляет письмо Бальтазару, тот дальше серию посланий. Рион уходит на встречу с пауками (сцена без свидетелей), возвращается с новостями, что они помогут отвлечь захватчиков в подземелье, где стоит портал. Товарищи проверяют его разум, душу и на магию, ощущая какой-то «контейнер» в памяти, которой не достать. Луперы решают не упускать шанс, соглашаются на помощь пауков, и готовятся к вылазке.\n \nМиряна находит Риона в поместье, обвиняя его в том, что «Он нас всех убил!».\n30 дня идут в подземелье, перед заставой их встречает отряд из пауков, волшебницы Луны и мушкетеров, те неуверенно смотрят на студентов, но пауков слушают, докладывают позиции врагов, сторожащих портал. Луперы ставят цель - добраться до портала и любой ценой войти в него. Если получится убить всех, так и сделают. Пауки идут первые, за ними отряд, следом луперы, секунды тишины и вот сигнал тревоги, бой.\n\nПауки парализовали троллей, отряд вышел фронтом, Рион и Дрипли призвали две слизи, Альд и Тула невидимые идут вдоль стен, Роза и Локи в высшей невидимости атакуют, Рион отвлекает на себя в центре пещеры, а Луна сверху убивает пару погонщиков и троллей. Вдруг к ним сзади подлетает некромант, атакуя конусом холода почти всех, он защищен сферой. Рион поливает огнем, Дрипли управляет слизью, но после облака смерти теряет над ней контроль. Локи и Роза тут же телепортируются к порталу, но ударяются о защиту. Пауки держат троллей, погонщики умерли, и кажется победили, но тут некромант снимает защиту, отправляя Послание, и на него кидается зверь Тулы. \n\nКупол с портала спадает, Локи и Роза заходят внутрь, видно зал подвала с воротами, Рион прыгает вслед за ними, Дрипли и Тула бьют некроманта, Альд двигается вдоль пещеры к порталу, как вдруг видит фигуру лича в красном плаще, который цепной молнией уничтожает Луну, пауков и попадает в жреца. Локи и Роза выходят из подвала, впереди коридор, только двери, никаких окон, они под землей, и видят, как на них мчится толпа нежити. \n\nАльд мигом прыгает в портал от лича, кричит Риону «Там смерть!», как за его спиной появляется Он, атакуя Альда, тот защищается, давая Риону возможность бежать из портала обратно в пещеру. Роза, Локи и Альд умирают на той стороне, Рион кричит Тулуне и Дрипли бежать, но лич появляется и стирает их в порошок. Так прошёл первый бал Тулуны.", "new_npcs_raw": "Сикэн Казински - мама Зориана\n\nКириэлле Казински - младшая сестра Зориана\n\nКопье решимости, прознающее самую суть - матриарх племени аренеа в Сиории"}'::jsonb),
  (57, '{"session_number": 57, "loop_number": 4, "game_date": "4 петля, 28-30 странствий", "recap": "Все, кроме Эрика, собираются в поместье и обсуждает грядущую вечеринку End of the World Party: Zachopocalypse. Луперы тратят весь бюджет, берут кредиты (Тулуна и Тони), тратят 2000 ЗМ на свиток Стены Силы, на остальные идут в первое попавшееся агентство наемников \"Издиш\" и нанимают там двадцать девять человек (из которых девять магов). Остается еще дохера и на это закупают бухла, еды и дорогие бейджики, куда можно написать имена.\n\nВ какой-то момент первого обсуждения вечеринки (вечером 28-го числа) в зале появляется Тулуна, знакомится с ребятами и помогает с украшениями и живыми растениями. Они обсуждают превращения друидов в ворон и спаривания в этом виде друг с другом. Тулуна спокойно отвечает на любопытные вопросы, поясняя за свою культуру. Также Лекс припахивает Розу и дает ей бюджет на декор и иллюзорные украшения. Тулуна в последние дни вместе с Розой с другой группой планируют прорыв к вратам и отваливаются из стихийного оргкомитета.\n\n29-го числа Маркус застревает в толчке рукой, пытаясь его починить, и Лекс запоминает эту картинку для будущих иллюзий. Покупается всё для вечеринки. Разговоры часто сводятся к сексу, пошлостям и членам – сказывается концентрация бардов. Маркус покупает на вечер весь персонал кухни из \"Вина поэзии\" и командует ими, пытается угрожать, но очень плохо. Луперы просят всех гостей приходить с оружием и объявляют конкурс на самый крутой боевой обвес. Тони готовится к балу, покупая бочонок с порохом.\n\nГости прибывают. Около десяти часов начинается концерт. Бенисека не приглашали, но он пришел, и Маркус скрытно повесил ему на затылок заранее заготовленный бейджик с именем \"Пенисек\" (на эту шутку в общей сложности было потрачено 100 ЗМ из общака). Лекс выступает первый с песнями. Затем выступает Британия со своими.\n\nВо время выступлений происходит знакомство с Эриком (новым лупером) – бывшим однокурсником, который решил не проходить сертификацию летом и поступил в Королевскую Военную Академию Эльдемара, в прошлой петле услышал про некромантский сговор в Сиории и решил прибыть в город в конце петли, чтобы проверить Розу (свою невесту) и начать свои итерации подкатов к ней. Эрик расспрашивает луперов, они обтекаемо отвечают ему, он пытается что-то понять. В какой-то момент он заговаривает с Тони, который выкладывает всё, ни на секунды не стесняясь.\n\nЛуперы обсуждают Эрика, то, что Роза тоже находится в петле и стала ведьмой, разговаривает с мертвыми, его шок  по этому поводу и предстоящую смерть. Тони много говорил о том, что ему классно жить вечно, пусть месяц и повторяется, и он не понимает, почему все так легко собрались умереть. В целом многие его понимали и принимали.\n\nЛекс заканчивает выступление песней, которую посвящает одному \"зеленому волшебнику/волшебнице, который/ая часто заебывает, но иногда оказывается ничего таким/такой\". Бальтазар, которого отпустили под залог с честным обещанием вернуться в тюрьму к 11 часам, в какой-то момент уходит с вечеринки, тихо прошептав побелевшему от страха Бенисеку \"Пойдешь ко мне барабанщиком? А то ты отлично стучишь\".\n\nПод конец десятиминутного выступления Британии, все присутствующие чувствуют воодушевление, она заканчивает песню и со слезами на глазах начинает говорить речь. Без видимых магических инвокаций на сцене позади Британии начинают проецироваться образы Сиории, и Провала рядом с ней. Затем артиллерия и артиллерийские заклинания начинают стирать город с лица земли. Меняются калейдоскопом сцены, пугающе реалистичные, вплоть до запаха и наэлектризованного, горячего воздуха. Вот ледяные волки разрывают горла Коприве и Акодже. Железные перья прошивают Эдвина и его големов насквозь. Тайвен в составе группы умирает от цепной молнии захватчиков. Разрушаются церкви и общежития, умирают старики и дети. Слышится бесконечная канонада, звуки ружейной пальбы, заклинаний, леденящие душу крики  и мольбы о пощаде, но ибасанские захватчики не щадят никого.\n\nГлаза Британии светятся синим, позади нее формируются серафимные фантомные крылья с глазами, и она говорит о том, что готовится большое нападение на город. И что некоторые из них были отмечены ангелами, как пророки, и призваны спасти всех. И они обязательно это сделают, чего бы им это ни стоило. Она показывает страшные картины, но говорит о любви, Богах, смелости и обязательной победе в конце. Она предупреждает о предателях, и за её спиной показывается сцена, где Боб Саймон открывает колбу с ядовитым облаком в убежище. Кто-то в ужасе кричит \"Он здесь!\".\n\nОн действительно оказывается здесь, откупоривает свою магическую колбу и едкий желтый ядовитый дым заполняет комнату. Маги и воины, нанятые луперами, оказываются готовы к этому с заклинаниями-пузырями вокруг их голов, и могут спокойно дышать в этом дыме. Начинается резня. Появляются две ледяные стенки, которые разделяют зал на три части. Эрик оказывается запертым наедине с магом ограждения и у них происходит дуэль в ходе которой он  сильно ранит мага, но тот мощными силовыми лучами дважды подряд впечатывает его в стену.\n\nЗак, Маркус и Джолин вступают в потасовку с вооруженными мечами ветеранами, Коприва Рейд помогает им лучами боли. Каэл пробует развеять дым фокусами, но у него не выходит.  Все страдают от этого дыма, многие гости начинают закашливаться, падать на землю и умирать, захлебываясь рвотой.\n\nЛекс в какой-то момент снимает эффект дыма, чем дает вражеским волшебникам возможность получше прицелиться молниями на будущее. Британия пробует заколдовать Саймона пляской Отто, но у него иммунитет к очарованию. Саймон достает очередную колбу и распыляет тот же дым. Вражеские боевые маги под его прикрытием накрывают двумя молниями почти всех луперов и большую часть гостей (включая карлика Бориса, который вовремя пригнулся и вообще не получил урона). Тони развеивает дым диспелом. Часть ветеранов-наемников режет гостей, пытаются зарезать нанятого карлика Бориса, но по нему хрен попадешь. Британия накрывает гипнотическим паттерном трех ветеранов и мага.\n\nЗак падает от яда, молнии и атак. Маркус с Джолин добивают одного ветерана, потом другого. Одному из них Маркус буквально вырывает сердце и дарит возлюбленной. Лекс накидывает на Саймона иллюзию и очередная колба у него в руке кажется ему ужасным монстром. Каэл изгоняет одного из ветеранов (помянем, он так и не вернулся, беднягу наверное до сих пор обвивают щупальца). Маркус также оглушает Саймона. Лекс падает от сильнейшего стихийного взрыва, который обогнул Саймона. Британия еле стоит на ногах. Маркусу ни разу не прилетает (как и за весь бой, он проходит все спасброски ловкости и получает 0 урона). Британия дает \"Помощь\" себе, Лексу и Заку, поднимая их на ноги.\n\n\nОдна ледяная стена пропадает, затем вторая. Тони берет бочонок пороха и кидает к двум магам (ограждения и воплощения), которые прикрывают друга друга. Лекс кидает в них и бочонок бусины силы, запирая их всех втроем. Параллельно Каэл держит Саймона в стазисе и просит не бить его. Маркус бьет Саймона в надежде оглушить его, но проваливается в этом. Раздраженный Саймон достает клинок и прыгает между Британией, Заком и Маркусом, попадая только по Заку. Дальше один из волшебников телепортируется из бусины, берет бочонок и кидает в Зака, тот разбивается, но волшебник ограждения создает силовое поле для контейнирование взрывной волны и поджигает порох, Зака еще и накрывает взрывом, но он успел заранее себя полечить и потому устоял на ногах. Британия пытается два раза задиспелить Саймона, чтобы снять с него положительные эффекты, но проваливается.\n\nЛуперы берут верх, окружают Саймона, Британия добивает его \"Злой насмешкой\" и он падает без сознания. Эрик одним изящным ударом (крит, скрытая атака, смайт, яд) убивает почти нетронутого мага ограждения. Маркус телепортируется в бусину силы к магу воплощения и превращает его лицо в кровавую кашу. Британия и Лекс диспелят Саймона без сознания и видят тридцатилетнего безукоризненного красивого блондина с длинными волосами. Они просят Джолин отрубить ему запясться, а затем лечат и приводят в себя. \n\nБритания применяет \"Приказ\" - \"Представься\". Он представляется как Сумрак, судя по всему нарушив Обет, от чего очень быстро умирает, из его носа и рта идет кровь. Ребята обсуждают, воскрешать ли его и решают, что нет. Затем по одному добивают трех солдат и мага, всё еще залипших после гипнотического узора. Все облегченно выдывхают, но слышат звуки боя и крики в поместье, и отправляются драться дальше, тратя половину оставшихся (и так довольно скудных) ресурсов. \n\nЛуперы находят оставшихся (к сожалению очень немногих) паникующих выживших, лечатся, баррикадируются, Каэл со свитка, переданного ему Британией создает \"Силовую стену\", чтобы все были в безопасности. Маркус и Джолин уединяются на несколько минут в приступе любви за тёмным экраном. Одноклассники в основном паникуют, Тайвен помогает организовывать оборону. Лекс с Маркусом, Джолин, Акоджей и близняшкой сидят в Леомундовой хижине.\n\nКончается эффект силовых стен. В помещение влетают тролли. Начинается новая резня. Затем волки. В дыры в стенах и окнах залетают железноклювы. Дальше под прикрытием огненных шаров заходят ибасанские маги. Луперы и люди из академии сражались достойно, уничтожили многих врагов, но в итоге их задавили количеством. В последний момент Лексу и Эрику удалось упрыгнуть через пространственную дверь. Они покурили сигарет, наложили на себя невидимость и вскоре погибли в стычках на городских улицах... Но Лекс, возможно, ещё оставил за собой если не последний куплет, то последний сдавленный хрип точно."}'::jsonb),
  (58, '{"session_number": 58, "loop_number": 5, "game_date": "5 петля, 1-2 день", "recap": "4 утра, Альд бежит к Риону проверить товарища, по пути посылает Локи «Проснись, уходите с Оливией».. Рион встречает жреца в дверях, он в порядке, Альд созывает всех в поместье Зака, а сам бежит дальше, кое-кого разбудить ещё. \n\nЛоки в библиотеке в 4:20 получает Послание, просыпается с Оливией, разбивает окно, чтобы телепортировать девушку из башни, сам выпрыгивает, и краем глаза замечает вошедшего Зеномира Оглая, который успел их увидеть, но те скрываются.\n\nПоместье, Зак спускается на кухню, и видит полненькую девушку, которая общается с помощью таблички (немая). Альд, Рион приходят на звуки, в этот момент девушка начинает говорить «Вы вообще всех пускаете сюда?» и превращается в Бальтазара. Секунды негодования, которые сменяются тем, что многие собираются в поместье, что-то крафтят, помогая друг другу. Риона ещё раз проверяют, пакет памяти на месте. \n\nЗак просит всех собраться в зале, обеспокоенная Офелия начинает рассказывать, как к ней в первую петлю подошло двое мужчин, один в  красном плаще, и сказали «Мы знаем, что ты в петле, мы её создатели, и можем тебя из неё убрать, и если в 6-ой петле ты не расскажешь нам всё о своих друзьях, мы тебя из неё уберём». Жрица начинает плакать, Карина и Британия её успокаивают, Офелия признаётся что сразу не рассказала, потому что боялась. Луперы перебирают варианты, что это значит, как это «убрать из петли» и кто эти странные люди. \n\nКаждый делится информацией, что они узнали в конце петли, новый лич в красных одеждах у портала, Локи вспоминает, что видел нечто похожее на Альде (когда он умер в 3-ей петле), и решают, что это как-то связанно с Суламноном. А нового врага с красным плащом, угрожающего Офелии, решают найти. День готовятся, собирая артефакты. \n\n(за кадром) Локи поехал на север, где вместе с Розой передали всю информацию Аланику. \n\n2 день. Роза приезжает в Сиорию, ей всё рассказывают, так как глобального плана нет, решают идти искать красный плащ, так как он был где-то в городе. Альд с помощью поиска предмета нащупывает след под землёй, второй уровень, по пути находят забытую алхимическую лабораторию, взламывают замок (звучит тревога), но плащ чувствуют дальше в толще породы. С помощью Нила и Церебро пробуют найти, но ничего не видно, и Рион начинает дребезгами ломать камень, он осыпается, кислота и огонь уничтожают часть предметов, видно какую-то руну.\n\nВдруг разума Риона касается паук, он передаёт какую-то фразу и тот убегает, и пока ребята разбирают тайник, пауки возвращаются, Искательница, Матриарх и Та паучиха. Они общаются телепатией, ребята просят перейти на общий, Роза пару раз огрызается и получает урон психикой, немного напряжения, пауки ведут себя снисходительно и заносчиво, Рион просит всех успокоиться, пауки извлекают пакет памяти, Альд не замечает на душе следов повреждений.\n\nРезко сзади слышно топот, пауки говорят «Нас обнаружили», убежать не успеют, поэтому будут сражаться, ребята соглашаются, успевают подготовить заклинания. Роза создаёт тьму в проходе, отрезая видимость врагам и союзникам, Зак и Рион выходят вперёд, остальные бафаются и рассредоточиваются. Тьму рассеивают, в пещеру вбегает 5 воинов, сзади культист и культистка. \n \nКультист влетает сбоку, поражая всех конусом холода, воины атакуют Зака и Риона, Бальтазар гипнотиком вырубает культистку и воинов позади, Матриарх кричит «Я их не вижу, снимите заклинание», пауки пробуют контроль, но ребята всех видят. Культист под защитой антимагии, Зак атакует его внутри сферы, но воины его убивают, перерезая горло. В это время успевают убить культистку, по очереди контролируя воинов, но пахнет жаренным. Альд подлетает к Заку, и Возрождает его, попутно исцеляя. \n\nКультист удивлён, но говорит «Отрезайте им головы», пока пауки всё ещё «не видят врагов», Офелия лечит всех, спасая пауков, Но на её глазах Зака роняют и отрубают ему голову.  Жрица кричит, в отчаянии снимает магию с культиста, паучиха тут же его контролирует, начинается новая фаза боя, где уже пауки и луперы в большинстве.\n\n\nВоины сразу не сдаются, переключаясь на Офелию, и даже выбивают её из сознания, Бальтазар в последний момент отвлекает лучника, чтобы стрела не убила жрицу, затем сам теряет сознание. Альд по очереди поднимает их до половины ХП. Рион танкует, и в какой-то момент впитывает сырую ману становясь парализованным, а Роза удачно убегает от воина, попутно стреляя в него некротикой. \n\nКультист и культистка погибли, двое воинов умерло, оставшиеся трое поднимают руки и сдаются. Слова «Отрезайте им головы» отражаются в голове у Альда, он не реагирует на их слова и продолжает атаковать одного воина, руки подёргиваются некротической энергией, потеряв контроль он истязает врага, который отвечает жрецу, но проигрывает и Альд тратит все силы на его убийство. \n\nРоза кричит «Прекратите, нам нужно их допросить!», связывая одного воина, Бальтазар ей помогает, не давая его убить, третьего оставшегося пауки быстро допрашивают на месте, но так как делают это наскоком, плавят ему мозг и от тоже умирает. \n\nГолова Зака, отрубленная от тела, утопает в луже крови.. Офелия не обращая внимание на врагов, в отчаянии падает на колени, приставляя его голову к телу, и накладывает нетленные останки на обе части.. Бальтазар, который до этого спас жрицу от последней стрелы в спину, подходит, и молча начинает кастовать починку на шею Зака, как до этого в подземелье он присоединил язык во рту некроманта. Офелия на него беспокойно смотрит, обращаясь к Альду помочь с пришиванием, тот наконец отвлекается от трупа воина.  \n\nЗак выглядит паршиво, крайне ужасно, шею прочерчивает рана, которую нужно зашить, Альд отмечает про себя удачную находку Бальтазара с починкой на голову, но нужно ещё поработать, иначе Зака воскреснет с отрезанной головой и умрёт снова. Жрец достаёт инструменты, Рион помогает советами по медицине, Альд в полевых условиях аккуратно соединяет ткани (крит 20), смотрит на Офелию и разводит руками - он потратил всю ману в порыве гнева, и не может возродить Зака здесь. Офелия вздыхает, так как у неё тоже не осталось сил, поэтому просят пауков помочь принести тело в поместье. \n\nПауки, впечатлённые силой жрицы жизни, которая спасла их от смерти, соглашаются помочь, Зака выносят без проблем, гвардия как будто даже его не замечает, видимо влияние пауков, до поместья добираются без происшествий. Пауки говорят, что подумают над сотрудничеством, после боевого столкновения они чуть менее высокомерно общаются с ребятами. \n\nЗака кладут на диван, все, кто есть в поместье, Офелия криком зовёт Карину, прибегают остальные в поместье, встревоженные увиденным, жрица удивляется, что происходит, почему Зак так выглядит. Интуитивно все понимают, что пришитая голова и второе возрождение за такой короткий срок - большое испытание для Зака. Альд подходит, проверяет след души глазами могилы, подсказывая, что нужно создать маяк для его сознания здесь, чтобы Зак почувствовал путь домой. (первый бросок Религии для возрождения положительный +).\n\nДалее к Заку наклоняется Бальтазар, и на ухо шепчет «Если ты не вернёшься, учти, что остаток месяца я останусь с Офелией» (второй бросок Запугивания для возрождения отрицательный -). Офелия, держащая голову Зака на коленях, отгоняет Бальтазара и обращается к Заку «Зак, пожалуйста, ты нам нужен, ты мне нужен, когда ты рядом, мне спокойнее и я чувствую себя сильной, возвращайся». (третий бросок Убеждения для возрождения положительный - две крит 20). \n\nКарина берёт бриллиант, произносит текст возрождения, окунаясь в облака и ночное звёздное небо, откуда достаёт Зака (крит 20). Карина уже второй раз возрождает кого-то именно в поместье, так странно. Зак открывает глаза, Карина тут же под маяком надежды вливает в него жизненные силы, Офелия обнимает подругу, а затем прыгает с объятьями к Заку. Роза даёт Альду жёсткую пощёчину, говорит что все сошли с ума и уходит собирать вещи, чтобы уехать в Эльдемар. Кажется всё обошлось, пока..", "new_npcs_raw": "Исполненная энтузиазмом искательница новизны - молодая (но совершеннолетняя) паучиха из племени аренеа, очень любопытная до людской культуры\n\n🥊 Культист культа Звездоного дракона\n\n🥊 Послушница культа Звездного дракона"}'::jsonb),
  (59, '{"session_number": 59, "loop_number": 5, "game_date": "5 петля, 1-5 странствий", "recap": "Маркус просыпается и идёт в Петуха, но за баром стоит парень, которого никогда не было в начале петли, но с его слов «он тут каждый день». Маркус идёт в поместье рассказать товарищам о своих подозрениях. \n\nВ поместье Лекс представляет всем Эрика как жениха Розы, тот подкатывает к Карине, не узнал одноклассницу со второго года, потому что она снова лысая. Приходит Маркус, зовет в бар проверить Торда. Часть луперов ушла на задание, вторая в Петуха. \n\nСадятся за стол, Эрик спрашивает «Почему бы его просто не спросить?», Лекс соглашается, Карина начинает ругать барда, что из-за его языка они не в первый раз попадают в неприятности, и на словах о петле и нападении на Сиорию к столу подходит Торд принять заказ, очевидно всё услышав, но лицом не выдал себя. \n\nПриходит Анарион, все знакомятся ещё раз, Маркус просит Торда сесть к ним, и ребята начинают спрашивать уставшего бармена, не снились ему сны о войне и смерти, тот жалуется, что «каждый день ему снится смерть из-за работы».. он явно не верит взбалмошным студентам, тогда Маркус вызывает его на дуэль, Джалин организует ринг и принимает ставки. \n\nБой. Торд мощно бьет Маркуса в грудь, извиняется, но монах контратакует, и зависает на балке под потолком, варвар неожиданно для всех телепортируется, хватая соперника, валит его на пол, но тот оглушает оппонента, бармен последним ударом вырубает Маркуса, но тот успевает в конце уронить Торда. Ничья, несмотря на то, что Карина и Анарион незаметно подлечили Торда и Маркуса, соответственно кто на кого поставил. На фоне беседа остальных, делятся сплетнями, кто кого бросил в любовной пентаграмме. \n\n(Скип. Торда посвящают в луперы, берут на зачистку легких ресурсов)\n2 день\n3 день\n4 день\n\n5 день. Маркус пристает к Тайвен с заданием по поиску часов, та удивлена откуда он знает, но соглашается. Спускаются в подземелье, с помощью поиска предмета не находят ничего, кроме погонщика с троллями, которых убивают за мгновение. Тайвен в афиге, спрашивает «кто они такие и откуда взяли силы», совместной ложью её убеждают, что состоят в тайном обществе допинга «Петля», но та недовольная этим остаётся при подозрениях.\n\nЗатем сразу встречают мозговых крыс, даже видя их трупы Тайвен не верит в городской миф, почему ребята так легко реагируют на это, и что значит «Встречались раньше» с ними. Тут с Анарионом связываются пауки, спрашивают что они тут забыли, соглашаются на встречу, если не нападёт Тайвен, которую они не знают. Пауки знакомятся с *новыми* людьми, Тайвен в шоке от разговоров и сил ребят, но держится. Пауки отдают часы, говорят что странные разведчики ищут аранеа, обронили предмет, но это не часы. Эрик их открывает, похоже на прибор для слежки, их забирают для дальнейшего изучения.\n\nНа обратном пути заплутали и вышли к коллектору, в котором на них нападают летучие мыши и 2 нечисти. С роем мышей быстро разбираются, но Торда берут под контроль и нападают на Тайвен, которую в миг высасывает до дна невидимый вампир, а после высушивает Маркуса. Вторая невидимая нежить пускает некротический взрыв в Лекса и Карину, которые успели отступить за закрытые решётки, бард мгновенно падает, жрица лечит и создаёт дневной свет. Никого не видно, но слышится шипение. Эрик, чуя невидимую нежить, убивает вампира, тот в тумане улетает прочь, Анарион пробует обнаружить мысли, кажется обе твари отступили. Карина возрождает Маркуса, и сохраняет Тайвен нетленными останками.\n\nЛекс делает Маркуса с Тайвен невидимыми, чтобы выбраться с ней из коллектора без лишних вопросов, если возродят её позже, на выходе из подземки замечают слежку в виде ворона. Анарион телепатически просит Маркуса в невидимости отнести Тайвен в поместье Зака, а Карина ведет остальных в храм под предлогом «Пополнить запасы», и через подземный ход в морге выводит ребят, снимая слежку, идя к поместью в маскировке и невидимости.\n\nПоместье, Зак спускается на оклик Маркуса в подвал и видит, как монах, с которого уже спала невидимость, кладёт на стол бледное иссушенное тело Тайвен."}'::jsonb),
  (60, '{"session_number": 60, "loop_number": 5, "game_date": "5 петля, 1-6 странствий", "recap": "Дрипли искал Янку в первый день, пытался вскрыть окно её дома, но передумал, его заметил сосед, после Лайонел серьёзно говорил с сыном, даже Лань пришла искать дочь, но никто её не видел. \n\nЗак возрождает Тайвен в подвале поместья, ребята делают вид, что она просто потеряла сознание и не умирала. Скрывать, что они в петле не получилось, Дрипли всё рассказал как есть, Тайвен фрустрирована этим, но злость пересиливает, просит каждую петлю ей рассказывать-показывать всё. \n\nНа следующий день Дрипли делает убедительную копию часов, собираются с Тайвен сдавать задание и поймать врагов на месте. Тулуна предлагает план - пробраться по канализации под домом, так как вороны ей сказали, что никто не заходил и не выходил из дома, кроме Тайвен (значит попадали в дом другим путём). \n\nПод землей находят место, где формировали камень для прохода, решают зайти внутрь подвала, часть зайдёт со двора, а часть сдавать задание. Карина открывает проход, видны бочки и мешки, жрица пихает Дрюса в облике кота внутрь, проход закрывается и на друида кто-то нападает. \n\nДальше по канализации слышен лязг доспехов, ребята понимают что нет времени на этот план, Карина снова открывает проход, Дрипли забирает Дрюса-кота, а Тулуна закрывает проход опять. Выбегают наружу, чтобы попасть в дом так: Тони, Тайвен и Дрипли идут внутрь, а Дрюс, Карина и Тулуна ждут на заднем дворе. \n\nТайвен стучится, их запускают, (закрывают дверь), волшебник просит подождать, пока проверят часы магией, ребята начинают нервничать, но через 10 минут чел подтверждает, что всё в порядке. Он просит подождать, чтобы выдать награду, выходит из комнаты за дверь, Дрипли дёргается что-то сделать, но не успевает остановить мага. \n\nРезкая Тьма и Тишина. Дрипли, получивший урок от семьи Манкод, через очки единственный видит, как через приоткрытую дверь вплывают две тени, а следом пара войнов. Студенты не могут в магию, их товарищи ничего не слышат и не подозревают о судьбе друзей. Дверь снова открывается, маг что-то сделав заходит внутрь, и тут Дрипли проскальзывает за него в коридор, где нет Тьмы и Тишины. \n\nКуклю, которая искала проход через заднюю дверь, уничтожает огненным шаром от Дрипли, вместе с окном, дверью и частью стены, открывая проход к отступлению и дневному свету, что как раз кстати, так как призраки почти высосали все силы из Тайвен и Тони, что равно смерти. Карина лечит, Дрюс кидает огненный шар (по своим тоже), Тулуна вызывает своего зверя, Тони катит бочку с порохом под войнов (небольшая игра в горячую картошку), но метким выстрелом бард взрывает её. \n\nДрипли создает паутину, маг стоит опутанный в Тишине, так как Тулуна рассеяла Тьму, натравляет на него зверя, а Дрюс добивает терновой стеной. Часть стены разнесло, ребята впопыхах тушат пожар, но зеваки вызвали службы, поэтому пришлось отступать, скрываясь в городе, таща за собой тело мага на спине зверя Тулуны в невидимости. \n\nУже в поместье Карина вызывает Аланика, тот прибывает через час, снова ругает студентов за самоуправство, но благодарит Тулуну за объяснение ситуации, часы оставляет им, а мага с его вещами забирает и удаляется для дальнейших разбирательств.\nТайвен говорит ребятам, что они сумасшедшие!"}'::jsonb),
  (61, '{"session_number": 61, "loop_number": 5, "game_date": "5 петля, 7-8 странствий", "recap": "7 день. После занятий в Академии ребята прогуливаются по магазинчикам Сиории в поисках ценных предметов и ингредиентов, но приходят к выводу, что лучше лавочки Савочки пока места нет. Они идут над широким речным каналом, когда слышат громкий мужской окрик «Воровка! Это серп моего брата!». Внизу стоит группа из 7 крепких парней, окружающих смуглую высокую девушку. Долг зовёт героев, и Британия просто спрыгивает с мостика, хватая Эрика за руку. Лекс с манерным цоканьем кастует на всех падение перышком (а потом как обычно делает сальто в воздухе), Рион прыгает следом. Тулуна, наблюдая за внезапной самоотверженностью, обращается в ворона и полётом устремляется вниз, пока не достигает плеча незнакомки\n\nШкольники вступают в переговоры с \"бандитами\", последние достают револьверы. Эрик угрожает полицией и уже собирается к ближайшему участку, Британия демонстрирует устрашающие иллюзии, но парни только крепче держат пистолеты, не выпуская жертву из круга. Бардка срывается и кастует в \"главаря\" психическое копьё, сваливая того с ног, Рион аналогично атакует ещё одного, Лекс подхватывает инициативу и создаёт гипнотический узор, накрывающий потерпевшую с вороном. Благо Тулуна остается в сознании, чтобы похлопать крыльями по лицу девушки и привести ту в чувство. Пока незнакомка пробегает обезвреженных врагов, птица пропадает из поля зрения. \n\nДва бандита всё ещё в сознании. Рион обходит их сзади, Британия и Лекс встают практически в упор к револьверам, защищённые доспехами самоуверенности и вооруженные острым языком. Магией Лекс выуживает струйку чернил и формирует фаллические контуры, которые направляет прямо на лица врагов. Эрик просто стоит в ахуе. Тулуна в человеческой форме оказывается недалеко от него и достаёт яркое перо на случай отступления. Попытка Риона выбросить оружие недееспособных противников приводит тех в сознание, парни растряхивают друг друга, но уже готовы разойтись мирно. Так стычка заканчивается, а к лупер''ам присоединяется новая девушка — Авр''ор''а Монр''о. *десяток передразниваний фалкринейского акцента от Лекса*\n\nНовенькую посвящают в петлю уже в Вине поэзии, в закрытой комнате. Эрик пытается убедить ребят, что убивать всех людей, встающих на пути, опасно для жизни после петли (будет привычка), Британия нехотя соглашается, она действительно потеряла контроль. Аврора рассказывает, как всё это время выживала на севере, погибала в пасти саламандры и пыталась достичь чего-то, что ей было не по зубам. Лекс оценивает вино сорта Монро и просит у девушки автогр''аф на бутылке. Помимо виноделия, Аврора так же владеет заклинанием превращения, бард даже соглашается попробовать его действие, но сопротивляется. То ли чтобы не обижать девушку, то ли из-за бутылки фалкренейского в крови Лекс сам виртуозно изображает кролика (выступление 26). \n\nЭрик быстро теряет интерес к дальнейшей беседе и удаляется на поиски спутницы этого вечера. Спустя какое-то время пьяные барды вспоминают про него и наперегонки покидают комнату: Британия, чтобы помешать свиданию, и Лекс, чтобы это предотвратить. Тем не менее Лекс быстро сливается, когда девушка использует близость (Лекс её схватил) для притворного поцелуя. Британия успешно находит воркующих, начинает наигрывать бодрый мотив на гитаре, смотря прямо на Эрика. Магия музыки заставляет паладина пуститься в пляс, но собственная харизматичность его спасает, короткий танец впечатляет публику. Сколько-то бокалов спустя барды сами танцуют под ручку; Лекс усиленно сопротивляется, когда его пытаются прижать к груди.\n\n8 день. На следующий день Тулуна и Аврора с интересом идут на пары — для них эта пятница в первый раз. Британия и Рион тоже идут ради встречи с кураторами, попутно стаскивая с кровати Лекса и уламывая Эрика прийти под маскировкой Зака. На основах инвокации на каждой парте стоит земля в горшках, Ильза не разрешает уходить со своих мест. Тулуну просят продемонстрировать заговор, и она увлечённо придаёт земле разные формы, отвечая на вопросы о неструктурированной магии. Британия довольно демонстрирует владение диспелом\n\n\nЗнакомство с кураторами проходит по-разному: Британия и Аврора проводят время на спортивной площадке у Ниртака, Рион интересуется модификацией заклинаний у Кайрона. Эрик же без маскировки шляется по Академии, останавливаясь возле красивых бывших однокурсниц (кажется, младшенькую Елену он увлёк беседой). \n\nТулуне достался Ксвим Чао — адский куратор, как его прозвали студенты. Ильза в понедельник объясняла, что слухи ложны, и профессор Чао является прекрасным вариантом для трудолюбивых студентов. Тулуна же сделала вывод, что он любит чёткость и безупречность. Добиться максимальной эффективности даже на простейших магических паттернах — вроде в этом была цель занятия. Это несколько разнилось с её представлениями о прекрасных в своей непредсказуемости потоках магии, но, похоже, это станет ещё одним шагом к познанию другой культуры. В конце концов интересно пробовать что-то новое, даже когда это новое кидает в тебя стеклянные шарики прямо по время занятия. \n\nЛекс как обычно пришёл к Юлиану Панкрацу, потому что знал: пара продемонстрированных пасов, и его освободят от посещения куратора как минимум до конца месяца. Но, что неожиданно, в этот раз Лекс так себя захвалил, что даже был приглашён на главную роль в пьесе. Как раз в этот момент в кабинет зашла Британия, слегка вымотанная после тренировки, и принесла сценарий, которого ещё не было. Юлиан — настоящий творец, поэтому оценил собственный почерк, но выразил скепсис к паре деталей и забрал текст на доработку. Мимо него так же не прошла химия, которая образовалось между двумя студентами. Мужчина довольно отметил, что это отличные кандидаты для чувственного финала с поцелуем. \n\nПосле уроков Рион снова пишет письмо на фабрику к брату и заранее предлагает съездить с ним, а так же вспоминает недавний случай с овцой. Он опять забрал свиток, отдав бедного волшебника Аериси и отложив палочку с истинным превращением в конец списка дел. Но, возможно, именно сейчас самое время про него вспомнить. Жаль, путь к дому, где держат Шайнбрайта, за эти месяцы окончательно стёрся из памяти. Рион отправляет послание овце, и не получает ничего более вразумительногого, чем «Я в загоне». Команда разделяется, чтобы провести своё расследование: Британия и Лекс идут по барам угощать гостей и распрашивать о всяких овцах и чародейках, а Тулуна настраивается на поиск мощной палочки и несколько часов проводит в полёте над окраинами. Приходится делать небольшие привалы для медитации, и уже к позднему вечеру (спустя 6 часов) она достигает цели — пастбища в 30 минутах от города. Здесь стоят загоны с десятками овец, но где-то в глубине одного из домов скрывается артефакт, который никак не ожидаешь встретить в подобном месте. \n\nКогда друидка возвращается обратно в поместье, компания снова навеселе. На секунду она представляет смешную сцену с опьяненными птицами, и вслух предлагает горе-бардам полетать. Лекс интерпретирует эти слова по-своему. Он берет Британию за руку, и спустя пару секунд они исчезают из зала, появиляясь в 500 футах от земли, прямо над крышей поместья. Лекс всё расчитал: он отпустит девушку, снова войдёт в переносящую дверь и поймает её внизу. А потом он приступает к исполнению плана и понимает, что летит вниз быстрее, чем хотелось бы. Время уходит на попытки выбраться из схватки Британии, вот поверхность уже близко и... он опять использует падение перышком, с неохотой, как клише последних дней. \n\nРион, невосприимчивый к алкоголю, но вынужденный мириться с пьянством союзников, одаривает всех отрезвляющим касанием. Он наконец знает, куда идти, и хочет сделать это незамедлительно. Его не оставливает ни отказ товарищей, ни сумерки на улице, ни дорога через лес, известный своей опасной фауной. Да, он пошёл совсем один, встретил по пути гигантского белого волка, каких раньше никогда не видел, но всё закончилось хорошо. Пару часов он потерял среди лесных тропинок, затем снова отправил послание овце и понадеялся, что животное поймёт команду «Кричи». Протяжное «беее» в голове отозвалось в реальности, и вывело его к нужному дому. Высокий забор, обереги — пора разработать план, как туда пробраться."}'::jsonb),
  (62, '{"session_number": 62, "loop_number": 5, "game_date": "5 петля, 9 странствий", "recap": "Утро, 10 утра, суббота. Анарион-засоня, карета, 3 часа пути. Миряна, невидимые слуги, три рогатки с ножками и ручками. Одна хуйня, халат мастера, Данвич. Ещё не голая женщина, голый мужчина, ещё не голый ребёнок. Удочка, леечка, садик. Искательница Новизны, Маркус, амулет-переводчик. Луперы с паучком, зоопарк фамильяров, хищный цветок. Марина, опасность, храбрость Дрипли. Споры, шум, гам. Низкая плотность маны, 300 атак монаха, чтение мыслей. Пара часов до цветка, воронья разведка, Анарион на руках монаха. Толпа из 40 человек, преследование, шум и гам. Белки-шпионы, мужчина в глубине леса, колчан стрел. Новизна в слинге, силок, угрозы Уини. Голая интеракция, прогулка до цветка, плачущий мальчик. Вершина холма, телоглот, 300 футов. Несработавшее изгнание волшебницы, топ-топ-топ до цветка, начало боя. \n\nДиалог с пиком эволюции, дебютная атака из трех рогаток, волшебные камни. Быстрые кулаки, отрыжка телом, геноцид. Очарование монстра, урон от слизи, шантаж мирняком. Ментальные игры, самоуверенность, надменность. Изгнание цветка, стена ветра, приближающаяся толпа. Убеждение и возвращение монстра, замедление, диалоги. Ледяной шар, паладинский меч, шторм кулаков. Пятый призыв к тишине, критический смайт, смерть цветка. Телепатия, коммунисты, putain de merde на фалкринейском. Выводы, допросы, 110 км/ч. Останки цветка, работа для Марины, ненависть Миряны. Профессор ботаники, высшая форма жизни, грусть экспериментатора.", "new_npcs_raw": "🥊 Телеглот\nhttps://5e14.dnd.su/bestiary/6851-bodytaker/\n\n🥊 Выплодки\nhttps://5e14.dnd.su/bestiary/6852-podling/"}'::jsonb),
