-- Migration 114: import session recaps from the player Google Sheet.
--
-- Source: docs.google.com/spreadsheets/d/1O8KM25y1wdyorNHYc2mXvnl0A84JX2gxFlN0jRVk-jY
-- (sheet "Рекапы", 72 games across loops 1-5).
--
-- The sheet is the canonical session log; the DB has only ~7 seeded
-- placeholder sessions (from seed_loops_sessions.sql + mig 012). This
-- migration brings the full set in.
--
-- Strategy (single transaction, temp tables):
--   1. Ensure edge_type `appeared_in` exists (base, like `participated_in`).
--      Direction: session → NPC. Semantic: "this NPC appeared/was mentioned
--      in this session". Mirrors `participated_in` (session → PC) so the
--      bidirectional navigation works the same way on both sides.
--
--   2. Load 72 session rows into a temp table; UPDATE merge by
--      session_number (preserves existing seed titles + dm_notes), then
--      INSERT new sessions with auto title 'Сессия N'.
--
--   3. Load 390 (session_number, pc_title) tuples into a temp table.
--      JOIN against nodes to resolve UUIDs, upsert `participated_in`
--      edges (session → PC). Unique constraint on (source, target, type)
--      makes ON CONFLICT DO NOTHING idempotent.
--
--   4. Same for 212 (session_number, npc_title) tuples → `appeared_in`
--      edges (session → NPC).
--
-- New keys added to nodes.fields (omitted when sheet cell was blank):
--   time_range       — col B "Дата \\ Время" — "20:00 — 00:00"
--   materials        — col H "Материалы" — raw text
--   materials_url    — col H — Google-Drive hyperlink target
--   perks            — col I "Плюшки \\ Ставки на спорт"
--   achievements     — col J "Достижения"
--   new_npcs_raw     — col G "Новые НПС / Монстры" — raw unstructured
--                      text; promoting individual NPCs into the catalog
--                      is intentionally out of scope (would require
--                      free-text parsing).
--
-- Existing keys updated (only when the sheet has a non-empty value):
--   session_number, loop_number, played_at, game_date, recap.
--   title and dm_notes are NOT touched — seed-set titles and DM notes
--   survive.
--
-- Coverage stats (built off the sheet's player + NPC tokens):
--   PC tokens:  41 unique forms → all 41 resolve to 29 PC nodes (100%)
--   NPC tokens: 87 unique strings → 84 match canonical NPC titles (96.5%).
--   The 3 mismatches are sheet typos, normalized inline:
--     'Копье решимости, прознающее самую суть' → '…пронзающее…'
--     'Ноа Тисгук'                              → 'Ноа Тиссгук'
--     'Славолюб Пенкало'                        → 'Славолюб Пенкала'
--
-- Loop distribution:
--   loop 1: 11 games, loop 2: 13, loop 3: 12, loop 4: 21, loop 5: 15.
--
-- Hyperlinks recovered: 13 materials_url (Google Drive).
--
-- Idempotent: every step uses NOT EXISTS / ON CONFLICT DO NOTHING. Re-
-- applying the migration is safe.

BEGIN;

-- ────────────── 1. edge_type appeared_in ──────────────

values (null, 'appeared_in', 'Появлялся в', true)
on conflict do nothing;

-- ────────────── 2. Load sessions into temp table ──────────────

create temp table _recap_sessions (
  session_number int primary key,
  patch jsonb not null
) on commit drop;


-- ────────────── 2a. UPDATE existing sessions (merge patch into fields) ──────────────
-- Preserves title, dm_notes, day_from, day_to and any other field not in
-- the sheet. fields = fields || patch ensures sheet values win on overlap.

update nodes n
   set fields     = n.fields || r.patch,
       updated_at = now()
  from _recap_sessions r
 where n.campaign_id = '00000000-0000-0000-0000-000000000001'
   and n.type_id    = (select id from node_types where campaign_id = '00000000-0000-0000-0000-000000000001' and slug = 'session')
   and (n.fields->>'session_number')::int = r.session_number;

-- ────────────── 2b. INSERT missing sessions (title auto-generated) ──────────────

select
  '00000000-0000-0000-0000-000000000001',
  (select id from node_types where campaign_id = '00000000-0000-0000-0000-000000000001' and slug = 'session'),
  'Сессия ' || r.session_number,
  r.patch
  from _recap_sessions r
 where not exists (
   select 1 from nodes n
    where n.campaign_id = '00000000-0000-0000-0000-000000000001'
      and n.type_id    = (select id from node_types where campaign_id = '00000000-0000-0000-0000-000000000001' and slug = 'session')
      and (n.fields->>'session_number')::int = r.session_number
 );

-- ────────────── 3. Load PC participation edges ──────────────

create temp table _recap_pc_edges (
  session_number int not null,
  pc_title text not null,
  primary key (session_number, pc_title)
) on commit drop;


-- ────────────── 3a. UPSERT participated_in edges (session → PC) ──────────────

select
  '00000000-0000-0000-0000-000000000001',
  s.id,
  p.id,
  (select id from edge_types where slug = 'participated_in' and is_base = true)
from _recap_pc_edges e
join nodes s on s.campaign_id = '00000000-0000-0000-0000-000000000001'
            and s.type_id    = (select id from node_types where campaign_id = '00000000-0000-0000-0000-000000000001' and slug = 'session')
            and (s.fields->>'session_number')::int = e.session_number
join nodes p on p.campaign_id = '00000000-0000-0000-0000-000000000001'
            and p.type_id    = (select id from node_types where campaign_id = '00000000-0000-0000-0000-000000000001' and slug = 'character')
            and p.title      = e.pc_title
on conflict (source_id, target_id, type_id) do nothing;

-- ────────────── 4. Load NPC appearance edges ──────────────

create temp table _recap_npc_edges (
  session_number int not null,
  npc_title text not null,
  primary key (session_number, npc_title)
) on commit drop;


-- ────────────── 4a. UPSERT appeared_in edges (session → NPC) ──────────────
-- Sessions or NPCs that don't exist yet in nodes (e.g. NPC not imported,
-- session not yet matched) are silently skipped by the inner JOIN —
-- the migration succeeds even if some references can't resolve.

select
  '00000000-0000-0000-0000-000000000001',
  s.id,
  n.id,
  (select id from edge_types where slug = 'appeared_in' and is_base = true)
from _recap_npc_edges e
join nodes s on s.campaign_id = '00000000-0000-0000-0000-000000000001'
            and s.type_id    = (select id from node_types where campaign_id = '00000000-0000-0000-0000-000000000001' and slug = 'session')
            and (s.fields->>'session_number')::int = e.session_number
join nodes n on n.campaign_id = '00000000-0000-0000-0000-000000000001'
            and n.type_id    = (select id from node_types where campaign_id = '00000000-0000-0000-0000-000000000001' and slug = 'npc')
            and n.title      = e.npc_title
on conflict (source_id, target_id, type_id) do nothing;

COMMIT;
